import { GoogleGenAI, Type, Modality } from '@google/genai';
import type { Scene, Character, NarrationPart } from '../types';

const getAiClient = () => {
    if (!process.env.API_KEY) {
        throw new Error("API_KEY environment variable not set");
    }
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

// --- Helpers for Audio Generation ---

const decode = (base64: string): Uint8Array => {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

const createWavBlob = (pcmData: Uint8Array, sampleRate: number, numChannels: number, bitsPerSample: number): Blob => {
    const dataSize = pcmData.length;
    const buffer = new ArrayBuffer(44 + dataSize);
    const view = new DataView(buffer);

    const writeString = (offset: number, str: string) => {
        for (let i = 0; i < str.length; i++) {
            view.setUint8(offset + i, str.charCodeAt(i));
        }
    };

    const blockAlign = numChannels * (bitsPerSample / 8);
    const byteRate = sampleRate * blockAlign;

    writeString(0, 'RIFF');
    view.setUint32(4, 36 + dataSize, true);
    writeString(8, 'WAVE');
    writeString(12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, numChannels, true);
    view.setUint32(24, sampleRate, true);
    view.setUint32(28, byteRate, true);
    view.setUint16(32, blockAlign, true);
    view.setUint16(34, bitsPerSample, true);
    writeString(36, 'data');
    view.setUint32(40, dataSize, true);

    const pcmAsUint8 = new Uint8Array(pcmData);
    for (let i = 0; i < dataSize; i++) {
        view.setUint8(44 + i, pcmAsUint8[i]);
    }

    return new Blob([view], { type: 'audio/wav' });
};


// --- API Functions ---

export const parseStoryboardIntoScenes = async (novelText: string): Promise<Pick<Scene, 'parts'>[]> => {
    const ai = getAiClient();
    const model = 'gemini-3-flash-preview';

    const prompt = `
    Eres un guionista y director de cine experto. Tu tarea es transformar el siguiente texto de una novela en un guion gráfico (storyboard) estructurado.

    Analiza el texto y divídelo en escenas visuales lógicas. 
    Para cada escena, genera un array de "parts" con:
    - "NARRATION": Texto descriptivo cinematográfico.
    - "DIALOGUE": Diálogos literales de personajes.
    - "INSTRUCTION": Instrucciones de cámara (Ej: "Gran plano general"), iluminación o ambiente.

    Proporciona ÚNICAMENTE el JSON.

    Texto:
    ${novelText}
    `;

    try {
        const response = await ai.models.generateContent({
            model: model,
            contents: prompt,
            config: {
                responseMimeType: 'application/json',
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                           parts: {
                                type: Type.ARRAY,
                                items: {
                                    type: Type.OBJECT,
                                    properties: {
                                        type: { type: Type.STRING, enum: ['NARRATION', 'DIALOGUE', 'INSTRUCTION'] },
                                        speaker: { type: Type.STRING },
                                        text: { type: Type.STRING },
                                    },
                                    required: ['type', 'text']
                                }
                           }
                        },
                        required: ['parts'],
                    },
                },
            },
        });

        return JSON.parse(response.text);
    } catch (error) {
        console.error('Error parsing storyboard:', error);
        throw new Error('No se pudo estructurar el guion. Intenta con un fragmento más corto.');
    }
};

export const identifyCharacters = async (novelText: string): Promise<Character[]> => {
    const ai = getAiClient();
    const model = 'gemini-3-flash-preview';

    const prompt = `Identifica a los personajes principales (máx 5) del texto. Crea una descripción visual MUY detallada de cada uno para IA (cabello, ojos, ropa, edad).
    Devuelve un array JSON con "name" y "description".
    Texto: ${novelText}`;

    try {
        const response = await ai.models.generateContent({
            model,
            contents: prompt,
            config: {
                responseMimeType: 'application/json',
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            name: { type: Type.STRING },
                            description: { type: Type.STRING },
                        },
                        required: ['name', 'description'],
                    },
                },
            },
        });
        return JSON.parse(response.text);
    } catch (error) {
        return [];
    }
};

export const generateImageForScene = async (parts: NarrationPart[], style: string, characters: Character[], artDirection: string, includeTextInImage: boolean): Promise<{ imageUrl: string, imagePrompt: string }> => {
    const ai = getAiClient();
    const textModel = 'gemini-3-flash-preview';
    const imageModel = 'gemini-2.5-flash-image';

    const charRef = characters.map(c => `${c.name}: ${c.description}`).join('\n');
    const sceneContent = parts.map(p => p.text).join(' ');

    const promptGenPrompt = `Create a highly detailed English image generation prompt for this scene. 
    STYLE: ${style}. ART DIRECTION: ${artDirection}.
    CHARACTER CONSISTENCY IS KEY. Use these descriptions:
    ${charRef}
    SCENE CONTENT: ${sceneContent}
    ${includeTextInImage ? 'Include subtle Spanish subtitles if appropriate.' : 'NO TEXT in the image.'}
    Return only the prompt text.`;

    const promptResponse = await ai.models.generateContent({ model: textModel, contents: promptGenPrompt });
    const imagePrompt = promptResponse.text;

    const imageResponse = await ai.models.generateContent({
        model: imageModel,
        contents: { parts: [{ text: imagePrompt }] },
    });

    const candidate = imageResponse.candidates?.[0];
    const imagePart = candidate?.content?.parts?.find(p => p.inlineData);

    if (imagePart?.inlineData) {
        return {
            imageUrl: `data:${imagePart.inlineData.mimeType};base64,${imagePart.inlineData.data}`,
            imagePrompt: imagePrompt
        };
    }
    throw new Error('La generación de imagen no devolvió datos visuales.');
};

export const generateVideoForScene = async (parts: NarrationPart[], aspectRatio: '16:9' | '9:16'): Promise<any> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = 'veo-3.1-fast-generate-preview';
    const action = parts.filter(p => p.type !== 'INSTRUCTION').map(p => p.text).join(' ').substring(0, 500);

    return await ai.models.generateVideos({
        model,
        prompt: `Cinematic animation of: ${action}. High quality, smooth motion.`,
        config: { numberOfVideos: 1, resolution: '720p', aspectRatio }
    });
};

export const checkVideoStatus = async (operation: any): Promise<any> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    return await ai.operations.getVideosOperation({ operation });
};

export const generateAudioForScene = async (parts: NarrationPart[], allCharacters: Character[], narratorVoice: string): Promise<string> => {
    const ai = getAiClient();
    const model = 'gemini-2.5-flash-preview-tts';

    const speakableParts = parts.filter(p => p.type !== 'INSTRUCTION' && p.text.trim());
    const pcmChunks: Uint8Array[] = [];
    let totalLength = 0;

    for (const part of speakableParts) {
        const voiceName = part.speaker === 'Narrador' || !part.speaker
            ? narratorVoice
            : allCharacters.find(c => c.name === part.speaker)?.voice || 'Zephyr';

        try {
            const response = await ai.models.generateContent({
                model,
                contents: [{ parts: [{ text: part.text }] }],
                config: {
                    responseModalities: [Modality.AUDIO],
                    speechConfig: {
                        voiceConfig: { prebuiltVoiceConfig: { voiceName } },
                    },
                },
            });

            const data = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
            if (data) {
                const pcm = decode(data);
                pcmChunks.push(pcm);
                totalLength += pcm.length;
            }
        } catch (e) {
            console.error("TTS Error for part:", part.text, e);
        }
    }

    if (pcmChunks.length === 0) throw new Error("No se pudo generar audio.");

    const concatenated = new Uint8Array(totalLength);
    let offset = 0;
    for (const chunk of pcmChunks) {
        concatenated.set(chunk, offset);
        offset += chunk.length;
    }

    return URL.createObjectURL(createWavBlob(concatenated, 24000, 1, 16));
};

import React, { useRef, useCallback, useState } from 'react';
import type { Scene } from '../types';
import { useProjectState, useProjectDispatch, useProjectActions } from '../context/ProjectContext';
import Loader from './Loader';
import { FilmIcon, SpeakerWaveIcon, SaveIcon, ClipboardIcon, TrashIcon, DragHandleIcon, UploadIcon, MusicNoteIcon } from './Icons';
import { generateVideoForScene, checkVideoStatus } from '../services/gemini';

const PREDEFINED_MUSIC = [
    { name: "Sin música", url: "" }, 
    { name: "Misterio", url: "https://cdn.pixabay.com/audio/2022/11/21/audio_a18db14263.mp3" }, 
    { name: "Aventura", url: "https://cdn.pixabay.com/audio/2023/08/03/audio_eb72f1c826.mp3" }, 
    { name: "Fantasía", url: "https://cdn.pixabay.com/audio/2022/08/17/audio_33b68d653c.mp3" }
];

interface SceneCardProps {
    scene: Scene;
    sceneNumber: number;
}

export default function SceneCard({ scene, sceneNumber }: SceneCardProps) {
    const dispatch = useProjectDispatch();
    const { hasApiKey, aspectRatio } = useProjectState();
    const { handleNarrateScene, handleUploadAudio } = useProjectActions();
    const [isPolling, setIsPolling] = useState(false);

    const uploadAudioInputRef = useRef<HTMLInputElement>(null);

    const handleCopyPrompt = () => {
        if (!scene.imagePrompt) return;
        navigator.clipboard.writeText(scene.imagePrompt);
        dispatch({ type: 'ADD_TOAST', payload: { message: 'Prompt copiado', type: 'success' } });
    };

    const handleAnimate = async () => {
        if (typeof (window as any).aistudio !== 'undefined' && !hasApiKey) {
            await (window as any).aistudio.openSelectKey();
            dispatch({ type: 'SET_API_KEY_STATUS', payload: true });
        }

        dispatch({type: 'UPDATE_SCENE', payload: {sceneId: scene.id, updates: { isGeneratingVideo: true, videoError: undefined }}});
        setIsPolling(true);

        try {
            const operation = await generateVideoForScene(scene.parts, aspectRatio);
            const check = async () => {
                const status = await checkVideoStatus(operation);
                if (status.done) {
                    const url = `${status.response?.generatedVideos?.[0]?.video?.uri}&key=${process.env.API_KEY}`;
                    dispatch({type: 'UPDATE_SCENE', payload: {sceneId: scene.id, updates: { videoUrl: url, isGeneratingVideo: false }}});
                    setIsPolling(false);
                } else {
                    setTimeout(check, 8000);
                }
            };
            check();
        } catch (err: any) {
            dispatch({type: 'UPDATE_SCENE', payload: {sceneId: scene.id, updates: { isGeneratingVideo: false, videoError: err.message }}});
            setIsPolling(false);
        }
    };

    return (
        <div className="bg-gray-800/40 backdrop-blur-xl border border-white/10 rounded-3xl overflow-hidden shadow-2xl hover:border-sky-500/50 transition-all duration-500 group">
            <header className="flex items-center justify-between bg-white/5 p-4 border-b border-white/10">
                <div className="flex items-center gap-4">
                    <div className="p-2 bg-sky-500/20 rounded-xl text-sky-400">
                        <DragHandleIcon className="w-5 h-5 cursor-grab active:cursor-grabbing" />
                    </div>
                    <h3 className="font-bold text-xl text-white tracking-tight">Escena {sceneNumber}</h3>
                </div>
                <button onClick={() => dispatch({ type: 'DELETE_SCENE', payload: scene.id })} className="text-gray-500 hover:text-red-400 transition-colors">
                    <TrashIcon className="w-5 h-5" />
                </button>
            </header>

            <div className="flex flex-col lg:flex-row">
                <div className="lg:w-1/2 aspect-video bg-black relative group/media">
                    {scene.isGeneratingImage ? (
                        <div className="absolute inset-0 flex items-center justify-center bg-gray-900"><Loader message="Dibujando..." /></div>
                    ) : scene.imageUrl ? (
                        scene.videoUrl ? (
                            <video src={scene.videoUrl} controls className="w-full h-full object-cover" />
                        ) : (
                            <img src={scene.imageUrl} alt="" className="w-full h-full object-cover group-hover/media:scale-105 transition-transform duration-700" />
                        )
                    ) : (
                        <div className="absolute inset-0 flex items-center justify-center text-gray-600 italic">Esperando generación...</div>
                    )}
                </div>

                <div className="lg:w-1/2 p-8 flex flex-col justify-between space-y-6">
                    <div className="space-y-4">
                        <div className="max-h-32 overflow-y-auto pr-2 custom-scrollbar">
                            {scene.parts.map((p, i) => (
                                <p key={i} className={`mb-2 text-sm ${p.type === 'DIALOGUE' ? 'text-sky-300 font-medium' : 'text-gray-400'}`}>
                                    {p.speaker && <span className="uppercase text-[10px] tracking-widest opacity-60 mr-2">{p.speaker}:</span>}
                                    {p.text}
                                </p>
                            ))}
                        </div>

                        <div className="flex gap-2">
                            <button onClick={handleCopyPrompt} className="text-[10px] uppercase tracking-tighter bg-white/5 hover:bg-white/10 px-3 py-1 rounded-full text-white/60 transition-colors">
                                <ClipboardIcon className="w-3 h-3 inline mr-1" /> Copiar Prompt
                            </button>
                        </div>
                    </div>

                    <div className="grid grid-cols-2 gap-3">
                        <button 
                            onClick={() => handleNarrateScene(scene.id)} 
                            disabled={scene.isGeneratingAudio || !!scene.audioUrl}
                            className={`flex items-center justify-center gap-2 py-3 rounded-2xl font-bold transition-all ${scene.audioUrl ? 'bg-green-500/20 text-green-400 border border-green-500/30' : 'bg-sky-600 hover:bg-sky-500 text-white shadow-lg shadow-sky-600/20'}`}
                        >
                            {scene.isGeneratingAudio ? <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : <SpeakerWaveIcon className="w-5 h-5" />}
                            {scene.audioUrl ? 'Audio Listo' : 'Generar Voz'}
                        </button>

                        <button 
                            onClick={handleAnimate}
                            disabled={scene.isGeneratingVideo || !scene.imageUrl || !!scene.videoUrl}
                            className={`flex items-center justify-center gap-2 py-3 rounded-2xl font-bold transition-all ${scene.videoUrl ? 'bg-purple-500/20 text-purple-400 border border-purple-500/30' : 'bg-purple-600 hover:bg-purple-500 text-white shadow-lg shadow-purple-600/20 disabled:opacity-30'}`}
                        >
                            {scene.isGeneratingVideo ? <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : <FilmIcon className="w-5 h-5" />}
                            {scene.videoUrl ? 'Animación Lista' : 'Animar con Veo'}
                        </button>
                    </div>

                    <div className="flex items-center gap-4 pt-4 border-t border-white/5">
                        <MusicNoteIcon className="w-5 h-5 text-gray-500" />
                        <select 
                            value={scene.backgroundMusicUrl || ''} 
                            onChange={e => dispatch({ type: 'UPDATE_SCENE_CONFIG', payload: { sceneId: scene.id, config: { backgroundMusicUrl: e.target.value } } })}
                            className="bg-transparent text-sm text-gray-400 focus:text-white outline-none w-full"
                        >
                            {PREDEFINED_MUSIC.map(m => <option key={m.name} value={m.url}>{m.name}</option>)}
                        </select>
                    </div>
                </div>
            </div>
        </div>
    );
}

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { useProjectState, useProjectDispatch } from '../context/ProjectContext';

const DEFAULT_SCENE_DURATION = 6;

export default function MovieModal() {
    const { scenes, isMovieModalOpen } = useProjectState();
    const dispatch = useProjectDispatch();

    const [currentIndex, setCurrentIndex] = useState(0);
    const [isTransitioning, setIsTransitioning] = useState(false);

    const narrationAudioRef = useRef<HTMLAudioElement | null>(null);
    const musicAudioRef = useRef<HTMLAudioElement | null>(null);
    const videoRef = useRef<HTMLVideoElement | null>(null);
    const timeoutRef = useRef<number | null>(null);

    const currentScene = scenes[currentIndex];

    const goToNextScene = useCallback(() => {
        if (currentIndex < scenes.length - 1) {
            setIsTransitioning(true);
            setTimeout(() => {
                setCurrentIndex(prev => prev + 1);
                setIsTransitioning(false);
            }, 600);
        } else {
            handleClose();
        }
    }, [currentIndex, scenes.length]);

    const handleClose = () => {
        if (narrationAudioRef.current) narrationAudioRef.current.pause();
        if (musicAudioRef.current) musicAudioRef.current.pause();
        if (timeoutRef.current) clearTimeout(timeoutRef.current);
        dispatch({ type: 'CLOSE_MOVIE_MODAL' });
    };

    useEffect(() => {
        if (isMovieModalOpen && !isTransitioning && currentScene) {
            const nar = narrationAudioRef.current;
            const mus = musicAudioRef.current;
            const vid = videoRef.current;

            if (mus) {
                if (currentScene.backgroundMusicUrl) {
                    mus.src = currentScene.backgroundMusicUrl;
                    mus.volume = 0.2;
                    mus.play().catch(() => {});
                } else {
                    mus.pause();
                }
            }

            if (nar && currentScene.audioUrl) {
                nar.src = currentScene.audioUrl;
                nar.onended = () => {
                    if (!vid) goToNextScene();
                };
                nar.play().catch(() => {});
            }

            if (vid) {
                vid.onended = goToNextScene;
                vid.play().catch(() => {});
            } else if (!currentScene.audioUrl) {
                timeoutRef.current = window.setTimeout(goToNextScene, DEFAULT_SCENE_DURATION * 1000);
            }
        }
    }, [isMovieModalOpen, currentIndex, currentScene, isTransitioning, goToNextScene]);

    if (!isMovieModalOpen || !currentScene) return null;

    return (
        <div className="fixed inset-0 bg-black z-50 flex items-center justify-center p-4 md:p-12 overflow-hidden">
            <div className={`relative w-full max-w-6xl aspect-video rounded-3xl overflow-hidden shadow-[0_0_100px_rgba(0,0,0,0.8)] transition-all duration-700 transform ${isTransitioning ? 'scale-95 opacity-0 rotate-1' : 'scale-100 opacity-100 rotate-0'}`}>
                {currentScene.videoUrl ? (
                    <video ref={videoRef} src={currentScene.videoUrl} className="w-full h-full object-cover" />
                ) : (
                    <img src={currentScene.imageUrl} className="w-full h-full object-cover" />
                )}

                {/* Script Overlay */}
                <div className="absolute inset-x-0 bottom-0 bg-gradient-to-t from-black/90 via-black/40 to-transparent p-12 pt-24 pointer-events-none">
                    <div className="max-w-3xl mx-auto text-center space-y-4">
                        {currentScene.parts.filter(p => p.type !== 'INSTRUCTION').map((p, i) => (
                            <p key={i} className={`text-lg md:text-2xl font-medium tracking-tight drop-shadow-lg ${p.type === 'DIALOGUE' ? 'text-sky-300 italic' : 'text-white'}`}>
                                {p.speaker && <span className="font-black uppercase text-xs tracking-widest block mb-1 opacity-70">{p.speaker}</span>}
                                "{p.text}"
                            </p>
                        ))}
                    </div>
                </div>

                {/* Progress Bar */}
                <div className="absolute top-0 left-0 right-0 h-1 bg-white/10">
                    <div 
                        className="h-full bg-sky-500 transition-all duration-500" 
                        style={{ width: `${((currentIndex + 1) / scenes.length) * 100}%` }}
                    />
                </div>
            </div>

            <button onClick={handleClose} className="absolute top-8 right-8 w-12 h-12 flex items-center justify-center rounded-full bg-white/10 hover:bg-white/20 text-white transition-all backdrop-blur-md">
                <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>

            <audio ref={narrationAudioRef} />
            <audio ref={musicAudioRef} loop />
        </div>
    );
};

