        if (!scene.imagePrompt) return;
        navigator.clipboard.writeText(scene.imagePrompt);
        dispatch({ type: 'ADD_TOAST', payload: { message: 'Prompt copiado', type: 'success' } });
    };

    const toggleAudioPreview = () => {
        if (!audioPlayerRef.current) return;
