                    const url = `${status.response?.generatedVideos?.[0]?.video?.uri}&key=${process.env.API_KEY}`;
                    dispatch({type: 'UPDATE_SCENE', payload: {sceneId: scene.id, updates: { videoUrl: url, isGeneratingVideo: false }}});
