                <div className="lg:w-1/2 aspect-video bg-black relative group/media overflow-hidden">
                    {scene.isGeneratingImage ? (
                        <div className="absolute inset-0 flex items-center justify-center bg-gray-900"><Loader message="Dibujando..." /></div>
                    ) : scene.imageUrl ? (
                        scene.videoUrl ? (
