                            >
                                {isPlayingAudio ? <PauseIcon className="w-5 h-5" /> : <PlayIcon className="w-5 h-5" />}
                                {isPlayingAudio ? 'Pausar Voz' : 'Escuchar Voz'}
                                <audio 
                                    ref={audioPlayerRef} 
                                    src={scene.audioUrl} 
                                    onEnded={() => setIsPlayingAudio(false)}
                                    className="hidden" 
                                />
                            </button>
                        )}

                        {/* Video Button Logic: Generate or status */}
                        <button 
                            onClick={handleAnimate}
