    { name: "Aventura", url: "https://cdn.pixabay.com/audio/2023/08/03/audio_eb72f1c826.mp3" }, 
    { name: "Fantasía", url: "https://cdn.pixabay.com/audio/2022/08/17/audio_33b68d653c.mp3" }
];

interface SceneCardProps {
    scene: Scene;
    sceneNumber: number;
}

export default function SceneCard({ scene, sceneNumber }: SceneCardProps) {
    const dispatch = useProjectDispatch();
