            dispatch({ type: 'SET_API_KEY_STATUS', payload: true });
        }

        dispatch({type: 'UPDATE_SCENE', payload: {sceneId: scene.id, updates: { isGeneratingVideo: true, videoError: undefined }}});

        try {
            const operation = await generateVideoForScene(scene.parts, aspectRatio);
            const check = async () => {
                const status = await checkVideoStatus(operation);
                if (status.done) {
                    const url = `${status.response?.generatedVideos?.[0]?.video?.uri}&key=${process.env.API_KEY}`;
                    dispatch({type: 'UPDATE_SCENE', payload: {sceneId: scene.id, updates: { videoUrl: url, isGeneratingVideo: false }}});
                } else {
                    setTimeout(check, 8000);
                }
            };
            check();
        } catch (err: any) {
            dispatch({type: 'UPDATE_SCENE', payload: {sceneId: scene.id, updates: { isGeneratingVideo: false, videoError: err.message }}});
        }
    };

    useEffect(() => {
        if (musicPlayerRef.current) {
            musicPlayerRef.current.pause();
            setIsPlayingMusic(false);
        }
    }, [scene.backgroundMusicUrl]);

    return (
        <div className="bg-gray-800/40 backdrop-blur-xl border border-white/10 rounded-3xl overflow-hidden shadow-2xl hover:border-sky-500/50 transition-all duration-500 group">
            <header className="flex items-center justify-between bg-white/5 p-4 border-b border-white/10">
                <div className="flex items-center gap-4">
                    <div className="p-2 bg-sky-500/20 rounded-xl text-sky-400">
                        <DragHandleIcon className="w-5 h-5 cursor-grab active:cursor-grabbing" />
                    </div>
                    <h3 className="font-bold text-xl text-white tracking-tight">Escena {sceneNumber}</h3>
                </div>
                <button onClick={() => dispatch({ type: 'DELETE_SCENE', payload: scene.id })} className="text-gray-500 hover:text-red-400 transition-colors">
                    <TrashIcon className="w-5 h-5" />
                </button>
            </header>

            <div className="flex flex-col lg:flex-row">
                <div className="lg:w-1/2 aspect-video bg-black relative group/media overflow-hidden">
                    {scene.isGeneratingImage ? (
                        <div className="absolute inset-0 flex items-center justify-center bg-gray-900"><Loader message="Dibujando..." /></div>
                    ) : scene.imageUrl ? (
                        scene.videoUrl ? (
                            <div className="relative w-full h-full">
                                <video src={scene.videoUrl} controls className="w-full h-full object-cover" />
                                <div className="absolute top-4 left-4 px-3 py-1 bg-purple-600/80 backdrop-blur-md rounded-full text-[10px] font-bold text-white uppercase tracking-widest shadow-lg">Video Listo</div>
                            </div>
                        ) : (
                            <img src={scene.imageUrl} alt="" className="w-full h-full object-cover group-hover/media:scale-105 transition-transform duration-700" />
                        )
                    ) : (
                        <div className="absolute inset-0 flex items-center justify-center text-gray-600 italic">Esperando generación...</div>
                    )}
                </div>

                <div className="lg:w-1/2 p-8 flex flex-col justify-between space-y-6">
                    <div className="space-y-4">
                        <div className="max-h-32 overflow-y-auto pr-2 custom-scrollbar">
                            {scene.parts.map((p, i) => (
                                <p key={i} className={`mb-2 text-sm ${p.type === 'DIALOGUE' ? 'text-sky-300 font-medium' : 'text-gray-400'}`}>
                                    {p.speaker && <span className="uppercase text-[10px] tracking-widest opacity-60 mr-2">{p.speaker}:</span>}
                                    {p.text}
                                </p>
                            ))}
                        </div>

                        <div className="flex gap-2">
                            <button onClick={handleCopyPrompt} className="text-[10px] uppercase tracking-tighter bg-white/5 hover:bg-white/10 px-3 py-1 rounded-full text-white/60 transition-colors">
                                <ClipboardIcon className="w-3 h-3 inline mr-1" /> Ver Prompt Maestro
                            </button>
                        </div>
                    </div>

                    <div className="grid grid-cols-2 gap-3">
                        {!scene.audioUrl ? (
                            <button 
                                onClick={() => handleNarrateScene(scene.id)} 
                                disabled={scene.isGeneratingAudio}
                                className="flex items-center justify-center gap-2 py-3 rounded-2xl font-bold bg-sky-600 hover:bg-sky-500 text-white shadow-lg transition-all disabled:opacity-50"
                            >
                                {scene.isGeneratingAudio ? <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : <SpeakerWaveIcon className="w-5 h-5" />}
                                Generar Voz
                            </button>
                        ) : (
                            <div className="flex flex-col gap-2">
                                <button 
                                    onClick={toggleAudioPreview}
                                    className={`flex items-center justify-center gap-2 py-3 rounded-2xl font-bold transition-all ${isPlayingAudio ? 'bg-amber-500 text-white' : 'bg-green-500/20 text-green-400 border border-green-500/30 hover:bg-green-500/30'}`}
                                >
                                    {isPlayingAudio ? <PauseIcon className="w-5 h-5" /> : <PlayIcon className="w-5 h-5" />}
                                    {isPlayingAudio ? 'Pausar' : 'Oír Voz'}
                                    <audio 
                                        ref={audioPlayerRef} 
                                        src={scene.audioUrl} 
                                        onEnded={() => setIsPlayingAudio(false)}
                                        onPause={() => setIsPlayingAudio(false)}
                                        onPlay={() => setIsPlayingAudio(true)}
                                        className="hidden" 
                                    />
                                </button>
                                <button onClick={handleResetAudio} className="text-[10px] text-gray-500 hover:text-sky-400 uppercase tracking-widest text-center transition-colors">Cambiar Voz</button>
                            </div>
                        )}

                        <button 
                            onClick={handleAnimate}
                            disabled={scene.isGeneratingVideo || !scene.imageUrl || !!scene.videoUrl}
                            className={`flex items-center justify-center gap-2 py-3 rounded-2xl font-bold transition-all ${scene.videoUrl ? 'bg-purple-500/20 text-purple-400 border border-purple-500/30' : 'bg-purple-600 hover:bg-purple-500 text-white shadow-lg disabled:opacity-30'}`}
                        >
                            {scene.isGeneratingVideo ? <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : <FilmIcon className="w-5 h-5" />}
                            {scene.videoUrl ? 'Video OK' : 'Animar'}
                        </button>
                    </div>

                    <div className="flex items-center gap-3 pt-4 border-t border-white/5">
                        <button 
                            onClick={toggleMusicPreview}
                            disabled={!scene.backgroundMusicUrl}
                            className={`p-2 rounded-xl transition-all ${isPlayingMusic ? 'bg-sky-500 text-white shadow-lg' : 'bg-white/5 text-gray-400 hover:bg-white/10 disabled:opacity-20'}`}
                            title="Previsualizar Música"
                        >
                            {isPlayingMusic ? <PauseIcon className="w-4 h-4" /> : <MusicNoteIcon className="w-4 h-4" />}
                        </button>
                        <select 
                            value={scene.backgroundMusicUrl || ''} 
                            onChange={e => dispatch({ type: 'UPDATE_SCENE_CONFIG', payload: { sceneId: scene.id, config: { backgroundMusicUrl: e.target.value } } })}
                            className="bg-transparent text-sm text-gray-400 focus:text-white outline-none w-full cursor-pointer"
                        >
                            {PREDEFINED_MUSIC.map(m => <option key={m.name} value={m.url} className="bg-gray-900">{m.name}</option>)}
                        </select>
                        <audio 
                            ref={musicPlayerRef} 
                            src={scene.backgroundMusicUrl} 
                            onEnded={() => setIsPlayingMusic(false)}
                            onPause={() => setIsPlayingMusic(false)}
                            onPlay={() => setIsPlayingMusic(true)}
                            loop
                            className="hidden"
                        />
                    </div>
                </div>
            </div>
        </div>
    );
}

