                    </div>

                    <div className="grid grid-cols-2 gap-3">
                        {!scene.audioUrl ? (
                            <button 
                                onClick={() => handleNarrateScene(scene.id)} 
                                disabled={scene.isGeneratingAudio}
                                className="flex items-center justify-center gap-2 py-3 rounded-2xl font-bold bg-sky-600 hover:bg-sky-500 text-white shadow-lg transition-all disabled:opacity-50"
                            >
                                {scene.isGeneratingAudio ? <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : <SpeakerWaveIcon className="w-5 h-5" />}
                                Generar Voz
                            </button>
