                            <div className="flex flex-col gap-2">
                                <button 
                                    onClick={toggleAudioPreview}
                                    className={`flex items-center justify-center gap-2 py-3 rounded-2xl font-bold transition-all ${isPlayingAudio ? 'bg-amber-500 text-white' : 'bg-green-500/20 text-green-400 border border-green-500/30 hover:bg-green-500/30'}`}
                                >
                                    {isPlayingAudio ? <PauseIcon className="w-5 h-5" /> : <PlayIcon className="w-5 h-5" />}
                                    {isPlayingAudio ? 'Pausar' : 'Oír Voz'}
                                    <audio 
                                        ref={audioPlayerRef} 
                                        src={scene.audioUrl} 
                                        onEnded={() => setIsPlayingAudio(false)}
                                        onPause={() => setIsPlayingAudio(false)}
                                        onPlay={() => setIsPlayingAudio(true)}
                                        className="hidden" 
                                    />
                                </button>
                                <button onClick={handleResetAudio} className="text-[10px] text-gray-500 hover:text-sky-400 uppercase tracking-widest text-center transition-colors">Cambiar Voz</button>
                            </div>
                        )}

                        <div className="flex flex-col gap-2">
                            <button 
                                onClick={handleAnimate}
                                disabled={scene.isGeneratingVideo || !scene.imageUrl || !!scene.videoUrl}
                                className={`flex items-center justify-center gap-2 py-3 rounded-2xl font-bold transition-all ${scene.videoUrl ? 'bg-purple-500/20 text-purple-400 border border-purple-500/30' : 'bg-purple-600 hover:bg-purple-500 text-white shadow-lg disabled:opacity-30'}`}
                            >
                                {scene.isGeneratingVideo ? <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : <FilmIcon className="w-5 h-5" />}
                                {scene.videoUrl ? 'Video OK' : 'Animar'}
                            </button>
                            {!scene.videoUrl && scene.imageUrl && (
                                <button onClick={() => videoUploadRef.current?.click()} className="text-[10px] text-gray-500 hover:text-purple-400 uppercase tracking-widest text-center transition-colors">Subir Video Propio</button>
                            )}
                        </div>
                    </div>

                    <div className="flex items-center gap-3 pt-4 border-t border-white/5">
                        <button 
                            onClick={toggleMusicPreview}
                            disabled={!scene.backgroundMusicUrl}
                            className={`p-2 rounded-xl transition-all ${isPlayingMusic ? 'bg-sky-500 text-white shadow-lg' : 'bg-white/5 text-gray-400 hover:bg-white/10 disabled:opacity-20'}`}
                            title="Previsualizar Música"
                        >
                            {isPlayingMusic ? <PauseIcon className="w-4 h-4" /> : <MusicNoteIcon className="w-4 h-4" />}
                        </button>
                        <select 
                            value={scene.backgroundMusicUrl || ''} 
                            onChange={e => dispatch({ type: 'UPDATE_SCENE_CONFIG', payload: { sceneId: scene.id, config: { backgroundMusicUrl: e.target.value } } })}
                            className="bg-transparent text-sm text-gray-400 focus:text-white outline-none w-full cursor-pointer"
                        >
                            {PREDEFINED_MUSIC.map(m => <option key={m.name} value={m.url} className="bg-gray-900">{m.name}</option>)}
                        </select>
                        <audio 
                            ref={musicPlayerRef} 
                            src={scene.backgroundMusicUrl} 
                            onEnded={() => setIsPlayingMusic(false)}
                            onPause={() => setIsPlayingMusic(false)}
                            onPlay={() => setIsPlayingMusic(true)}
                            loop
                            className="hidden"
                        />
                    </div>
                </div>
            </div>
        </div>
    );
}

