import React, { createContext, useReducer, useContext, ReactNode, useCallback, useEffect, useRef } from 'react';
import type { ProjectState, ProjectAction, Scene, Character, Toast } from '../types';
import { 
    parseStoryboardIntoScenes, 
    identifyCharacters,
    generateImageForScene,
    generateVideoForScene,
    checkVideoStatus,
    generateAudioForScene
} from '../services/gemini';

const AVAILABLE_VOICES = [
    { name: 'Puck', description: 'Voz Femenina, enérgica y juvenil' },
    { name: 'Zephyr', description: 'Voz Masculina, amigable y clara' },
    { name: 'Kore', description: 'Voz Femenina, neutra y profesional' },
    { name: 'Charon', description: 'Voz Masculina, grave y épica' },
    { name: 'Fenrir', description: 'Voz Masculina, profunda y misteriosa' },
    { name: 'Achernar', description: 'Voz Masculina, serena y adulta' },
    { name: 'Alnilam', description: 'Voz Masculina, resonante y profunda' },
    { name: 'Callirrhoe', description: 'Voz Femenina, suave y melódica' },
    { name: 'Gacrux', description: 'Voz Masculina, autoritaria y madura' },
    { name: 'Sadachbia', description: 'Voz Femenina, cálida y conversacional' },
    { name: 'Vindemiatrix', description: 'Voz Femenina, elegante y sofisticada' },
    { name: 'Zubenelgenubi', description: 'Voz Masculina, única y distintiva' },
];

const initialState: ProjectState = {
    currentStep: 'input',
    novelText: '',
    scenes: [],
    characters: [],
    statusMessage: '',
    error: '',
    hasApiKey: false,
    imageStyle: 'Cinematográfica',
    artDirection: 'Colores saturados, iluminación dramática tipo noir',
    aspectRatio: '16:9',
    includeTextInImage: false,
    narratorVoice: 'Zephyr',
    isSaving: false,
    isProjectSaved: false,
    isMovieModalOpen: false,
    toasts: [],
};

const projectReducer = (state: ProjectState, action: ProjectAction): ProjectState => {
    switch (action.type) {
        case 'SET_STEP': return { ...state, currentStep: action.payload };
        case 'SET_NOVEL_TEXT': return { ...state, novelText: action.payload };
        case 'SET_STATUS_MESSAGE': return { ...state, statusMessage: action.payload };
        case 'SET_ERROR': return { ...state, error: action.payload, statusMessage: '' };
        case 'START_ANALYSIS': return { ...state, statusMessage: 'Analizando el alma de tu historia...', error: '' };
        case 'ANALYZE_SUCCESS': return { ...state, characters: action.payload, currentStep: 'config', statusMessage: '' };
        case 'ANALYZE_FAILURE': return { ...state, error: action.payload, statusMessage: '' };
        case 'START_SCENE_GENERATION': return { ...state, statusMessage: 'Arquitectando el storyboard visual...', currentStep: 'scenes', error: '' };
        case 'SCENE_GENERATION_INITIALIZE': return { ...state, scenes: action.payload };
        case 'SCENE_GENERATION_COMPLETE': return { ...state, statusMessage: '' };
        case 'SCENE_GENERATION_FAILURE': return { ...state, error: action.payload, statusMessage: '' };
        case 'UPDATE_SCENE': return { ...state, scenes: state.scenes.map(s => s.id === action.payload.sceneId ? { ...s, ...action.payload.updates } : s) };
        case 'UPDATE_SCENES_ORDER': return { ...state, scenes: action.payload };
        case 'DELETE_SCENE': return { ...state, scenes: state.scenes.filter(s => s.id !== action.payload) };
        case 'UPDATE_CHARACTER_VOICE': return { ...state, characters: state.characters.map(c => c.name === action.payload.characterName ? { ...c, voice: action.payload.newVoice } : c) };
        case 'SET_CONFIG': return { ...state, ...action.payload };
        case 'UPDATE_SCENE_CONFIG': return { ...state, scenes: state.scenes.map(s => s.id === action.payload.sceneId ? { ...s, ...action.payload.config } : s)};
        case 'OPEN_MOVIE_MODAL': return { ...state, isMovieModalOpen: true };
        case 'CLOSE_MOVIE_MODAL': return { ...state, isMovieModalOpen: false };
        case 'LOAD_PROJECT': 
            return {
                ...initialState,
                ...action.payload,
                statusMessage: '',
                isSaving: false,
                isMovieModalOpen: false,
                scenes: action.payload.scenes.map(s => ({...s, isGeneratingAudio: false, isGeneratingImage: false, isGeneratingVideo: false })),
            };
        case 'RESET_PROJECT': return { ...initialState };
        case 'SET_API_KEY_STATUS': return { ...state, hasApiKey: action.payload };
        case 'ADD_TOAST': return { ...state, toasts: [...state.toasts, { ...action.payload, id: Date.now() }] };
        case 'REMOVE_TOAST': return { ...state, toasts: state.toasts.filter(t => t.id !== action.payload) };
        default: return state;
    }
};

const getAudioDuration = (url: string): Promise<number> => {
    return new Promise((resolve) => {
        const audio = new Audio(url);
        audio.addEventListener('loadedmetadata', () => resolve(audio.duration));
        audio.addEventListener('error', () => resolve(6));
    });
};

const ProjectStateContext = createContext<ProjectState | undefined>(undefined);
const ProjectDispatchContext = createContext<React.Dispatch<ProjectAction> | undefined>(undefined);

export const ProjectProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
    const [state, dispatch] = useReducer(projectReducer, initialState);

    useEffect(() => {
      const saved = localStorage.getItem('interactiveNovelProject');
      if (saved) dispatch({ type: 'SET_CONFIG', payload: { isProjectSaved: true }});
    }, []);

    return (
        <ProjectStateContext.Provider value={state}>
            <ProjectDispatchContext.Provider value={dispatch}>
                {children}
            </ProjectDispatchContext.Provider>
        </ProjectStateContext.Provider>
    );
};

export const useProjectState = () => {
    const context = useContext(ProjectStateContext);
    if (!context) throw new Error('useProjectState must be used within a ProjectProvider');
    return context;
};

export const useProjectDispatch = () => {
    const context = useContext(ProjectDispatchContext);
    if (!context) throw new Error('useProjectDispatch must be used within a ProjectProvider');
    return context;
};

export const useProjectActions = () => {
    const dispatch = useProjectDispatch();
    const state = useProjectState();

    const handleAnalyzeText = useCallback(async () => {
        if (!state.novelText.trim()) {
            dispatch({ type: 'SET_ERROR', payload: 'El guion no puede estar vacío.' });
            return;
        }
        dispatch({ type: 'START_ANALYSIS' });
        try {
            const chars = await identifyCharacters(state.novelText);
            const charsWithVoices = chars.map((char, i) => ({
                ...char,
                voice: AVAILABLE_VOICES[i % AVAILABLE_VOICES.length].name
            }));
            dispatch({ type: 'ANALYZE_SUCCESS', payload: charsWithVoices });
        } catch (err: any) {
            dispatch({ type: 'ANALYZE_FAILURE', payload: err.message });
        }
    }, [state.novelText, dispatch]);

    const handleGenerateScenes = useCallback(async () => {
        dispatch({ type: 'START_SCENE_GENERATION' });
        try {
            const scenes = await parseStoryboardIntoScenes(state.novelText);
            const initScenes: Scene[] = scenes.map((s, i) => ({
                id: Date.now() + i,
                parts: s.parts,
                isGeneratingImage: true,
                isGeneratingVideo: false,
                isGeneratingAudio: false,
            }));
            dispatch({ type: 'SCENE_GENERATION_INITIALIZE', payload: initScenes });

            for (const scene of initScenes) {
                try {
                    const { imageUrl, imagePrompt } = await generateImageForScene(scene.parts, state.imageStyle, state.characters, state.artDirection, state.includeTextInImage);
                    dispatch({ type: 'UPDATE_SCENE', payload: { sceneId: scene.id, updates: { imageUrl, imagePrompt, isGeneratingImage: false } } });
                } catch {
                    dispatch({ type: 'UPDATE_SCENE', payload: { sceneId: scene.id, updates: { isGeneratingImage: false, imageError: 'Error' } } });
                }
            }
            dispatch({ type: 'SCENE_GENERATION_COMPLETE' });
        } catch (err: any) {
            dispatch({ type: 'SCENE_GENERATION_FAILURE', payload: err.message });
        }
    }, [state, dispatch]);

    const handleNarrateScene = useCallback(async (sceneId: number) => {
        const scene = state.scenes.find(s => s.id === sceneId);
        if (!scene) return;
        dispatch({ type: 'UPDATE_SCENE', payload: { sceneId, updates: { isGeneratingAudio: true } } });
        try {
            const audioUrl = await generateAudioForScene(scene.parts, state.characters, state.narratorVoice);
            const duration = await getAudioDuration(audioUrl);
            dispatch({ type: 'UPDATE_SCENE', payload: { sceneId, updates: { audioUrl, duration, isGeneratingAudio: false } } });
        } catch (err: any) {
            dispatch({ type: 'UPDATE_SCENE', payload: { sceneId, updates: { isGeneratingAudio: false, audioError: err.message } } });
        }
    }, [state, dispatch]);

    const handleSaveProject = useCallback(async () => {
        dispatch({ type: 'SET_CONFIG', payload: { isSaving: true } });
        try {
            const cleanScenes = state.scenes.map(s => ({
                ...s,
                isGeneratingImage: false, isGeneratingVideo: false, isGeneratingAudio: false,
                // Nota: Los blob URLs morirán al recargar, pero las imágenes base64 persisten.
            }));
            const stateToSave = { ...state, scenes: cleanScenes, isSaving: false, statusMessage: '', error: '' };
            localStorage.setItem('interactiveNovelProject', JSON.stringify(stateToSave));
            dispatch({ type: 'SET_CONFIG', payload: { isSaving: false, isProjectSaved: true } });
            dispatch({ type: 'ADD_TOAST', payload: { message: '¡Proyecto guardado!', type: 'success' } });
        } catch (e) {
            dispatch({ type: 'SET_CONFIG', payload: { isSaving: false } });
            dispatch({ type: 'ADD_TOAST', payload: { message: 'Error de espacio en almacenamiento.', type: 'error' } });
        }
    }, [state, dispatch]);

    const handleLoadProject = useCallback(() => {
        const saved = localStorage.getItem('interactiveNovelProject');
        if (saved) {
            dispatch({ type: 'LOAD_PROJECT', payload: JSON.parse(saved) });
            dispatch({ type: 'ADD_TOAST', payload: { message: 'Proyecto cargado correctamente.', type: 'success' } });
        }
    }, [dispatch]);

    const handleResetProject = useCallback(() => {
        if (confirm('¿Seguro que quieres borrar todo y empezar de nuevo?')) {
            dispatch({ type: 'RESET_PROJECT' });
            dispatch({ type: 'ADD_TOAST', payload: { message: 'Proyecto reseteado.', type: 'info' } });
        }
    }, [dispatch]);

    return {
        handleAnalyzeText,
        handleGenerateScenes,
        handleNarrateScene,
        handleSaveProject,
        handleLoadProject,
        handleResetProject
    };
};

import React, { useRef, useState, useEffect } from 'react';
import type { Scene } from '../types';
import { useProjectState, useProjectDispatch, useProjectActions } from '../context/ProjectContext';
import Loader from './Loader';
import { FilmIcon, SpeakerWaveIcon, ClipboardIcon, TrashIcon, DragHandleIcon, MusicNoteIcon, PlayIcon, PauseIcon, DownloadIcon, UploadIcon } from './Icons';
import { generateVideoForScene, checkVideoStatus } from '../services/gemini';

const PREDEFINED_MUSIC = [
    { name: "Sin música ambiental", url: "" }, 
    { name: "Suspense y Misterio", url: "https://cdn.pixabay.com/audio/2022/11/21/audio_a18db14263.mp3" }, 
    { name: "Acción Épica", url: "https://cdn.pixabay.com/audio/2023/08/03/audio_eb72f1c826.mp3" }, 
    { name: "Bosque Fantástico", url: "https://cdn.pixabay.com/audio/2022/08/17/audio_33b68d653c.mp3" }
];

interface SceneCardProps {
    scene: Scene;
    sceneNumber: number;
}

export default function SceneCard({ scene, sceneNumber }: SceneCardProps) {
    const dispatch = useProjectDispatch();
    const { hasApiKey, aspectRatio } = useProjectState();
    const { handleNarrateScene } = useProjectActions();

    const [isPlayingAudio, setIsPlayingAudio] = useState(false);
    const [isPlayingMusic, setIsPlayingMusic] = useState(false);

    const audioPlayerRef = useRef<HTMLAudioElement | null>(null);
    const musicPlayerRef = useRef<HTMLAudioElement | null>(null);
    const imageUploadRef = useRef<HTMLInputElement>(null);
    const videoUploadRef = useRef<HTMLInputElement>(null);

    const toggleAudioPreview = () => {
        if (!audioPlayerRef.current) return;
        if (isPlayingAudio) {
            audioPlayerRef.current.pause();
        } else {
            if (isPlayingMusic && musicPlayerRef.current) musicPlayerRef.current.pause();
            audioPlayerRef.current.play().catch(() => {});
        }
    };

    const toggleMusicPreview = () => {
        if (!musicPlayerRef.current || !scene.backgroundMusicUrl) return;
        if (isPlayingMusic) {
            musicPlayerRef.current.pause();
        } else {
            if (isPlayingAudio && audioPlayerRef.current) audioPlayerRef.current.pause();
            musicPlayerRef.current.play().catch(() => {});
        }
    };

    const handleResetAudio = () => {
        dispatch({ type: 'UPDATE_SCENE', payload: { sceneId: scene.id, updates: { audioUrl: undefined } } });
    };

    const handleDownload = (url: string, filename: string) => {
        const link = document.createElement('a');
        link.href = url;
        link.download = filename;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onload = (event) => {
                dispatch({ type: 'UPDATE_SCENE', payload: { sceneId: scene.id, updates: { imageUrl: event.target?.result as string, isGeneratingImage: false } } });
                dispatch({ type: 'ADD_TOAST', payload: { message: 'Imagen subida', type: 'success' } });
            };
            reader.readAsDataURL(file);
        }
    };

    const handleVideoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const videoUrl = URL.createObjectURL(file);
            dispatch({ type: 'UPDATE_SCENE', payload: { sceneId: scene.id, updates: { videoUrl, isGeneratingVideo: false } } });
            dispatch({ type: 'ADD_TOAST', payload: { message: 'Video vinculado', type: 'success' } });
        }
    };

    const handleAnimate = async () => {
        if (typeof (window as any).aistudio !== 'undefined' && !hasApiKey) {
            await (window as any).aistudio.openSelectKey();
            dispatch({ type: 'SET_API_KEY_STATUS', payload: true });
        }

        dispatch({type: 'UPDATE_SCENE', payload: {sceneId: scene.id, updates: { isGeneratingVideo: true, videoError: undefined }}});

        try {
            const operation = await generateVideoForScene(scene.parts, aspectRatio);
            const check = async () => {
                const status = await checkVideoStatus(operation);
                if (status.done) {
                    const url = `${status.response?.generatedVideos?.[0]?.video?.uri}&key=${process.env.API_KEY}`;
                    dispatch({type: 'UPDATE_SCENE', payload: {sceneId: scene.id, updates: { videoUrl: url, isGeneratingVideo: false }}});
                    dispatch({ type: 'ADD_TOAST', payload: { message: `Video de Escena ${sceneNumber} listo`, type: 'success' } });
                } else {
                    setTimeout(check, 8000);
                }
            };
            check();
        } catch (err: any) {
            dispatch({type: 'UPDATE_SCENE', payload: {sceneId: scene.id, updates: { isGeneratingVideo: false, videoError: err.message }}});
        }
    };

    useEffect(() => {
        if (musicPlayerRef.current) {
            musicPlayerRef.current.pause();
            setIsPlayingMusic(false);
        }
    }, [scene.backgroundMusicUrl]);

    return (
        <div className="bg-gray-900/40 backdrop-blur-2xl border border-white/5 rounded-[2rem] overflow-hidden shadow-2xl hover:border-sky-500/30 transition-all duration-700 group/card">
            <header className="flex items-center justify-between bg-white/[0.02] p-6 border-b border-white/5">
                <div className="flex items-center gap-4">
                    <div className="p-2.5 bg-sky-500/10 rounded-2xl text-sky-400 group-hover/card:scale-110 transition-transform">
                        <DragHandleIcon className="w-5 h-5 cursor-grab active:cursor-grabbing" />
                    </div>
                    <div>
                        <h3 className="font-black text-lg text-white tracking-tight">ESCENA {sceneNumber}</h3>
                        <p className="text-[10px] text-gray-500 uppercase tracking-[0.2em] font-bold">Bloque de Storyboard</p>
                    </div>
                </div>
                <button onClick={() => dispatch({ type: 'DELETE_SCENE', payload: scene.id })} className="p-2 text-gray-600 hover:text-red-400 hover:bg-red-400/10 rounded-full transition-all">
                    <TrashIcon className="w-5 h-5" />
                </button>
            </header>

            <div className="flex flex-col xl:flex-row">
                {/* Media Section */}
                <div className="xl:w-3/5 aspect-video bg-gray-950 relative group/media overflow-hidden border-r border-white/5">
                    {scene.isGeneratingImage ? (
                        <div className="absolute inset-0 flex items-center justify-center bg-gray-950"><Loader message="Generando visual..." /></div>
                    ) : scene.imageUrl ? (
                        scene.videoUrl ? (
                            <div className="relative w-full h-full">
                                <video src={scene.videoUrl} controls className="w-full h-full object-cover" />
                                <div className="absolute top-6 left-6 flex gap-2">
                                    <div className="px-4 py-1.5 bg-purple-600/90 backdrop-blur-xl rounded-full text-[10px] font-black text-white uppercase tracking-widest shadow-2xl animate-pulse">Cinemática Lista</div>
                                    <button onClick={() => handleDownload(scene.videoUrl!, `nova-video-${sceneNumber}.mp4`)} className="p-2 bg-black/60 hover:bg-sky-500 rounded-full text-white transition-all shadow-xl" title="Descargar Video">
                                        <DownloadIcon className="w-4 h-4" />
                                    </button>
                                </div>
                            </div>
                        ) : (
                            <div className="relative w-full h-full group/img">
                                <img src={scene.imageUrl} alt="" className="w-full h-full object-cover group-hover/img:scale-105 transition-transform duration-[2s]" />
                                <div className="absolute top-6 left-6 flex gap-2 opacity-0 group-hover/img:opacity-100 transition-opacity duration-500">
                                    <button onClick={() => handleDownload(scene.imageUrl!, `nova-img-${sceneNumber}.png`)} className="p-2 bg-black/60 hover:bg-sky-500 rounded-full text-white transition-all shadow-xl" title="Descargar Imagen">
                                        <DownloadIcon className="w-4 h-4" />
                                    </button>
                                    <button onClick={() => imageUploadRef.current?.click()} className="p-2 bg-black/60 hover:bg-sky-500 rounded-full text-white transition-all shadow-xl" title="Remplazar Imagen">
                                        <UploadIcon className="w-4 h-4" />
                                    </button>
                                </div>
                            </div>
                        )
                    ) : (
                        <div className="absolute inset-0 flex flex-col items-center justify-center gap-6 text-gray-700 bg-[radial-gradient(circle_at_center,_#111_0%,_#000_100%)]">
                             <div className="w-16 h-16 rounded-3xl border-2 border-dashed border-gray-800 flex items-center justify-center">
                                <UploadIcon className="w-6 h-6 opacity-20" />
                             </div>
                             <button onClick={() => imageUploadRef.current?.click()} className="px-6 py-2.5 bg-white/5 hover:bg-white/10 rounded-2xl text-xs font-bold text-gray-400 border border-white/5 transition-all">Subir Arte Propio</button>
                        </div>
                    )}
                    <input ref={imageUploadRef} type="file" accept="image/*" className="hidden" onChange={handleImageUpload} />
                    <input ref={videoUploadRef} type="file" accept="video/*" className="hidden" onChange={handleVideoUpload} />
                </div>

                {/* Controls Section */}
                <div className="xl:w-2/5 p-10 flex flex-col justify-between space-y-8 bg-gradient-to-br from-white/[0.01] to-transparent">
                    <div className="space-y-6">
                        <div className="max-h-40 overflow-y-auto pr-4 custom-scrollbar space-y-3">
                            {scene.parts.map((p, i) => (
                                <div key={i} className={`p-3 rounded-2xl border transition-colors ${p.type === 'DIALOGUE' ? 'bg-sky-500/5 border-sky-500/20' : 'bg-white/5 border-transparent'}`}>
                                    {p.speaker && <p className="text-[9px] font-black text-sky-400 uppercase tracking-widest mb-1">{p.speaker}</p>}
                                    <p className={`text-sm leading-relaxed ${p.type === 'DIALOGUE' ? 'text-white font-medium italic' : 'text-gray-400'}`}>
                                        {p.text}
                                    </p>
                                </div>
                            ))}
                        </div>
                    </div>

                    <div className="space-y-4">
                        <div className="grid grid-cols-2 gap-4">
                            {!scene.audioUrl ? (
                                <button 
                                    onClick={() => handleNarrateScene(scene.id)} 
                                    disabled={scene.isGeneratingAudio}
                                    className="flex flex-col items-center justify-center gap-2 py-5 rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest bg-sky-600 hover:bg-sky-500 text-white shadow-xl shadow-sky-600/10 transition-all disabled:opacity-50 group/btn"
                                >
                                    {scene.isGeneratingAudio ? <div className="w-5 h-5 border-2 border-white/20 border-t-white rounded-full animate-spin"></div> : <SpeakerWaveIcon className="w-6 h-6 group-hover/btn:scale-110 transition-transform" />}
                                    Generar Voz
                                </button>
                            ) : (
                                <div className="flex flex-col gap-2">
                                    <button 
                                        onClick={toggleAudioPreview}
                                        className={`flex flex-col items-center justify-center gap-2 py-5 rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest transition-all ${isPlayingAudio ? 'bg-amber-500 text-white shadow-amber-500/20 shadow-xl' : 'bg-green-500/10 text-green-400 border border-green-500/20 hover:bg-green-500/20'}`}
                                    >
                                        {isPlayingAudio ? <PauseIcon className="w-6 h-6 animate-pulse" /> : <PlayIcon className="w-6 h-6" />}
                                        {isPlayingAudio ? 'Reproduciendo' : 'Oír Narración'}
                                        <audio 
                                            ref={audioPlayerRef} 
                                            src={scene.audioUrl} 
                                            onEnded={() => setIsPlayingAudio(false)}
                                            onPause={() => setIsPlayingAudio(false)}
                                            onPlay={() => setIsPlayingAudio(true)}
                                            className="hidden" 
                                        />
                                    </button>
                                    <button onClick={handleResetAudio} className="text-[9px] text-gray-600 hover:text-sky-400 uppercase tracking-[0.2em] font-black transition-colors text-center">Remplazar Voz</button>
                                </div>
                            )}

                            <div className="flex flex-col gap-2">
                                <button 
                                    onClick={handleAnimate}
                                    disabled={scene.isGeneratingVideo || !scene.imageUrl || !!scene.videoUrl}
                                    className={`flex flex-col items-center justify-center gap-2 py-5 rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest transition-all ${scene.videoUrl ? 'bg-purple-500/10 text-purple-400 border border-purple-500/20' : 'bg-purple-600 hover:bg-purple-500 text-white shadow-xl shadow-purple-600/10 disabled:opacity-20'}`}
                                >
                                    {scene.isGeneratingVideo ? <div className="w-5 h-5 border-2 border-white/20 border-t-white rounded-full animate-spin"></div> : <FilmIcon className="w-6 h-6" />}
                                    {scene.videoUrl ? 'Cinemática OK' : 'Animar con IA'}
                                </button>
                                {!scene.videoUrl && scene.imageUrl && (
                                    <button onClick={() => videoUploadRef.current?.click()} className="text-[9px] text-gray-600 hover:text-purple-400 uppercase tracking-[0.2em] font-black transition-colors text-center">Subir Video</button>
                                )}
                            </div>
                        </div>

                        <div className="bg-white/[0.03] p-4 rounded-2xl border border-white/5 space-y-3">
                            <div className="flex items-center justify-between">
                                <div className="flex items-center gap-2 text-gray-500">
                                    <MusicNoteIcon className="w-4 h-4" />
                                    <span className="text-[10px] font-black uppercase tracking-widest">Atmósfera</span>
                                </div>
                                {scene.backgroundMusicUrl && (
                                    <button 
                                        onClick={toggleMusicPreview}
                                        className={`p-1.5 rounded-lg transition-all ${isPlayingMusic ? 'bg-sky-500 text-white shadow-lg' : 'bg-white/5 text-gray-400 hover:bg-white/10'}`}
                                    >
                                        {isPlayingMusic ? <PauseIcon className="w-3.2 h-3.2" /> : <PlayIcon className="w-3.2 h-3.2" />}
                                    </button>
                                )}
                            </div>
                            <select 
                                value={scene.backgroundMusicUrl || ''} 
                                onChange={e => dispatch({ type: 'UPDATE_SCENE_CONFIG', payload: { sceneId: scene.id, config: { backgroundMusicUrl: e.target.value } } })}
                                className="bg-transparent text-xs text-gray-400 focus:text-white outline-none w-full cursor-pointer font-medium"
                            >
                                {PREDEFINED_MUSIC.map(m => <option key={m.name} value={m.url} className="bg-gray-900">{m.name}</option>)}
                            </select>
                            <audio 
                                ref={musicPlayerRef} 
                                src={scene.backgroundMusicUrl} 
                                onEnded={() => setIsPlayingMusic(false)}
                                onPause={() => setIsPlayingMusic(false)}
                                onPlay={() => setIsPlayingMusic(true)}
                                loop
                                className="hidden"
                            />
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

import React, { useRef } from 'react';
import { useProjectState, useProjectDispatch, useProjectActions } from '../context/ProjectContext';
import SceneCard from './SceneCard';
import { MovieIcon } from './Icons';

export default function ScenesDashboard() {
    const { scenes } = useProjectState();
    const dispatch = useProjectDispatch();

    const dragItem = useRef<number | null>(null);
    const dragOverItem = useRef<number | null>(null);

    const handleDragEnd = () => {
        if (dragItem.current === null || dragOverItem.current === null || dragItem.current === dragOverItem.current) return;
        const scenesCopy = [...scenes];
        const draggedItemContent = scenesCopy.splice(dragItem.current, 1)[0];
        scenesCopy.splice(dragOverItem.current, 0, draggedItemContent);
        dragItem.current = null;
        dragOverItem.current = null;
        dispatch({ type: 'UPDATE_SCENES_ORDER', payload: scenesCopy });
    };

    const allAudioGenerated = scenes.length > 0 && scenes.every(s => s.audioUrl);

    return (
       <div className="max-w-7xl mx-auto space-y-12">
         <div className="flex flex-col md:flex-row items-center justify-between gap-6 bg-sky-500/5 p-8 rounded-[2.5rem] border border-sky-500/10">
            <div className="text-center md:text-left">
                <h2 className="text-3xl font-black text-white tracking-tight">Storyboard Interactivo</h2>
                <p className="text-gray-400 text-sm mt-1">Organiza tus escenas, genera voces y anima cada cuadro con IA.</p>
            </div>

             <button 
                onClick={() => dispatch({type: 'OPEN_MOVIE_MODAL'})} 
                disabled={!allAudioGenerated} 
                className="group relative px-8 py-4 flex items-center gap-3 bg-gradient-to-r from-purple-600 to-sky-600 hover:from-purple-500 hover:to-sky-500 text-white font-black text-sm uppercase tracking-widest rounded-2xl shadow-2xl shadow-purple-500/20 transition-all disabled:opacity-30 disabled:grayscale overflow-hidden"
             >
                <div className="absolute inset-0 bg-white/20 translate-y-full group-hover:translate-y-0 transition-transform duration-500"></div>
                <MovieIcon className="w-6 h-6 relative z-10"/>
                <span className="relative z-10">{allAudioGenerated ? 'Producir Película' : 'Faltan Narraciones'}</span>
             </button>
        </div>

        <div className="space-y-10">
            {scenes.map((scene, index) => (
                <div
                    key={scene.id}
                    draggable
                    onDragStart={() => (dragItem.current = index)}
                    onDragEnter={() => (dragOverItem.current = index)}
                    onDragEnd={handleDragEnd}
                    onDragOver={(e) => e.preventDefault()}
                    className="cursor-move group"
                >
                    <SceneCard 
                        scene={scene} 
                        sceneNumber={index + 1}
                    />
                </div>
            ))}
        </div>

        <div className="flex justify-center pb-20">
             <button 
                onClick={() => dispatch({ type: 'SET_STEP', payload: 'config' })}
                className="text-gray-500 hover:text-sky-400 font-bold text-sm transition-colors"
            >
                &larr; Volver a Configuración de Personajes
            </button>
        </div>
       </div>
    );
}

import React, { useRef, useState, useEffect } from 'react';
import type { Scene } from '../types';
import { useProjectState, useProjectDispatch, useProjectActions } from '../context/ProjectContext';
import Loader from './Loader';
import { FilmIcon, SpeakerWaveIcon, ClipboardIcon, TrashIcon, DragHandleIcon, MusicNoteIcon, PlayIcon, PauseIcon, DownloadIcon, UploadIcon } from './Icons';
import { generateVideoForScene, checkVideoStatus } from '../services/gemini';

const PREDEFINED_MUSIC = [
    { name: "Sin música ambiental", url: "" }, 
    { name: "Suspense y Misterio", url: "https://cdn.pixabay.com/audio/2022/11/21/audio_a18db14263.mp3" }, 
    { name: "Acción Épica", url: "https://cdn.pixabay.com/audio/2023/08/03/audio_eb72f1c826.mp3" }, 
    { name: "Bosque Fantástico", url: "https://cdn.pixabay.com/audio/2022/08/17/audio_33b68d653c.mp3" }
];

interface SceneCardProps {
    scene: Scene;
    sceneNumber: number;
}

export default function SceneCard({ scene, sceneNumber }: SceneCardProps) {
    const dispatch = useProjectDispatch();
    const { hasApiKey, aspectRatio } = useProjectState();
    const { handleNarrateScene } = useProjectActions();

    const [isPlayingAudio, setIsPlayingAudio] = useState(false);
    const [isPlayingMusic, setIsPlayingMusic] = useState(false);

    const audioPlayerRef = useRef<HTMLAudioElement | null>(null);
    const musicPlayerRef = useRef<HTMLAudioElement | null>(null);
    const imageUploadRef = useRef<HTMLInputElement>(null);
    const videoUploadRef = useRef<HTMLInputElement>(null);

    const toggleAudioPreview = () => {
        if (!audioPlayerRef.current) return;
        if (isPlayingAudio) {
            audioPlayerRef.current.pause();
        } else {
            if (isPlayingMusic && musicPlayerRef.current) musicPlayerRef.current.pause();
            audioPlayerRef.current.play().catch(e => console.error("Error voz:", e));
        }
    };

    const toggleMusicPreview = () => {
        if (!musicPlayerRef.current || !scene.backgroundMusicUrl) return;

        if (isPlayingMusic) {
            musicPlayerRef.current.pause();
        } else {
            // Pausar la voz si está sonando
            if (isPlayingAudio && audioPlayerRef.current) audioPlayerRef.current.pause();

            musicPlayerRef.current.volume = 0.5; // Asegurar volumen audible
            const playPromise = musicPlayerRef.current.play();
            if (playPromise !== undefined) {
                playPromise.catch(error => {
                    console.error("Error al reproducir música:", error);
                    dispatch({ type: 'ADD_TOAST', payload: { message: 'Error al reproducir música ambiental', type: 'error' } });
                    setIsPlayingMusic(false);
                });
            }
        }
    };

    const handleResetAudio = () => {
        dispatch({ type: 'UPDATE_SCENE', payload: { sceneId: scene.id, updates: { audioUrl: undefined } } });
    };

    const handleDownload = (url: string, filename: string) => {
        const link = document.createElement('a');
        link.href = url;
        link.download = filename;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onload = (event) => {
                dispatch({ type: 'UPDATE_SCENE', payload: { sceneId: scene.id, updates: { imageUrl: event.target?.result as string, isGeneratingImage: false } } });
                dispatch({ type: 'ADD_TOAST', payload: { message: 'Imagen subida', type: 'success' } });
            };
            reader.readAsDataURL(file);
        }
    };

    const handleVideoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const videoUrl = URL.createObjectURL(file);
            dispatch({ type: 'UPDATE_SCENE', payload: { sceneId: scene.id, updates: { videoUrl, isGeneratingVideo: false } } });
            dispatch({ type: 'ADD_TOAST', payload: { message: 'Video vinculado', type: 'success' } });
        }
    };

    const handleAnimate = async () => {
        if (typeof (window as any).aistudio !== 'undefined' && !hasApiKey) {
            await (window as any).aistudio.openSelectKey();
            dispatch({ type: 'SET_API_KEY_STATUS', payload: true });
        }

        dispatch({type: 'UPDATE_SCENE', payload: {sceneId: scene.id, updates: { isGeneratingVideo: true, videoError: undefined }}});

        try {
            const operation = await generateVideoForScene(scene.parts, aspectRatio);
            const check = async () => {
                const status = await checkVideoStatus(operation);
                if (status.done) {
                    const url = `${status.response?.generatedVideos?.[0]?.video?.uri}&key=${process.env.API_KEY}`;
                    dispatch({type: 'UPDATE_SCENE', payload: {sceneId: scene.id, updates: { videoUrl: url, isGeneratingVideo: false }}});
                    dispatch({ type: 'ADD_TOAST', payload: { message: `Video de Escena ${sceneNumber} listo`, type: 'success' } });
                } else {
                    setTimeout(check, 8000);
                }
            };
            check();
        } catch (err: any) {
            dispatch({type: 'UPDATE_SCENE', payload: {sceneId: scene.id, updates: { isGeneratingVideo: false, videoError: err.message }}});
        }
    };

    // Cuando la música cambia en el selector, pausamos y recargamos
    useEffect(() => {
        if (musicPlayerRef.current) {
            musicPlayerRef.current.pause();
            musicPlayerRef.current.load(); // Forzar carga del nuevo src
            setIsPlayingMusic(false);
        }
    }, [scene.backgroundMusicUrl]);

    return (
        <div className="bg-gray-900/40 backdrop-blur-2xl border border-white/5 rounded-[2rem] overflow-hidden shadow-2xl hover:border-sky-500/30 transition-all duration-700 group/card">
            <header className="flex items-center justify-between bg-white/[0.02] p-6 border-b border-white/5">
                <div className="flex items-center gap-4">
                    <div className="p-2.5 bg-sky-500/10 rounded-2xl text-sky-400 group-hover/card:scale-110 transition-transform">
                        <DragHandleIcon className="w-5 h-5 cursor-grab active:cursor-grabbing" />
                    </div>
                    <div>
                        <h3 className="font-black text-lg text-white tracking-tight">ESCENA {sceneNumber}</h3>
                        <p className="text-[10px] text-gray-500 uppercase tracking-[0.2em] font-bold">Bloque de Storyboard</p>
                    </div>
                </div>
                <button onClick={() => dispatch({ type: 'DELETE_SCENE', payload: scene.id })} className="p-2 text-gray-600 hover:text-red-400 hover:bg-red-400/10 rounded-full transition-all">
                    <TrashIcon className="w-5 h-5" />
                </button>
            </header>

            <div className="flex flex-col xl:flex-row">
                {/* Media Section */}
                <div className="xl:w-3/5 aspect-video bg-gray-950 relative group/media overflow-hidden border-r border-white/5">
                    {scene.isGeneratingImage ? (
                        <div className="absolute inset-0 flex items-center justify-center bg-gray-950"><Loader message="Generando visual..." /></div>
                    ) : scene.imageUrl ? (
                        scene.videoUrl ? (
                            <div className="relative w-full h-full">
                                <video src={scene.videoUrl} controls className="w-full h-full object-cover" />
                                <div className="absolute top-6 left-6 flex gap-2">
                                    <div className="px-4 py-1.5 bg-purple-600/90 backdrop-blur-xl rounded-full text-[10px] font-black text-white uppercase tracking-widest shadow-2xl animate-pulse">Cinemática Lista</div>
                                    <button onClick={() => handleDownload(scene.videoUrl!, `nova-video-${sceneNumber}.mp4`)} className="p-2 bg-black/60 hover:bg-sky-500 rounded-full text-white transition-all shadow-xl" title="Descargar Video">
                                        <DownloadIcon className="w-4 h-4" />
                                    </button>
                                </div>
                            </div>
                        ) : (
                            <div className="relative w-full h-full group/img">
                                <img src={scene.imageUrl} alt="" className="w-full h-full object-cover group-hover/img:scale-105 transition-transform duration-[2s]" />
                                <div className="absolute top-6 left-6 flex gap-2 opacity-0 group-hover/img:opacity-100 transition-opacity duration-500">
                                    <button onClick={() => handleDownload(scene.imageUrl!, `nova-img-${sceneNumber}.png`)} className="p-2 bg-black/60 hover:bg-sky-500 rounded-full text-white transition-all shadow-xl" title="Descargar Imagen">
                                        <DownloadIcon className="w-4 h-4" />
                                    </button>
                                    <button onClick={() => imageUploadRef.current?.click()} className="p-2 bg-black/60 hover:bg-sky-500 rounded-full text-white transition-all shadow-xl" title="Remplazar Imagen">
                                        <UploadIcon className="w-4 h-4" />
                                    </button>
                                </div>
                            </div>
                        )
                    ) : (
                        <div className="absolute inset-0 flex flex-col items-center justify-center gap-6 text-gray-700 bg-[radial-gradient(circle_at_center,_#111_0%,_#000_100%)]">
                             <div className="w-16 h-16 rounded-3xl border-2 border-dashed border-gray-800 flex items-center justify-center">
                                <UploadIcon className="w-6 h-6 opacity-20" />
                             </div>
                             <button onClick={() => imageUploadRef.current?.click()} className="px-6 py-2.5 bg-white/5 hover:bg-white/10 rounded-2xl text-xs font-bold text-gray-400 border border-white/5 transition-all">Subir Arte Propio</button>
                        </div>
                    )}
                    <input ref={imageUploadRef} type="file" accept="image/*" className="hidden" onChange={handleImageUpload} />
                    <input ref={videoUploadRef} type="file" accept="video/*" className="hidden" onChange={handleVideoUpload} />
                </div>

                {/* Controls Section */}
                <div className="xl:w-2/5 p-10 flex flex-col justify-between space-y-8 bg-gradient-to-br from-white/[0.01] to-transparent">
                    <div className="space-y-6">
                        <div className="max-h-40 overflow-y-auto pr-4 custom-scrollbar space-y-3">
                            {scene.parts.map((p, i) => (
                                <div key={i} className={`p-3 rounded-2xl border transition-colors ${p.type === 'DIALOGUE' ? 'bg-sky-500/5 border-sky-500/20' : 'bg-white/5 border-transparent'}`}>
                                    {p.speaker && <p className="text-[9px] font-black text-sky-400 uppercase tracking-widest mb-1">{p.speaker}</p>}
                                    <p className={`text-sm leading-relaxed ${p.type === 'DIALOGUE' ? 'text-white font-medium italic' : 'text-gray-400'}`}>
                                        {p.text}
                                    </p>
                                </div>
                            ))}
                        </div>
                    </div>

                    <div className="space-y-4">
                        <div className="grid grid-cols-2 gap-4">
                            {!scene.audioUrl ? (
                                <button 
                                    onClick={() => handleNarrateScene(scene.id)} 
                                    disabled={scene.isGeneratingAudio}
