const projectReducer = (state: ProjectState, action: ProjectAction): ProjectState => {
    switch (action.type) {
        case 'SET_STEP': return { ...state, currentStep: action.payload };
        case 'SET_NOVEL_TEXT': return { ...state, novelText: action.payload };
        case 'SET_STATUS_MESSAGE': return { ...state, statusMessage: action.payload };
        case 'SET_ERROR': return { ...state, error: action.payload, statusMessage: '' };
        case 'START_ANALYSIS': return { ...state, statusMessage: 'Analizando el alma de tu historia...', error: '' };
        case 'ANALYZE_SUCCESS': return { ...state, characters: action.payload, currentStep: 'config', statusMessage: '' };
        case 'ANALYZE_FAILURE': return { ...state, error: action.payload, statusMessage: '' };
        case 'START_SCENE_GENERATION': return { ...state, statusMessage: 'Arquitectando el storyboard visual...', currentStep: 'scenes', error: '' };
        case 'SCENE_GENERATION_INITIALIZE': return { ...state, scenes: action.payload };
        case 'SCENE_GENERATION_COMPLETE': return { ...state, statusMessage: '' };
        case 'SCENE_GENERATION_FAILURE': return { ...state, error: action.payload, statusMessage: '' };
        case 'UPDATE_SCENE': return { ...state, scenes: state.scenes.map(s => s.id === action.payload.sceneId ? { ...s, ...action.payload.updates } : s) };
        case 'UPDATE_SCENES_ORDER': return { ...state, scenes: action.payload };
        case 'DELETE_SCENE': return { ...state, scenes: state.scenes.filter(s => s.id !== action.payload) };
        case 'UPDATE_CHARACTER_VOICE': return { ...state, characters: state.characters.map(c => c.name === action.payload.characterName ? { ...c, voice: action.payload.newVoice } : c) };
        case 'SET_CONFIG': return { ...state, ...action.payload };
        case 'UPDATE_SCENE_CONFIG': return { ...state, scenes: state.scenes.map(s => s.id === action.payload.sceneId ? { ...s, ...action.payload.config } : s)};
        case 'OPEN_MOVIE_MODAL': return { ...state, isMovieModalOpen: true };
        case 'CLOSE_MOVIE_MODAL': return { ...state, isMovieModalOpen: false };
        case 'LOAD_PROJECT': 
            return {
                ...initialState,
                ...action.payload,
                statusMessage: '',
                isSaving: false,
                isMovieModalOpen: false,
                scenes: action.payload.scenes.map(s => ({...s, isGeneratingAudio: false, isGeneratingImage: false, isGeneratingVideo: false })),
            };
        case 'RESET_PROJECT': return { ...initialState };
        case 'SET_API_KEY_STATUS': return { ...state, hasApiKey: action.payload };
        case 'ADD_TOAST': return { ...state, toasts: [...state.toasts, { ...action.payload, id: Date.now() }] };
        case 'REMOVE_TOAST': return { ...state, toasts: state.toasts.filter(t => t.id !== action.payload) };
        default: return state;
    }
};

const getAudioDuration = (url: string): Promise<number> => {
    return new Promise((resolve) => {
        const audio = new Audio(url);
        audio.addEventListener('loadedmetadata', () => resolve(audio.duration));
        audio.addEventListener('error', () => resolve(6));
    });
};

const ProjectStateContext = createContext<ProjectState | undefined>(undefined);
const ProjectDispatchContext = createContext<React.Dispatch<ProjectAction> | undefined>(undefined);

export const ProjectProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
    const [state, dispatch] = useReducer(projectReducer, initialState);

    useEffect(() => {
      const saved = localStorage.getItem('interactiveNovelProject');
      if (saved) dispatch({ type: 'SET_CONFIG', payload: { isProjectSaved: true }});
    }, []);

    return (
        <ProjectStateContext.Provider value={state}>
            <ProjectDispatchContext.Provider value={dispatch}>
                {children}
            </ProjectDispatchContext.Provider>
        </ProjectStateContext.Provider>
    );
};

export const useProjectState = () => {
    const context = useContext(ProjectStateContext);
    if (!context) throw new Error('useProjectState must be used within a ProjectProvider');
    return context;
};

export const useProjectDispatch = () => {
    const context = useContext(ProjectDispatchContext);
    if (!context) throw new Error('useProjectDispatch must be used within a ProjectProvider');
    return context;
};

export const useProjectActions = () => {
    const dispatch = useProjectDispatch();
    const state = useProjectState();

    const handleAnalyzeText = useCallback(async () => {
        if (!state.novelText.trim()) {
            dispatch({ type: 'SET_ERROR', payload: 'El guion no puede estar vacío.' });
            return;
        }
        dispatch({ type: 'START_ANALYSIS' });
        try {
            const chars = await identifyCharacters(state.novelText);
            const charsWithVoices = chars.map((char, i) => ({
                ...char,
                voice: AVAILABLE_VOICES[i % AVAILABLE_VOICES.length].name
            }));
            dispatch({ type: 'ANALYZE_SUCCESS', payload: charsWithVoices });
        } catch (err: any) {
            dispatch({ type: 'ANALYZE_FAILURE', payload: err.message });
        }
    }, [state.novelText, dispatch]);

    const handleGenerateImageForScene = useCallback(async (sceneId: number) => {
        const scene = state.scenes.find(s => s.id === sceneId);
        if (!scene) return;

        dispatch({ type: 'UPDATE_SCENE', payload: { sceneId, updates: { isGeneratingImage: true, imageError: undefined } } });
        try {
            const { imageUrl, imagePrompt } = await generateImageForScene(
                scene.parts, 
                state.imageStyle, 
                state.characters, 
                state.artDirection, 
                state.includeTextInImage
            );
            dispatch({ type: 'UPDATE_SCENE', payload: { sceneId, updates: { imageUrl, imagePrompt, isGeneratingImage: false } } });
            dispatch({ type: 'ADD_TOAST', payload: { message: 'Imagen sincronizada con estilo global', type: 'success' } });
        } catch (err: any) {
            dispatch({ type: 'UPDATE_SCENE', payload: { sceneId, updates: { isGeneratingImage: false, imageError: err.message } } });
        }
    }, [state, dispatch]);

    const handleGenerateScenes = useCallback(async () => {
        dispatch({ type: 'START_SCENE_GENERATION' });
        try {
            const scenesData = await parseStoryboardIntoScenes(state.novelText);
            const initScenes: Scene[] = scenesData.map((s, i) => ({
                id: Date.now() + i,
                parts: s.parts,
                isGeneratingImage: true,
                isGeneratingVideo: false,
                isGeneratingAudio: false,
            }));
            dispatch({ type: 'SCENE_GENERATION_INITIALIZE', payload: initScenes });

            // Generar secuencialmente para asegurar carga controlada
            for (const scene of initScenes) {
                try {
                    const { imageUrl, imagePrompt } = await generateImageForScene(
                        scene.parts, 
                        state.imageStyle, 
                        state.characters, 
                        state.artDirection, 
                        state.includeTextInImage
                    );
                    dispatch({ type: 'UPDATE_SCENE', payload: { sceneId: scene.id, updates: { imageUrl, imagePrompt, isGeneratingImage: false } } });
                } catch {
                    dispatch({ type: 'UPDATE_SCENE', payload: { sceneId: scene.id, updates: { isGeneratingImage: false, imageError: 'Error de generación' } } });
                }
            }
            dispatch({ type: 'SCENE_GENERATION_COMPLETE' });
        } catch (err: any) {
            dispatch({ type: 'SCENE_GENERATION_FAILURE', payload: err.message });
        }
    }, [state, dispatch]);

    const handleNarrateScene = useCallback(async (sceneId: number) => {
        const scene = state.scenes.find(s => s.id === sceneId);
        if (!scene) return;
        dispatch({ type: 'UPDATE_SCENE', payload: { sceneId, updates: { isGeneratingAudio: true } } });
        try {
            const audioUrl = await generateAudioForScene(scene.parts, state.characters, state.narratorVoice);
            const duration = await getAudioDuration(audioUrl);
            dispatch({ type: 'UPDATE_SCENE', payload: { sceneId, updates: { audioUrl, duration, isGeneratingAudio: false } } });
        } catch (err: any) {
            dispatch({ type: 'UPDATE_SCENE', payload: { sceneId, updates: { isGeneratingAudio: false, audioError: err.message } } });
        }
    }, [state, dispatch]);

    const handleSaveProject = useCallback(async () => {
        dispatch({ type: 'SET_CONFIG', payload: { isSaving: true } });
        try {
            const cleanScenes = state.scenes.map(s => ({
                ...s,
                isGeneratingImage: false, isGeneratingVideo: false, isGeneratingAudio: false,
            }));
            const stateToSave = { ...state, scenes: cleanScenes, isSaving: false, statusMessage: '', error: '' };
            localStorage.setItem('interactiveNovelProject', JSON.stringify(stateToSave));
            dispatch({ type: 'SET_CONFIG', payload: { isSaving: false, isProjectSaved: true } });
            dispatch({ type: 'ADD_TOAST', payload: { message: '¡Proyecto guardado!', type: 'success' } });
        } catch (e) {
            dispatch({ type: 'SET_CONFIG', payload: { isSaving: false } });
            dispatch({ type: 'ADD_TOAST', payload: { message: 'Error de espacio en almacenamiento.', type: 'error' } });
        }
    }, [state, dispatch]);

    const handleLoadProject = useCallback(() => {
        const saved = localStorage.getItem('interactiveNovelProject');
        if (saved) {
            dispatch({ type: 'LOAD_PROJECT', payload: JSON.parse(saved) });
            dispatch({ type: 'ADD_TOAST', payload: { message: 'Proyecto cargado correctamente.', type: 'success' } });
        }
    }, [dispatch]);

    const handleResetProject = useCallback(() => {
        if (confirm('¿Seguro que quieres borrar todo y empezar de nuevo?')) {
            dispatch({ type: 'RESET_PROJECT' });
            dispatch({ type: 'ADD_TOAST', payload: { message: 'Proyecto reseteado.', type: 'info' } });
        }
    }, [dispatch]);

    return {
        handleAnalyzeText,
        handleGenerateScenes,
        handleNarrateScene,
        handleSaveProject,
        handleLoadProject,
        handleResetProject,
        handleGenerateImageForScene
    };
};

import React, { useRef, useState, useEffect } from 'react';
import type { Scene } from '../types';
import { useProjectState, useProjectDispatch, useProjectActions } from '../context/ProjectContext';
import Loader from './Loader';
import { FilmIcon, SpeakerWaveIcon, ClipboardIcon, TrashIcon, DragHandleIcon, MusicNoteIcon, PlayIcon, PauseIcon, DownloadIcon, UploadIcon } from './Icons';
import { generateVideoForScene, checkVideoStatus } from '../services/gemini';

const PREDEFINED_MUSIC = [
    { name: "Sin música ambiental", url: "" }, 
    { name: "Suspense y Misterio", url: "https://cdn.pixabay.com/audio/2022/11/21/audio_a18db14263.mp3" }, 
    { name: "Acción Épica", url: "https://cdn.pixabay.com/audio/2023/08/03/audio_eb72f1c826.mp3" }, 
    { name: "Bosque Fantástico", url: "https://cdn.pixabay.com/audio/2022/08/17/audio_33b68d653c.mp3" }
];

interface SceneCardProps {
    scene: Scene;
    sceneNumber: number;
}

export default function SceneCard({ scene, sceneNumber }: SceneCardProps) {
    const dispatch = useProjectDispatch();
    const { hasApiKey, aspectRatio } = useProjectState();
    const { handleNarrateScene, handleGenerateImageForScene } = useProjectActions();

    const [isPlayingAudio, setIsPlayingAudio] = useState(false);
    const [isPlayingMusic, setIsPlayingMusic] = useState(false);

    const audioPlayerRef = useRef<HTMLAudioElement | null>(null);
    const musicPlayerRef = useRef<HTMLAudioElement | null>(null);
    const imageUploadRef = useRef<HTMLInputElement>(null);
    const videoUploadRef = useRef<HTMLInputElement>(null);

    const toggleAudioPreview = () => {
        if (!audioPlayerRef.current) return;
        if (isPlayingAudio) {
            audioPlayerRef.current.pause();
        } else {
            if (isPlayingMusic && musicPlayerRef.current) musicPlayerRef.current.pause();
            audioPlayerRef.current.play().catch(e => console.error("Error voz:", e));
        }
    };

    const toggleMusicPreview = () => {
        if (!musicPlayerRef.current || !scene.backgroundMusicUrl) return;

        if (isPlayingMusic) {
            musicPlayerRef.current.pause();
        } else {
            if (isPlayingAudio && audioPlayerRef.current) audioPlayerRef.current.pause();

            musicPlayerRef.current.volume = 0.5;
            const playPromise = musicPlayerRef.current.play();
            if (playPromise !== undefined) {
                playPromise.catch(error => {
                    console.error("Error al reproducir música:", error);
                    dispatch({ type: 'ADD_TOAST', payload: { message: 'Error al reproducir música ambiental', type: 'error' } });
                    setIsPlayingMusic(false);
                });
            }
        }
    };

    const handleResetAudio = () => {
        dispatch({ type: 'UPDATE_SCENE', payload: { sceneId: scene.id, updates: { audioUrl: undefined } } });
    };

    const handleDownload = (url: string, filename: string) => {
        const link = document.createElement('a');
        link.href = url;
        link.download = filename;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onload = (event) => {
                dispatch({ type: 'UPDATE_SCENE', payload: { sceneId: scene.id, updates: { imageUrl: event.target?.result as string, isGeneratingImage: false } } });
                dispatch({ type: 'ADD_TOAST', payload: { message: 'Imagen subida', type: 'success' } });
            };
            reader.readAsDataURL(file);
        }
    };

    const handleVideoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const videoUrl = URL.createObjectURL(file);
            dispatch({ type: 'UPDATE_SCENE', payload: { sceneId: scene.id, updates: { videoUrl, isGeneratingVideo: false } } });
            dispatch({ type: 'ADD_TOAST', payload: { message: 'Video vinculado', type: 'success' } });
        }
    };

    const handleAnimate = async () => {
        if (typeof (window as any).aistudio !== 'undefined' && !hasApiKey) {
            await (window as any).aistudio.openSelectKey();
            dispatch({ type: 'SET_API_KEY_STATUS', payload: true });
        }

        dispatch({type: 'UPDATE_SCENE', payload: {sceneId: scene.id, updates: { isGeneratingVideo: true, videoError: undefined }}});

        try {
            const operation = await generateVideoForScene(scene.parts, aspectRatio);
            const check = async () => {
                const status = await checkVideoStatus(operation);
                if (status.done) {
                    const url = `${status.response?.generatedVideos?.[0]?.video?.uri}&key=${process.env.API_KEY}`;
                    dispatch({type: 'UPDATE_SCENE', payload: {sceneId: scene.id, updates: { videoUrl: url, isGeneratingVideo: false }}});
                    dispatch({ type: 'ADD_TOAST', payload: { message: `Video de Escena ${sceneNumber} listo`, type: 'success' } });
                } else {
                    setTimeout(check, 8000);
                }
            };
            check();
        } catch (err: any) {
            dispatch({type: 'UPDATE_SCENE', payload: {sceneId: scene.id, updates: { isGeneratingVideo: false, videoError: err.message }}});
        }
    };

    useEffect(() => {
        if (musicPlayerRef.current) {
            musicPlayerRef.current.pause();
            musicPlayerRef.current.load();
            setIsPlayingMusic(false);
        }
    }, [scene.backgroundMusicUrl]);

    return (
        <div className="bg-gray-900/40 backdrop-blur-2xl border border-white/5 rounded-[2rem] overflow-hidden shadow-2xl hover:border-sky-500/30 transition-all duration-700 group/card">
            <header className="flex items-center justify-between bg-white/[0.02] p-6 border-b border-white/5">
                <div className="flex items-center gap-4">
                    <div className="p-2.5 bg-sky-500/10 rounded-2xl text-sky-400 group-hover/card:scale-110 transition-transform">
                        <DragHandleIcon className="w-5 h-5 cursor-grab active:cursor-grabbing" />
                    </div>
                    <div>
                        <h3 className="font-black text-lg text-white tracking-tight">ESCENA {sceneNumber}</h3>
                        <p className="text-[10px] text-gray-500 uppercase tracking-[0.2em] font-bold">Bloque de Storyboard</p>
                    </div>
                </div>
                <button onClick={() => dispatch({ type: 'DELETE_SCENE', payload: scene.id })} className="p-2 text-gray-600 hover:text-red-400 hover:bg-red-400/10 rounded-full transition-all">
                    <TrashIcon className="w-5 h-5" />
                </button>
            </header>

            <div className="flex flex-col xl:flex-row">
                {/* Media Section */}
                <div className="xl:w-3/5 aspect-video bg-gray-950 relative group/media overflow-hidden border-r border-white/5">
                    {scene.isGeneratingImage ? (
                        <div className="absolute inset-0 flex items-center justify-center bg-gray-950"><Loader message="Sincronizando estilo..." /></div>
                    ) : scene.imageUrl ? (
                        scene.videoUrl ? (
                            <div className="relative w-full h-full">
                                <video src={scene.videoUrl} controls className="w-full h-full object-cover" />
                                <div className="absolute top-6 left-6 flex gap-2">
                                    <div className="px-4 py-1.5 bg-purple-600/90 backdrop-blur-xl rounded-full text-[10px] font-black text-white uppercase tracking-widest shadow-2xl animate-pulse">Cinemática Lista</div>
                                    <button onClick={() => handleDownload(scene.videoUrl!, `nova-video-${sceneNumber}.mp4`)} className="p-2 bg-black/60 hover:bg-sky-500 rounded-full text-white transition-all shadow-xl" title="Descargar Video">
                                        <DownloadIcon className="w-4 h-4" />
                                    </button>
                                </div>
                            </div>
                        ) : (
                            <div className="relative w-full h-full group/img">
                                <img src={scene.imageUrl} alt="" className="w-full h-full object-cover group-hover/img:scale-105 transition-transform duration-[2s]" />
                                <div className="absolute top-6 left-6 flex gap-2 opacity-0 group-hover/img:opacity-100 transition-opacity duration-500">
                                    <button onClick={() => handleDownload(scene.imageUrl!, `nova-img-${sceneNumber}.png`)} className="p-2 bg-black/60 hover:bg-sky-500 rounded-full text-white transition-all shadow-xl" title="Descargar Imagen">
                                        <DownloadIcon className="w-4 h-4" />
                                    </button>
                                    <button onClick={() => imageUploadRef.current?.click()} className="p-2 bg-black/60 hover:bg-sky-500 rounded-full text-white transition-all shadow-xl" title="Remplazar Imagen">
                                        <UploadIcon className="w-4 h-4" />
                                    </button>
                                    <button onClick={() => handleGenerateImageForScene(scene.id)} className="p-2 bg-sky-600 hover:bg-sky-500 rounded-full text-white transition-all shadow-xl" title="Regenerar con Estilo Global">
                                        <svg xmlns="http://www.w3.org/2000/svg" className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
                                    </button>
                                </div>
                            </div>
                        )
                    ) : (
                        <div className="absolute inset-0 flex flex-col items-center justify-center gap-6 text-gray-700 bg-[radial-gradient(circle_at_center,_#111_0%,_#000_100%)]">
                             <div className="w-16 h-16 rounded-3xl border-2 border-dashed border-gray-800 flex items-center justify-center">
                                <UploadIcon className="w-6 h-6 opacity-20" />
                             </div>
                             <div className="flex flex-col gap-2">
                                <button onClick={() => handleGenerateImageForScene(scene.id)} className="px-6 py-2.5 bg-sky-600 hover:bg-sky-500 rounded-2xl text-xs font-bold text-white transition-all">Generar con Estilo Global</button>
                                <button onClick={() => imageUploadRef.current?.click()} className="px-6 py-2.5 bg-white/5 hover:bg-white/10 rounded-2xl text-xs font-bold text-gray-400 border border-white/5 transition-all">Subir Arte Propio</button>
                             </div>
                        </div>
                    )}
                    <input ref={imageUploadRef} type="file" accept="image/*" className="hidden" onChange={handleImageUpload} />
                    <input ref={videoUploadRef} type="file" accept="video/*" className="hidden" onChange={handleVideoUpload} />
                </div>

                {/* Controls Section */}
                <div className="xl:w-2/5 p-10 flex flex-col justify-between space-y-8 bg-gradient-to-br from-white/[0.01] to-transparent">
                    <div className="space-y-6">
                        <div className="max-h-40 overflow-y-auto pr-4 custom-scrollbar space-y-3">
                            {scene.parts.map((p, i) => (
                                <div key={i} className={`p-3 rounded-2xl border transition-colors ${p.type === 'DIALOGUE' ? 'bg-sky-500/5 border-sky-500/20' : 'bg-white/5 border-transparent'}`}>
                                    {p.speaker && <p className="text-[9px] font-black text-sky-400 uppercase tracking-widest mb-1">{p.speaker}</p>}
                                    <p className={`text-sm leading-relaxed ${p.type === 'DIALOGUE' ? 'text-white font-medium italic' : 'text-gray-400'}`}>
                                        {p.text}
                                    </p>
                                </div>
                            ))}
                        </div>
                    </div>

                    <div className="space-y-4">
                        <div className="grid grid-cols-2 gap-4">
                            {!scene.audioUrl ? (
                                <button 
                                    onClick={() => handleNarrateScene(scene.id)} 
                                    disabled={scene.isGeneratingAudio}
                                    className="flex flex-col items-center justify-center gap-2 py-5 rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest bg-sky-600 hover:bg-sky-500 text-white shadow-xl shadow-sky-600/10 transition-all disabled:opacity-50 group/btn"
                                >
                                    {scene.isGeneratingAudio ? <div className="w-5 h-5 border-2 border-white/20 border-t-white rounded-full animate-spin"></div> : <SpeakerWaveIcon className="w-6 h-6 group-hover/btn:scale-110 transition-transform" />}
                                    Generar Voz
                                </button>
                            ) : (
                                <div className="flex flex-col gap-2">
                                    <button 
                                        onClick={toggleAudioPreview}
                                        className={`flex flex-col items-center justify-center gap-2 py-5 rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest transition-all ${isPlayingAudio ? 'bg-amber-500 text-white shadow-amber-500/20 shadow-xl' : 'bg-green-500/10 text-green-400 border border-green-500/20 hover:bg-green-500/20'}`}
                                    >
                                        {isPlayingAudio ? <PauseIcon className="w-6 h-6 animate-pulse" /> : <PlayIcon className="w-6 h-6" />}
                                        {isPlayingAudio ? 'Reproduciendo' : 'Oír Narración'}
                                        <audio 
                                            ref={audioPlayerRef} 
                                            src={scene.audioUrl} 
                                            onEnded={() => setIsPlayingAudio(false)}
                                            onPause={() => setIsPlayingAudio(false)}
                                            onPlay={() => setIsPlayingAudio(true)}
                                            className="hidden" 
                                        />
                                    </button>
                                    <button onClick={handleResetAudio} className="text-[9px] text-gray-600 hover:text-sky-400 uppercase tracking-[0.2em] font-black transition-colors text-center">Remplazar Voz</button>
                                </div>
                            )}

                            <div className="flex flex-col gap-2">
                                <button 
                                    onClick={handleAnimate}
                                    disabled={scene.isGeneratingVideo || !scene.imageUrl || !!scene.videoUrl}
                                    className={`flex flex-col items-center justify-center gap-2 py-5 rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest transition-all ${scene.videoUrl ? 'bg-purple-500/10 text-purple-400 border border-purple-500/20' : 'bg-purple-600 hover:bg-purple-500 text-white shadow-xl shadow-purple-600/10 disabled:opacity-20'}`}
                                >
                                    {scene.isGeneratingVideo ? <div className="w-5 h-5 border-2 border-white/20 border-t-white rounded-full animate-spin"></div> : <FilmIcon className="w-6 h-6" />}
                                    {scene.videoUrl ? 'Cinemática OK' : 'Animar con IA'}
                                </button>
                                {!scene.videoUrl && scene.imageUrl && (
                                    <button onClick={() => videoUploadRef.current?.click()} className="text-[9px] text-gray-600 hover:text-purple-400 uppercase tracking-[0.2em] font-black transition-colors text-center">Subir Video</button>
                                )}
                            </div>
                        </div>

                        <div className="bg-white/[0.03] p-4 rounded-2xl border border-white/5 space-y-3">
                            <div className="flex items-center justify-between">
                                <div className="flex items-center gap-2 text-gray-500">
                                    <MusicNoteIcon className="w-4 h-4" />
                                    <span className="text-[10px] font-black uppercase tracking-widest">Atmósfera</span>
                                </div>
                                {scene.backgroundMusicUrl && (
                                    <button 
                                        onClick={toggleMusicPreview}
                                        className={`p-1.5 rounded-lg transition-all ${isPlayingMusic ? 'bg-sky-500 text-white shadow-lg' : 'bg-white/5 text-gray-400 hover:bg-white/10'}`}
                                    >
                                        {isPlayingMusic ? <PauseIcon className="w-3.2 h-3.2" /> : <PlayIcon className="w-3.2 h-3.2" />}
                                    </button>
                                )}
                            </div>
                            <select 
                                value={scene.backgroundMusicUrl || ''} 
                                onChange={e => dispatch({ type: 'UPDATE_SCENE_CONFIG', payload: { sceneId: scene.id, config: { backgroundMusicUrl: e.target.value } } })}
                                className="bg-transparent text-xs text-gray-400 focus:text-white outline-none w-full cursor-pointer font-medium"
                            >
                                {PREDEFINED_MUSIC.map(m => <option key={m.name} value={m.url} className="bg-gray-900">{m.name}</option>)}
                            </select>
                            <audio 
                                ref={musicPlayerRef} 
                                src={scene.backgroundMusicUrl} 
                                onEnded={() => setIsPlayingMusic(false)}
                                onPause={() => setIsPlayingMusic(false)}
                                onPlay={() => setIsPlayingMusic(true)}
                                loop
                                className="hidden"
                            />
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

import React, { useRef, useState, useEffect } from 'react';
import type { Scene } from '../types';
import { useProjectState, useProjectDispatch, useProjectActions } from '../context/ProjectContext';
import Loader from './Loader';
import { FilmIcon, SpeakerWaveIcon, ClipboardIcon, TrashIcon, DragHandleIcon, MusicNoteIcon, PlayIcon, PauseIcon, DownloadIcon, UploadIcon } from './Icons';
import { generateVideoForScene, checkVideoStatus } from '../services/gemini';

const PREDEFINED_MUSIC = [
    { name: "Sin música ambiental", url: "" }, 
    { name: "Misterio y Tensión", url: "https://www.soundhelix.com/examples/mp3/SoundHelix-Song-8.mp3" }, 
    { name: "Acción Heroica", url: "https://www.soundhelix.com/examples/mp3/SoundHelix-Song-1.mp3" }, 
    { name: "Atmósfera de Ensueño", url: "https://www.soundhelix.com/examples/mp3/SoundHelix-Song-2.mp3" }
];

interface SceneCardProps {
    scene: Scene;
    sceneNumber: number;
}

export default function SceneCard({ scene, sceneNumber }: SceneCardProps) {
    const dispatch = useProjectDispatch();
    const { hasApiKey, aspectRatio } = useProjectState();
    const { handleNarrateScene, handleGenerateImageForScene } = useProjectActions();

    const [isPlayingAudio, setIsPlayingAudio] = useState(false);
    const [isPlayingMusic, setIsPlayingMusic] = useState(false);

    const audioPlayerRef = useRef<HTMLAudioElement | null>(null);
    const musicPlayerRef = useRef<HTMLAudioElement | null>(null);
    const imageUploadRef = useRef<HTMLInputElement>(null);
    const videoUploadRef = useRef<HTMLInputElement>(null);

    const toggleAudioPreview = () => {
        const player = audioPlayerRef.current;
        if (!player) return;
        if (isPlayingAudio) {
            player.pause();
        } else {
            if (isPlayingMusic && musicPlayerRef.current) musicPlayerRef.current.pause();
            player.play().catch(e => console.error("Error voz:", e));
        }
    };

    const toggleMusicPreview = () => {
        const player = musicPlayerRef.current;
        if (!player || !scene.backgroundMusicUrl) return;

        if (isPlayingMusic) {
            player.pause();
        } else {
            if (isPlayingAudio && audioPlayerRef.current) audioPlayerRef.current.pause();

            player.volume = 0.4;

            // Forzar carga si el estado es inicial
            if (player.readyState === 0) player.load();

            const playPromise = player.play();
            if (playPromise !== undefined) {
                playPromise.catch(error => {
                    console.error("Error al reproducir música:", error);
                    let msg = 'Error de conexión con el servidor de audio';
                    if (error.name === 'NotAllowedError') msg = 'Haz clic en la página para habilitar el sonido';
                    dispatch({ type: 'ADD_TOAST', payload: { message: msg, type: 'error' } });
                    setIsPlayingMusic(false);
                });
            }
        }
    };

    const handleResetAudio = () => {
        dispatch({ type: 'UPDATE_SCENE', payload: { sceneId: scene.id, updates: { audioUrl: undefined } } });
    };

    const handleDownload = (url: string, filename: string) => {
        const link = document.createElement('a');
        link.href = url;
        link.download = filename;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onload = (event) => {
                dispatch({ type: 'UPDATE_SCENE', payload: { sceneId: scene.id, updates: { imageUrl: event.target?.result as string, isGeneratingImage: false } } });
                dispatch({ type: 'ADD_TOAST', payload: { message: 'Imagen subida', type: 'success' } });
            };
            reader.readAsDataURL(file);
        }
    };

    const handleVideoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const videoUrl = URL.createObjectURL(file);
            dispatch({ type: 'UPDATE_SCENE', payload: { sceneId: scene.id, updates: { videoUrl, isGeneratingVideo: false } } });
            dispatch({ type: 'ADD_TOAST', payload: { message: 'Video vinculado', type: 'success' } });
        }
    };

    const handleAnimate = async () => {
        if (typeof (window as any).aistudio !== 'undefined' && !hasApiKey) {
            await (window as any).aistudio.openSelectKey();
            dispatch({ type: 'SET_API_KEY_STATUS', payload: true });
        }

        dispatch({type: 'UPDATE_SCENE', payload: {sceneId: scene.id, updates: { isGeneratingVideo: true, videoError: undefined }}});

        try {
            const operation = await generateVideoForScene(scene.parts, aspectRatio);
            const check = async () => {
                const status = await checkVideoStatus(operation);
                if (status.done) {
                    const url = `${status.response?.generatedVideos?.[0]?.video?.uri}&key=${process.env.API_KEY}`;
                    dispatch({type: 'UPDATE_SCENE', payload: {sceneId: scene.id, updates: { videoUrl: url, isGeneratingVideo: false }}});
                    dispatch({ type: 'ADD_TOAST', payload: { message: `Video de Escena ${sceneNumber} listo`, type: 'success' } });
                } else {
                    setTimeout(check, 8000);
                }
            };
            check();
        } catch (err: any) {
            dispatch({type: 'UPDATE_SCENE', payload: {sceneId: scene.id, updates: { isGeneratingVideo: false, videoError: err.message }}});
        }
    };

    useEffect(() => {
        if (musicPlayerRef.current) {
            musicPlayerRef.current.pause();
            musicPlayerRef.current.load();
            setIsPlayingMusic(false);
        }
    }, [scene.backgroundMusicUrl]);

    return (
        <div className="bg-gray-900/40 backdrop-blur-2xl border border-white/5 rounded-[2rem] overflow-hidden shadow-2xl hover:border-sky-500/30 transition-all duration-700 group/card">
            <header className="flex items-center justify-between bg-white/[0.02] p-6 border-b border-white/5">
                <div className="flex items-center gap-4">
                    <div className="p-2.5 bg-sky-500/10 rounded-2xl text-sky-400 group-hover/card:scale-110 transition-transform">
                        <DragHandleIcon className="w-5 h-5 cursor-grab active:cursor-grabbing" />
                    </div>
                    <div>
                        <h3 className="font-black text-lg text-white tracking-tight">ESCENA {sceneNumber}</h3>
                        <p className="text-[10px] text-gray-500 uppercase tracking-[0.2em] font-bold">Bloque de Storyboard</p>
                    </div>
                </div>
                <button onClick={() => dispatch({ type: 'DELETE_SCENE', payload: scene.id })} className="p-2 text-gray-600 hover:text-red-400 hover:bg-red-400/10 rounded-full transition-all">
                    <TrashIcon className="w-5 h-5" />
                </button>
            </header>

            <div className="flex flex-col xl:flex-row">
                <div className="xl:w-3/5 aspect-video bg-gray-950 relative group/media overflow-hidden border-r border-white/5">
                    {scene.isGeneratingImage ? (
                        <div className="absolute inset-0 flex items-center justify-center bg-gray-950"><Loader message="Sincronizando estilo..." /></div>
                    ) : scene.imageUrl ? (
                        scene.videoUrl ? (
                            <div className="relative w-full h-full">
                                <video src={scene.videoUrl} controls className="w-full h-full object-cover" />
                                <div className="absolute top-6 left-6 flex gap-2">
                                    <div className="px-4 py-1.5 bg-purple-600/90 backdrop-blur-xl rounded-full text-[10px] font-black text-white uppercase tracking-widest shadow-2xl animate-pulse">Cinemática Lista</div>
                                    <button onClick={() => handleDownload(scene.videoUrl!, `nova-video-${sceneNumber}.mp4`)} className="p-2 bg-black/60 hover:bg-sky-500 rounded-full text-white transition-all shadow-xl" title="Descargar Video">
                                        <DownloadIcon className="w-4 h-4" />
                                    </button>
                                </div>
                            </div>
                        ) : (
                            <div className="relative w-full h-full group/img">
                                <img src={scene.imageUrl} alt="" className="w-full h-full object-cover group-hover/img:scale-105 transition-transform duration-[2s]" />
                                <div className="absolute top-6 left-6 flex gap-2 opacity-0 group-hover/img:opacity-100 transition-opacity duration-500">
                                    <button onClick={() => handleDownload(scene.imageUrl!, `nova-img-${sceneNumber}.png`)} className="p-2 bg-black/60 hover:bg-sky-500 rounded-full text-white transition-all shadow-xl" title="Descargar Imagen">
                                        <DownloadIcon className="w-4 h-4" />
                                    </button>
                                    <button onClick={() => imageUploadRef.current?.click()} className="p-2 bg-black/60 hover:bg-sky-500 rounded-full text-white transition-all shadow-xl" title="Remplazar Imagen">
                                        <UploadIcon className="w-4 h-4" />
                                    </button>
                                    <button onClick={() => handleGenerateImageForScene(scene.id)} className="p-2 bg-sky-600 hover:bg-sky-500 rounded-full text-white transition-all shadow-xl" title="Regenerar con Estilo Global">
                                        <svg xmlns="http://www.w3.org/2000/svg" className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
                                    </button>
                                </div>
                            </div>
                        )
                    ) : (
                        <div className="absolute inset-0 flex flex-col items-center justify-center gap-6 text-gray-700 bg-[radial-gradient(circle_at_center,_#111_0%,_#000_100%)]">
                             <div className="w-16 h-16 rounded-3xl border-2 border-dashed border-gray-800 flex items-center justify-center">
                                <UploadIcon className="w-6 h-6 opacity-20" />
                             </div>
                             <div className="flex flex-col gap-2">
                                <button onClick={() => handleGenerateImageForScene(scene.id)} className="px-6 py-2.5 bg-sky-600 hover:bg-sky-500 rounded-2xl text-xs font-bold text-white transition-all">Generar con Estilo Global</button>
                                <button onClick={() => imageUploadRef.current?.click()} className="px-6 py-2.5 bg-white/5 hover:bg-white/10 rounded-2xl text-xs font-bold text-gray-400 border border-white/5 transition-all">Subir Arte Propio</button>
                             </div>
                        </div>
                    )}
                    <input ref={imageUploadRef} type="file" accept="image/*" className="hidden" onChange={handleImageUpload} />
                    <input ref={videoUploadRef} type="file" accept="video/*" className="hidden" onChange={handleVideoUpload} />
                </div>

                <div className="xl:w-2/5 p-10 flex flex-col justify-between space-y-8 bg-gradient-to-br from-white/[0.01] to-transparent">
                    <div className="space-y-6">
                        <div className="max-h-40 overflow-y-auto pr-4 custom-scrollbar space-y-3">
                            {scene.parts.map((p, i) => (
                                <div key={i} className={`p-3 rounded-2xl border transition-colors ${p.type === 'DIALOGUE' ? 'bg-sky-500/5 border-sky-500/20' : 'bg-white/5 border-transparent'}`}>
                                    {p.speaker && <p className="text-[9px] font-black text-sky-400 uppercase tracking-widest mb-1">{p.speaker}</p>}
                                    <p className={`text-sm leading-relaxed ${p.type === 'DIALOGUE' ? 'text-white font-medium italic' : 'text-gray-400'}`}>
                                        {p.text}
                                    </p>
                                </div>
                            ))}
                        </div>
                    </div>

                    <div className="space-y-4">
                        <div className="grid grid-cols-2 gap-4">
                            {!scene.audioUrl ? (
                                <button 
                                    onClick={() => handleNarrateScene(scene.id)} 
                                    disabled={scene.isGeneratingAudio}
                                    className="flex flex-col items-center justify-center gap-2 py-5 rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest bg-sky-600 hover:bg-sky-500 text-white shadow-xl shadow-sky-600/10 transition-all disabled:opacity-50 group/btn"
                                >
                                    {scene.isGeneratingAudio ? <div className="w-5 h-5 border-2 border-white/20 border-t-white rounded-full animate-spin"></div> : <SpeakerWaveIcon className="w-6 h-6 group-hover/btn:scale-110 transition-transform" />}
                                    Generar Voz
                                </button>
                            ) : (
                                <div className="flex flex-col gap-2">
                                    <button 
                                        onClick={toggleAudioPreview}
                                        className={`flex flex-col items-center justify-center gap-2 py-5 rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest transition-all ${isPlayingAudio ? 'bg-amber-500 text-white shadow-amber-500/20 shadow-xl' : 'bg-green-500/10 text-green-400 border border-green-500/20 hover:bg-green-500/20'}`}
                                    >
                                        {isPlayingAudio ? <PauseIcon className="w-6 h-6 animate-pulse" /> : <PlayIcon className="w-6 h-6" />}
                                        {isPlayingAudio ? 'Reproduciendo' : 'Oír Narración'}
                                        <audio 
                                            ref={audioPlayerRef} 
                                            src={scene.audioUrl} 
                                            crossOrigin="anonymous"
                                            onEnded={() => setIsPlayingAudio(false)}
                                            onPause={() => setIsPlayingAudio(false)}
                                            onPlay={() => setIsPlayingAudio(true)}
                                            className="hidden" 
                                        />
                                    </button>
                                    <button onClick={handleResetAudio} className="text-[9px] text-gray-600 hover:text-sky-400 uppercase tracking-[0.2em] font-black transition-colors text-center">Remplazar Voz</button>
                                </div>
                            )}

                            <div className="flex flex-col gap-2">
                                <button 
                                    onClick={handleAnimate}
                                    disabled={scene.isGeneratingVideo || !scene.imageUrl || !!scene.videoUrl}
                                    className={`flex flex-col items-center justify-center gap-2 py-5 rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest transition-all ${scene.videoUrl ? 'bg-purple-500/10 text-purple-400 border border-purple-500/20' : 'bg-purple-600 hover:bg-purple-500 text-white shadow-xl shadow-purple-600/10 disabled:opacity-20'}`}
                                >
                                    {scene.isGeneratingVideo ? <div className="w-5 h-5 border-2 border-white/20 border-t-white rounded-full animate-spin"></div> : <FilmIcon className="w-6 h-6" />}
                                    {scene.videoUrl ? 'Cinemática OK' : 'Animar con IA'}
                                </button>
                                {!scene.videoUrl && scene.imageUrl && (
                                    <button onClick={() => videoUploadRef.current?.click()} className="text-[9px] text-gray-600 hover:text-purple-400 uppercase tracking-[0.2em] font-black transition-colors text-center">Subir Video</button>
                                )}
                            </div>
                        </div>

                        <div className="bg-white/[0.03] p-4 rounded-2xl border border-white/5 space-y-3">
                            <div className="flex items-center justify-between">
                                <div className="flex items-center gap-2 text-gray-500">
                                    <MusicNoteIcon className="w-4 h-4" />
                                    <span className="text-[10px] font-black uppercase tracking-widest">Atmósfera</span>
                                </div>
                                {scene.backgroundMusicUrl && (
                                    <button 
                                        onClick={toggleMusicPreview}
                                        className={`p-1.5 rounded-lg transition-all ${isPlayingMusic ? 'bg-sky-500 text-white shadow-lg' : 'bg-white/5 text-gray-400 hover:bg-white/10'}`}
                                    >
                                        {isPlayingMusic ? <PauseIcon className="w-3.2 h-3.2" /> : <PlayIcon className="w-3.2 h-3.2" />}
                                    </button>
                                )}
                            </div>
                            <select 
                                value={scene.backgroundMusicUrl || ''} 
                                onChange={e => dispatch({ type: 'UPDATE_SCENE_CONFIG', payload: { sceneId: scene.id, config: { backgroundMusicUrl: e.target.value } } })}
                                className="bg-transparent text-xs text-gray-400 focus:text-white outline-none w-full cursor-pointer font-medium"
                            >
                                {PREDEFINED_MUSIC.map(m => <option key={m.name} value={m.url} className="bg-gray-900">{m.name}</option>)}
                            </select>
                            <audio 
                                ref={musicPlayerRef} 
                                src={scene.backgroundMusicUrl} 
                                crossOrigin="anonymous"
                                preload="auto"
                                onEnded={() => setIsPlayingMusic(false)}
                                onPause={() => setIsPlayingMusic(false)}
                                onPlay={() => setIsPlayingMusic(true)}
                                loop
                                className="hidden"
                            />
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { useProjectState, useProjectDispatch } from '../context/ProjectContext';

const DEFAULT_SCENE_DURATION = 6;

export default function MovieModal() {
    const { scenes, isMovieModalOpen } = useProjectState();
    const dispatch = useProjectDispatch();

    const [currentIndex, setCurrentIndex] = useState(0);
    const [isTransitioning, setIsTransitioning] = useState(false);

    const narrationAudioRef = useRef<HTMLAudioElement | null>(null);
    const musicAudioRef = useRef<HTMLAudioElement | null>(null);
    const videoRef = useRef<HTMLVideoElement | null>(null);
    const timeoutRef = useRef<number | null>(null);

    const currentScene = scenes[currentIndex];

    const goToNextScene = useCallback(() => {
        if (currentIndex < scenes.length - 1) {
            setIsTransitioning(true);
            setTimeout(() => {
                setCurrentIndex(prev => prev + 1);
                setIsTransitioning(false);
            }, 600);
        } else {
            handleClose();
        }
    }, [currentIndex, scenes.length]);

    const handleClose = () => {
        if (narrationAudioRef.current) narrationAudioRef.current.pause();
        if (musicAudioRef.current) musicAudioRef.current.pause();
        if (timeoutRef.current) clearTimeout(timeoutRef.current);
        dispatch({ type: 'CLOSE_MOVIE_MODAL' });
        setCurrentIndex(0);
    };

    useEffect(() => {
        if (isMovieModalOpen && !isTransitioning && currentScene) {
            const nar = narrationAudioRef.current;
            const mus = musicAudioRef.current;
            const vid = videoRef.current;

            if (mus) {
                if (currentScene.backgroundMusicUrl && currentScene.backgroundMusicUrl.trim() !== "") {
                    if (mus.src !== currentScene.backgroundMusicUrl) {
                        mus.src = currentScene.backgroundMusicUrl;
                        mus.load();
                    }
                    mus.volume = 0.25;
                    mus.play().catch(e => console.error("Error música película:", e));
                } else {
                    mus.pause();
                    mus.src = "";
                }
            }

            if (nar && currentScene.audioUrl) {
                nar.src = currentScene.audioUrl;
                nar.onended = () => {
                    if (!vid) goToNextScene();
                };
                nar.play().catch(e => console.error("Error voz película:", e));
            }

            if (vid) {
                vid.onended = goToNextScene;
                vid.play().catch(e => console.error("Error video película:", e));
            } else if (!currentScene.audioUrl) {
                timeoutRef.current = window.setTimeout(goToNextScene, DEFAULT_SCENE_DURATION * 1000);
            }
        }
    }, [isMovieModalOpen, currentIndex, currentScene, isTransitioning, goToNextScene]);

    if (!isMovieModalOpen || !currentScene) return null;

    return (
        <div className="fixed inset-0 bg-black z-50 flex items-center justify-center p-4 md:p-12 overflow-hidden">
            <div className={`relative w-full max-w-6xl aspect-video rounded-3xl overflow-hidden shadow-[0_0_100px_rgba(0,0,0,0.8)] transition-all duration-700 transform ${isTransitioning ? 'scale-95 opacity-0 rotate-1' : 'scale-100 opacity-100 rotate-0'}`}>
                {currentScene.videoUrl ? (
                    <video ref={videoRef} src={currentScene.videoUrl} className="w-full h-full object-cover" />
                ) : (
                    <img src={currentScene.imageUrl} className="w-full h-full object-cover" />
                )}

                <div className="absolute inset-x-0 bottom-0 bg-gradient-to-t from-black/90 via-black/40 to-transparent p-12 pt-24 pointer-events-none">
                    <div className="max-w-3xl mx-auto text-center space-y-4">
                        {currentScene.parts.filter(p => p.type !== 'INSTRUCTION').map((p, i) => (
                            <p key={i} className={`text-lg md:text-2xl font-medium tracking-tight drop-shadow-lg ${p.type === 'DIALOGUE' ? 'text-sky-300 italic' : 'text-white'}`}>
                                {p.speaker && <span className="font-black uppercase text-xs tracking-widest block mb-1 opacity-70">{p.speaker}</span>}
                                "{p.text}"
                            </p>
                        ))}
                    </div>
                </div>

                <div className="absolute top-0 left-0 right-0 h-1 bg-white/10">
                    <div 
                        className="h-full bg-sky-500 transition-all duration-500" 
                        style={{ width: `${((currentIndex + 1) / scenes.length) * 100}%` }}
                    />
                </div>
            </div>

            <button onClick={handleClose} className="absolute top-8 right-8 w-12 h-12 flex items-center justify-center rounded-full bg-white/10 hover:bg-white/20 text-white transition-all backdrop-blur-md">
                <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>

            <audio ref={narrationAudioRef} crossOrigin="anonymous" />
            <audio ref={musicAudioRef} crossOrigin="anonymous" preload="auto" loop />
        </div>
    );
};

import React, { useRef, useState, useEffect } from 'react';
import type { Scene } from '../types';
import { useProjectState, useProjectDispatch, useProjectActions } from '../context/ProjectContext';
import Loader from './Loader';
import { FilmIcon, SpeakerWaveIcon, ClipboardIcon, TrashIcon, DragHandleIcon, MusicNoteIcon, PlayIcon, PauseIcon, DownloadIcon, UploadIcon } from './Icons';
import { generateVideoForScene, checkVideoStatus } from '../services/gemini';

const PREDEFINED_MUSIC = [
    { name: "Sin música ambiental", url: "" }, 
    { name: "Misterio y Tensión", url: "https://www.soundhelix.com/examples/mp3/SoundHelix-Song-8.mp3" }, 
    { name: "Acción Heroica", url: "https://www.soundhelix.com/examples/mp3/SoundHelix-Song-1.mp3" }, 
    { name: "Atmósfera de Ensueño", url: "https://www.soundhelix.com/examples/mp3/SoundHelix-Song-2.mp3" }
];

interface SceneCardProps {
    scene: Scene;
    sceneNumber: number;
}

export default function SceneCard({ scene, sceneNumber }: SceneCardProps) {
    const dispatch = useProjectDispatch();
    const { hasApiKey, aspectRatio } = useProjectState();
    const { handleNarrateScene, handleGenerateImageForScene } = useProjectActions();

    const [isPlayingAudio, setIsPlayingAudio] = useState(false);
    const [isPlayingMusic, setIsPlayingMusic] = useState(false);
    const [customMusicName, setCustomMusicName] = useState<string | null>(null);

    const audioPlayerRef = useRef<HTMLAudioElement | null>(null);
    const musicPlayerRef = useRef<HTMLAudioElement | null>(null);
    const imageUploadRef = useRef<HTMLInputElement>(null);
    const videoUploadRef = useRef<HTMLInputElement>(null);
    const musicUploadRef = useRef<HTMLInputElement>(null);

    const toggleAudioPreview = () => {
        const player = audioPlayerRef.current;
        if (!player) return;
        if (isPlayingAudio) {
            player.pause();
        } else {
            if (isPlayingMusic && musicPlayerRef.current) musicPlayerRef.current.pause();
            player.play().catch(e => console.error("Error voz:", e));
        }
    };

    const toggleMusicPreview = () => {
        const player = musicPlayerRef.current;
        if (!player || !scene.backgroundMusicUrl) return;

        if (isPlayingMusic) {
            player.pause();
        } else {
            if (isPlayingAudio && audioPlayerRef.current) audioPlayerRef.current.pause();

            player.volume = 0.4;

            if (player.readyState === 0) player.load();

            const playPromise = player.play();
            if (playPromise !== undefined) {
                playPromise.catch(error => {
                    console.error("Error al reproducir música:", error);
                    let msg = 'Error de conexión con el servidor de audio';
                    if (error.name === 'NotAllowedError') msg = 'Haz clic en la página para habilitar el sonido';
                    dispatch({ type: 'ADD_TOAST', payload: { message: msg, type: 'error' } });
                    setIsPlayingMusic(false);
                });
            }
        }
    };

    const handleResetAudio = () => {
        dispatch({ type: 'UPDATE_SCENE', payload: { sceneId: scene.id, updates: { audioUrl: undefined } } });
    };

    const handleDownload = (url: string, filename: string) => {
        const link = document.createElement('a');
        link.href = url;
        link.download = filename;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onload = (event) => {
                dispatch({ type: 'UPDATE_SCENE', payload: { sceneId: scene.id, updates: { imageUrl: event.target?.result as string, isGeneratingImage: false } } });
                dispatch({ type: 'ADD_TOAST', payload: { message: 'Imagen subida', type: 'success' } });
            };
            reader.readAsDataURL(file);
        }
    };

    const handleVideoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const videoUrl = URL.createObjectURL(file);
            dispatch({ type: 'UPDATE_SCENE', payload: { sceneId: scene.id, updates: { videoUrl, isGeneratingVideo: false } } });
            dispatch({ type: 'ADD_TOAST', payload: { message: 'Video vinculado', type: 'success' } });
        }
    };

    const handleMusicUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const musicUrl = URL.createObjectURL(file);
            setCustomMusicName(file.name);
            dispatch({ type: 'UPDATE_SCENE_CONFIG', payload: { sceneId: scene.id, config: { backgroundMusicUrl: musicUrl } } });
            dispatch({ type: 'ADD_TOAST', payload: { message: 'Música personalizada cargada', type: 'success' } });
        }
    };

    const handleAnimate = async () => {
        if (typeof (window as any).aistudio !== 'undefined' && !hasApiKey) {
            await (window as any).aistudio.openSelectKey();
            dispatch({ type: 'SET_API_KEY_STATUS', payload: true });
        }

        dispatch({type: 'UPDATE_SCENE', payload: {sceneId: scene.id, updates: { isGeneratingVideo: true, videoError: undefined }}});

        try {
            const operation = await generateVideoForScene(scene.parts, aspectRatio);
            const check = async () => {
                const status = await checkVideoStatus(operation);
                if (status.done) {
                    const url = `${status.response?.generatedVideos?.[0]?.video?.uri}&key=${process.env.API_KEY}`;
                    dispatch({type: 'UPDATE_SCENE', payload: {sceneId: scene.id, updates: { videoUrl: url, isGeneratingVideo: false }}});
                    dispatch({ type: 'ADD_TOAST', payload: { message: `Video de Escena ${sceneNumber} listo`, type: 'success' } });
                } else {
                    setTimeout(check, 8000);
                }
            };
            check();
        } catch (err: any) {
            dispatch({type: 'UPDATE_SCENE', payload: {sceneId: scene.id, updates: { isGeneratingVideo: false, videoError: err.message }}});
        }
    };

    useEffect(() => {
        if (musicPlayerRef.current) {
            musicPlayerRef.current.pause();
            musicPlayerRef.current.load();
            setIsPlayingMusic(false);
        }
    }, [scene.backgroundMusicUrl]);

    return (
        <div className="bg-gray-900/40 backdrop-blur-2xl border border-white/5 rounded-[2rem] overflow-hidden shadow-2xl hover:border-sky-500/30 transition-all duration-700 group/card">
            <header className="flex items-center justify-between bg-white/[0.02] p-6 border-b border-white/5">
                <div className="flex items-center gap-4">
                    <div className="p-2.5 bg-sky-500/10 rounded-2xl text-sky-400 group-hover/card:scale-110 transition-transform">
                        <DragHandleIcon className="w-5 h-5 cursor-grab active:cursor-grabbing" />
                    </div>
                    <div>
                        <h3 className="font-black text-lg text-white tracking-tight">ESCENA {sceneNumber}</h3>
                        <p className="text-[10px] text-gray-500 uppercase tracking-[0.2em] font-bold">Bloque de Storyboard</p>
                    </div>
                </div>
                <button onClick={() => dispatch({ type: 'DELETE_SCENE', payload: scene.id })} className="p-2 text-gray-600 hover:text-red-400 hover:bg-red-400/10 rounded-full transition-all">
                    <TrashIcon className="w-5 h-5" />
                </button>
            </header>

            <div className="flex flex-col xl:flex-row">
                <div className="xl:w-3/5 aspect-video bg-gray-950 relative group/media overflow-hidden border-r border-white/5">
                    {scene.isGeneratingImage ? (
                        <div className="absolute inset-0 flex items-center justify-center bg-gray-950"><Loader message="Sincronizando estilo..." /></div>
                    ) : scene.imageUrl ? (
                        scene.videoUrl ? (
                            <div className="relative w-full h-full">
                                <video src={scene.videoUrl} controls className="w-full h-full object-cover" />
                                <div className="absolute top-6 left-6 flex gap-2">
                                    <div className="px-4 py-1.5 bg-purple-600/90 backdrop-blur-xl rounded-full text-[10px] font-black text-white uppercase tracking-widest shadow-2xl animate-pulse">Cinemática Lista</div>
                                    <button onClick={() => handleDownload(scene.videoUrl!, `nova-video-${sceneNumber}.mp4`)} className="p-2 bg-black/60 hover:bg-sky-500 rounded-full text-white transition-all shadow-xl" title="Descargar Video">
                                        <DownloadIcon className="w-4 h-4" />
                                    </button>
                                </div>
                            </div>
                        ) : (
                            <div className="relative w-full h-full group/img">
                                <img src={scene.imageUrl} alt="" className="w-full h-full object-cover group-hover/img:scale-105 transition-transform duration-[2s]" />
                                <div className="absolute top-6 left-6 flex gap-2 opacity-0 group-hover/img:opacity-100 transition-opacity duration-500">
                                    <button onClick={() => handleDownload(scene.imageUrl!, `nova-img-${sceneNumber}.png`)} className="p-2 bg-black/60 hover:bg-sky-500 rounded-full text-white transition-all shadow-xl" title="Descargar Imagen">
                                        <DownloadIcon className="w-4 h-4" />
                                    </button>
                                    <button onClick={() => imageUploadRef.current?.click()} className="p-2 bg-black/60 hover:bg-sky-500 rounded-full text-white transition-all shadow-xl" title="Remplazar Imagen">
                                        <UploadIcon className="w-4 h-4" />
                                    </button>
                                    <button onClick={() => handleGenerateImageForScene(scene.id)} className="p-2 bg-sky-600 hover:bg-sky-500 rounded-full text-white transition-all shadow-xl" title="Regenerar con Estilo Global">
                                        <svg xmlns="http://www.w3.org/2000/svg" className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
                                    </button>
                                </div>
                            </div>
                        )
                    ) : (
                        <div className="absolute inset-0 flex flex-col items-center justify-center gap-6 text-gray-700 bg-[radial-gradient(circle_at_center,_#111_0%,_#000_100%)]">
                             <div className="w-16 h-16 rounded-3xl border-2 border-dashed border-gray-800 flex items-center justify-center">
                                <UploadIcon className="w-6 h-6 opacity-20" />
                             </div>
                             <div className="flex flex-col gap-2">
                                <button onClick={() => handleGenerateImageForScene(scene.id)} className="px-6 py-2.5 bg-sky-600 hover:bg-sky-500 rounded-2xl text-xs font-bold text-white transition-all">Generar con Estilo Global</button>
                                <button onClick={() => imageUploadRef.current?.click()} className="px-6 py-2.5 bg-white/5 hover:bg-white/10 rounded-2xl text-xs font-bold text-gray-400 border border-white/5 transition-all">Subir Arte Propio</button>
                             </div>
                        </div>
                    )}
                    <input ref={imageUploadRef} type="file" accept="image/*" className="hidden" onChange={handleImageUpload} />
                    <input ref={videoUploadRef} type="file" accept="video/*" className="hidden" onChange={handleVideoUpload} />
                </div>

                <div className="xl:w-2/5 p-10 flex flex-col justify-between space-y-8 bg-gradient-to-br from-white/[0.01] to-transparent">
                    <div className="space-y-6">
                        <div className="max-h-40 overflow-y-auto pr-4 custom-scrollbar space-y-3">
                            {scene.parts.map((p, i) => (
                                <div key={i} className={`p-3 rounded-2xl border transition-colors ${p.type === 'DIALOGUE' ? 'bg-sky-500/5 border-sky-500/20' : 'bg-white/5 border-transparent'}`}>
                                    {p.speaker && <p className="text-[9px] font-black text-sky-400 uppercase tracking-widest mb-1">{p.speaker}</p>}
                                    <p className={`text-sm leading-relaxed ${p.type === 'DIALOGUE' ? 'text-white font-medium italic' : 'text-gray-400'}`}>
                                        {p.text}
                                    </p>
                                </div>
                            ))}
                        </div>
                    </div>

                    <div className="space-y-4">
                        <div className="grid grid-cols-2 gap-4">
                            {!scene.audioUrl ? (
                                <button 
                                    onClick={() => handleNarrateScene(scene.id)} 
                                    disabled={scene.isGeneratingAudio}
                                    className="flex flex-col items-center justify-center gap-2 py-5 rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest bg-sky-600 hover:bg-sky-500 text-white shadow-xl shadow-sky-600/10 transition-all disabled:opacity-50 group/btn"
                                >
                                    {scene.isGeneratingAudio ? <div className="w-5 h-5 border-2 border-white/20 border-t-white rounded-full animate-spin"></div> : <SpeakerWaveIcon className="w-6 h-6 group-hover/btn:scale-110 transition-transform" />}
                                    Generar Voz
                                </button>
                            ) : (
                                <div className="flex flex-col gap-2">
                                    <button 
                                        onClick={toggleAudioPreview}
                                        className={`flex flex-col items-center justify-center gap-2 py-5 rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest transition-all ${isPlayingAudio ? 'bg-amber-500 text-white shadow-amber-500/20 shadow-xl' : 'bg-green-500/10 text-green-400 border border-green-500/20 hover:bg-green-500/20'}`}
                                    >
                                        {isPlayingAudio ? <PauseIcon className="w-6 h-6 animate-pulse" /> : <PlayIcon className="w-6 h-6" />}
                                        {isPlayingAudio ? 'Reproduciendo' : 'Oír Narración'}
                                        <audio 
                                            ref={audioPlayerRef} 
                                            src={scene.audioUrl} 
                                            crossOrigin="anonymous"
                                            onEnded={() => setIsPlayingAudio(false)}
                                            onPause={() => setIsPlayingAudio(false)}
                                            onPlay={() => setIsPlayingAudio(true)}
                                            className="hidden" 
                                        />
                                    </button>
                                    <button onClick={handleResetAudio} className="text-[9px] text-gray-600 hover:text-sky-400 uppercase tracking-[0.2em] font-black transition-colors text-center">Remplazar Voz</button>
                                </div>
                            )}

                            <div className="flex flex-col gap-2">
                                <button 
                                    onClick={handleAnimate}
                                    disabled={scene.isGeneratingVideo || !scene.imageUrl || !!scene.videoUrl}
                                    className={`flex flex-col items-center justify-center gap-2 py-5 rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest transition-all ${scene.videoUrl ? 'bg-purple-500/10 text-purple-400 border border-purple-500/20' : 'bg-purple-600 hover:bg-purple-500 text-white shadow-xl shadow-purple-600/10 disabled:opacity-20'}`}
                                >
                                    {scene.isGeneratingVideo ? <div className="w-5 h-5 border-2 border-white/20 border-t-white rounded-full animate-spin"></div> : <FilmIcon className="w-6 h-6" />}
                                    {scene.videoUrl ? 'Cinemática OK' : 'Animar con IA'}
                                </button>
                                {!scene.videoUrl && scene.imageUrl && (
                                    <button onClick={() => videoUploadRef.current?.click()} className="text-[9px] text-gray-600 hover:text-purple-400 uppercase tracking-[0.2em] font-black transition-colors text-center">Subir Video</button>
                                )}
                            </div>
                        </div>

                        <div className="bg-white/[0.03] p-4 rounded-2xl border border-white/5 space-y-3">
                            <div className="flex items-center justify-between">
                                <div className="flex items-center gap-2 text-gray-500">
                                    <MusicNoteIcon className="w-4 h-4" />
                                    <span className="text-[10px] font-black uppercase tracking-widest">Atmósfera</span>
                                </div>
                                <div className="flex items-center gap-2">
                                    {scene.backgroundMusicUrl && (
                                        <button 
                                            onClick={toggleMusicPreview}
                                            className={`p-1.5 rounded-lg transition-all ${isPlayingMusic ? 'bg-sky-500 text-white shadow-lg' : 'bg-white/5 text-gray-400 hover:bg-white/10'}`}
                                        >
                                            {isPlayingMusic ? <PauseIcon className="w-3.2 h-3.2" /> : <PlayIcon className="w-3.2 h-3.2" />}
                                        </button>
                                    )}
                                    <button 
                                        onClick={() => musicUploadRef.current?.click()} 
                                        className="p-1.5 bg-white/5 text-gray-400 hover:bg-sky-500/20 hover:text-sky-400 rounded-lg transition-all"
                                        title="Subir música propia (MP3/WAV)"
                                    >
                                        <UploadIcon className="w-3.2 h-3.2" />
                                    </button>
                                </div>
                            </div>

                            <select 
                                value={PREDEFINED_MUSIC.some(m => m.url === scene.backgroundMusicUrl) ? scene.backgroundMusicUrl : (customMusicName ? "custom" : "")} 
                                onChange={e => {
                                    if (e.target.value === "custom") return;
                                    setCustomMusicName(null);
                                    dispatch({ type: 'UPDATE_SCENE_CONFIG', payload: { sceneId: scene.id, config: { backgroundMusicUrl: e.target.value } } });
                                }}
                                className="bg-transparent text-xs text-gray-400 focus:text-white outline-none w-full cursor-pointer font-medium"
                            >
                                {PREDEFINED_MUSIC.map(m => <option key={m.name} value={m.url} className="bg-gray-900">{m.name}</option>)}
                                {customMusicName && <option value="custom" className="bg-gray-900">Personalizada: {customMusicName}</option>}
                            </select>

                            <input 
                                ref={musicUploadRef} 
                                type="file" 
                                accept="audio/*" 
                                className="hidden" 
                                onChange={handleMusicUpload} 
                            />

                            <audio 
                                ref={musicPlayerRef} 
                                src={scene.backgroundMusicUrl} 
                                crossOrigin="anonymous"
                                preload="auto"
                                onEnded={() => setIsPlayingMusic(false)}
                                onPause={() => setIsPlayingMusic(false)}
                                onPlay={() => setIsPlayingMusic(true)}
                                loop
                                className="hidden"
                            />
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

import React, { useRef, useState, useEffect } from 'react';
import type { Scene } from '../types';
import { useProjectState, useProjectDispatch, useProjectActions } from '../context/ProjectContext';
import Loader from './Loader';
import { FilmIcon, SpeakerWaveIcon, TrashIcon, DragHandleIcon, MusicNoteIcon, PlayIcon, PauseIcon, DownloadIcon, UploadIcon, VolumeUpIcon } from './Icons';
import { generateVideoForScene, checkVideoStatus } from '../services/gemini';

const PREDEFINED_MUSIC = [
    { name: "Sin música ambiental", url: "" }, 
    { name: "Misterio y Tensión", url: "https://www.soundhelix.com/examples/mp3/SoundHelix-Song-8.mp3" }, 
    { name: "Acción Heroica", url: "https://www.soundhelix.com/examples/mp3/SoundHelix-Song-1.mp3" }, 
    { name: "Atmósfera de Ensueño", url: "https://www.soundhelix.com/examples/mp3/SoundHelix-Song-2.mp3" },
    { name: "Suspenso Noir", url: "https://www.soundhelix.com/examples/mp3/SoundHelix-Song-3.mp3" }
];

interface SceneCardProps {
    scene: Scene;
    sceneNumber: number;
}

export default function SceneCard({ scene, sceneNumber }: SceneCardProps) {
    const dispatch = useProjectDispatch();
    const { hasApiKey, aspectRatio } = useProjectState();
    const { handleNarrateScene, handleGenerateImageForScene } = useProjectActions();

    const [isPlayingAudio, setIsPlayingAudio] = useState(false);
    const [isPlayingMusic, setIsPlayingMusic] = useState(false);
    const [customMusicName, setCustomMusicName] = useState<string | null>(null);

    const audioPlayerRef = useRef<HTMLAudioElement | null>(null);
    const musicPlayerRef = useRef<HTMLAudioElement | null>(null);
    const imageUploadRef = useRef<HTMLInputElement>(null);
    const videoUploadRef = useRef<HTMLInputElement>(null);
    const musicUploadRef = useRef<HTMLInputElement>(null);

    // Sincronizar volumen del reproductor con el estado
    useEffect(() => {
        if (musicPlayerRef.current) {
            musicPlayerRef.current.volume = (scene.musicVolume ?? 40) / 100;
        }
    }, [scene.musicVolume]);

    const toggleAudioPreview = () => {
        const player = audioPlayerRef.current;
        if (!player) return;
        if (isPlayingAudio) {
            player.pause();
        } else {
            if (isPlayingMusic && musicPlayerRef.current) musicPlayerRef.current.pause();
            player.play().catch(e => console.error("Error voz:", e));
        }
    };

    const toggleMusicPreview = () => {
        const player = musicPlayerRef.current;
        if (!player || !scene.backgroundMusicUrl) return;

        if (isPlayingMusic) {
            player.pause();
        } else {
            if (isPlayingAudio && audioPlayerRef.current) audioPlayerRef.current.pause();

            // Asegurar volumen antes de reproducir
            player.volume = (scene.musicVolume ?? 40) / 100;

            const playPromise = player.play();
            if (playPromise !== undefined) {
                playPromise.catch(error => {
                    console.error("Error al reproducir música:", error);
                    let msg = 'Error de conexión con el servidor de audio. Prueba subiendo tu propio archivo.';
                    if (error.name === 'NotAllowedError') msg = 'Haz clic en la página para habilitar el sonido';
                    dispatch({ type: 'ADD_TOAST', payload: { message: msg, type: 'error' } });
                    setIsPlayingMusic(false);
                });
            }
        }
    };

    const handleVolumeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const volume = parseInt(e.target.value);
        dispatch({ type: 'UPDATE_SCENE_CONFIG', payload: { sceneId: scene.id, config: { musicVolume: volume } } });
    };

    const handleMusicUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const musicUrl = URL.createObjectURL(file);
            setCustomMusicName(file.name);
            dispatch({ type: 'UPDATE_SCENE_CONFIG', payload: { sceneId: scene.id, config: { backgroundMusicUrl: musicUrl } } });
            dispatch({ type: 'ADD_TOAST', payload: { message: `"${file.name}" cargada correctamente`, type: 'success' } });
        }
    };

    const handleAnimate = async () => {
        if (typeof (window as any).aistudio !== 'undefined' && !hasApiKey) {
            await (window as any).aistudio.openSelectKey();
            dispatch({ type: 'SET_API_KEY_STATUS', payload: true });
        }
        dispatch({type: 'UPDATE_SCENE', payload: {sceneId: scene.id, updates: { isGeneratingVideo: true, videoError: undefined }}});
        try {
            const operation = await generateVideoForScene(scene.parts, aspectRatio);
            const check = async () => {
                const status = await checkVideoStatus(operation);
                if (status.done) {
                    const url = `${status.response?.generatedVideos?.[0]?.video?.uri}&key=${process.env.API_KEY}`;
                    dispatch({type: 'UPDATE_SCENE', payload: {sceneId: scene.id, updates: { videoUrl: url, isGeneratingVideo: false }}});
                    dispatch({ type: 'ADD_TOAST', payload: { message: `Video listo`, type: 'success' } });
                } else {
                    setTimeout(check, 8000);
                }
            };
            check();
        } catch (err: any) {
            dispatch({type: 'UPDATE_SCENE', payload: {sceneId: scene.id, updates: { isGeneratingVideo: false, videoError: err.message }}});
        }
    };

    return (
        <div className="bg-gray-900/40 backdrop-blur-2xl border border-white/5 rounded-[2rem] overflow-hidden shadow-2xl hover:border-sky-500/30 transition-all duration-700 group/card">
            <header className="flex items-center justify-between bg-white/[0.02] p-6 border-b border-white/5">
                <div className="flex items-center gap-4">
                    <div className="p-2.5 bg-sky-500/10 rounded-2xl text-sky-400 group-hover/card:scale-110 transition-transform">
                        <DragHandleIcon className="w-5 h-5 cursor-grab active:cursor-grabbing" />
                    </div>
                    <div>
                        <h3 className="font-black text-lg text-white tracking-tight">ESCENA {sceneNumber}</h3>
                        <p className="text-[10px] text-gray-500 uppercase tracking-[0.2em] font-bold">Bloque de Storyboard</p>
                    </div>
                </div>
                <button onClick={() => dispatch({ type: 'DELETE_SCENE', payload: scene.id })} className="p-2 text-gray-600 hover:text-red-400 hover:bg-red-400/10 rounded-full transition-all">
                    <TrashIcon className="w-5 h-5" />
                </button>
            </header>

            <div className="flex flex-col xl:flex-row">
                <div className="xl:w-3/5 aspect-video bg-gray-950 relative group/media overflow-hidden border-r border-white/5">
                    {scene.isGeneratingImage ? (
                        <div className="absolute inset-0 flex items-center justify-center bg-gray-950"><Loader message="Sincronizando estilo..." /></div>
                    ) : scene.imageUrl ? (
                        scene.videoUrl ? (
                            <div className="relative w-full h-full">
                                <video src={scene.videoUrl} controls className="w-full h-full object-cover" />
                                <div className="absolute top-6 left-6 flex gap-2">
                                    <div className="px-4 py-1.5 bg-purple-600/90 backdrop-blur-xl rounded-full text-[10px] font-black text-white uppercase tracking-widest shadow-2xl animate-pulse">Cinemática Lista</div>
                                    <button onClick={() => {
                                        const link = document.createElement('a');
                                        link.href = scene.videoUrl!;
                                        link.download = `nova-video-${sceneNumber}.mp4`;
                                        link.click();
                                    }} className="p-2 bg-black/60 hover:bg-sky-500 rounded-full text-white transition-all shadow-xl">
                                        <DownloadIcon className="w-4 h-4" />
                                    </button>
                                </div>
                            </div>
                        ) : (
                            <div className="relative w-full h-full group/img">
                                <img src={scene.imageUrl} alt="" className="w-full h-full object-cover group-hover/img:scale-105 transition-transform duration-[2s]" />
                                <div className="absolute top-6 left-6 flex gap-2 opacity-0 group-hover/img:opacity-100 transition-opacity duration-500">
                                    <button onClick={() => {
                                        const link = document.createElement('a');
                                        link.href = scene.imageUrl!;
                                        link.download = `nova-img-${sceneNumber}.png`;
                                        link.click();
                                    }} className="p-2 bg-black/60 hover:bg-sky-500 rounded-full text-white transition-all shadow-xl">
                                        <DownloadIcon className="w-4 h-4" />
                                    </button>
                                    <button onClick={() => imageUploadRef.current?.click()} className="p-2 bg-black/60 hover:bg-sky-500 rounded-full text-white transition-all shadow-xl">
                                        <UploadIcon className="w-4 h-4" />
                                    </button>
                                    <button onClick={() => handleGenerateImageForScene(scene.id)} className="p-2 bg-sky-600 hover:bg-sky-500 rounded-full text-white transition-all shadow-xl">
                                        <svg xmlns="http://www.w3.org/2000/svg" className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
                                    </button>
                                </div>
                            </div>
                        )
                    ) : (
                        <div className="absolute inset-0 flex flex-col items-center justify-center gap-6 text-gray-700 bg-[radial-gradient(circle_at_center,_#111_0%,_#000_100%)]">
                             <div className="w-16 h-16 rounded-3xl border-2 border-dashed border-gray-800 flex items-center justify-center">
                                <UploadIcon className="w-6 h-6 opacity-20" />
                             </div>
                             <div className="flex flex-col gap-2">
                                <button onClick={() => handleGenerateImageForScene(scene.id)} className="px-6 py-2.5 bg-sky-600 hover:bg-sky-500 rounded-2xl text-xs font-bold text-white transition-all">Generar con Estilo Global</button>
                                <button onClick={() => imageUploadRef.current?.click()} className="px-6 py-2.5 bg-white/5 hover:bg-white/10 rounded-2xl text-xs font-bold text-gray-400 border border-white/5 transition-all">Subir Arte Propio</button>
                             </div>
                        </div>
                    )}
                    <input ref={imageUploadRef} type="file" accept="image/*" className="hidden" onChange={handleImageUpload} />
                    <input ref={videoUploadRef} type="file" accept="video/*" className="hidden" onChange={handleVideoUpload} />
                </div>

                <div className="xl:w-2/5 p-10 flex flex-col justify-between space-y-8 bg-gradient-to-br from-white/[0.01] to-transparent">
                    <div className="space-y-6">
                        <div className="max-h-40 overflow-y-auto pr-4 custom-scrollbar space-y-3">
                            {scene.parts.map((p, i) => (
                                <div key={i} className={`p-3 rounded-2xl border transition-colors ${p.type === 'DIALOGUE' ? 'bg-sky-500/5 border-sky-500/20' : 'bg-white/5 border-transparent'}`}>
                                    {p.speaker && <p className="text-[9px] font-black text-sky-400 uppercase tracking-widest mb-1">{p.speaker}</p>}
                                    <p className={`text-sm leading-relaxed ${p.type === 'DIALOGUE' ? 'text-white font-medium italic' : 'text-gray-400'}`}>
                                        {p.text}
                                    </p>
                                </div>
                            ))}
                        </div>
                    </div>

                    <div className="space-y-4">
                        <div className="grid grid-cols-2 gap-4">
                            {!scene.audioUrl ? (
                                <button 
                                    onClick={() => handleNarrateScene(scene.id)} 
                                    disabled={scene.isGeneratingAudio}
                                    className="flex flex-col items-center justify-center gap-2 py-5 rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest bg-sky-600 hover:bg-sky-500 text-white shadow-xl shadow-sky-600/10 transition-all disabled:opacity-50 group/btn"
                                >
                                    {scene.isGeneratingAudio ? <div className="w-5 h-5 border-2 border-white/20 border-t-white rounded-full animate-spin"></div> : <SpeakerWaveIcon className="w-6 h-6 group-hover/btn:scale-110 transition-transform" />}
                                    Generar Voz
                                </button>
                            ) : (
                                <div className="flex flex-col gap-2">
                                    <button 
                                        onClick={toggleAudioPreview}
                                        className={`flex flex-col items-center justify-center gap-2 py-5 rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest transition-all ${isPlayingAudio ? 'bg-amber-500 text-white shadow-amber-500/20 shadow-xl' : 'bg-green-500/10 text-green-400 border border-green-500/20 hover:bg-green-500/20'}`}
                                    >
                                        {isPlayingAudio ? <PauseIcon className="w-6 h-6 animate-pulse" /> : <PlayIcon className="w-6 h-6" />}
                                        {isPlayingAudio ? 'Reproduciendo' : 'Oír Narración'}
                                        <audio 
                                            ref={audioPlayerRef} 
                                            src={scene.audioUrl} 
                                            crossOrigin="anonymous"
                                            onEnded={() => setIsPlayingAudio(false)}
                                            onPause={() => setIsPlayingAudio(false)}
                                            onPlay={() => setIsPlayingAudio(true)}
                                            className="hidden" 
                                        />
                                    </button>
                                    <button onClick={() => dispatch({ type: 'UPDATE_SCENE', payload: { sceneId: scene.id, updates: { audioUrl: undefined } } })} className="text-[9px] text-gray-600 hover:text-sky-400 uppercase tracking-[0.2em] font-black transition-colors text-center">Remplazar Voz</button>
                                </div>
                            )}

                            <div className="flex flex-col gap-2">
                                <button 
                                    onClick={handleAnimate}
                                    disabled={scene.isGeneratingVideo || !scene.imageUrl || !!scene.videoUrl}
                                    className={`flex flex-col items-center justify-center gap-2 py-5 rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest transition-all ${scene.videoUrl ? 'bg-purple-500/10 text-purple-400 border border-purple-500/20' : 'bg-purple-600 hover:bg-purple-500 text-white shadow-xl shadow-purple-600/10 disabled:opacity-20'}`}
                                >
                                    {scene.isGeneratingVideo ? <div className="w-5 h-5 border-2 border-white/20 border-t-white rounded-full animate-spin"></div> : <FilmIcon className="w-6 h-6" />}
                                    {scene.videoUrl ? 'Cinemática OK' : 'Animar con IA'}
                                </button>
                                {!scene.videoUrl && scene.imageUrl && (
                                    <button onClick={() => videoUploadRef.current?.click()} className="text-[9px] text-gray-600 hover:text-purple-400 uppercase tracking-[0.2em] font-black transition-colors text-center">Subir Video</button>
                                )}
                            </div>
                        </div>

                        <div className="bg-white/[0.03] p-6 rounded-2xl border border-white/5 space-y-4">
                            <div className="flex items-center justify-between">
                                <div className="flex items-center gap-2 text-gray-400">
                                    <MusicNoteIcon className="w-4 h-4" />
                                    <span className="text-[10px] font-black uppercase tracking-widest">Música Ambiental</span>
                                </div>
                                <div className="flex items-center gap-2">
                                    {scene.backgroundMusicUrl && (
                                        <button 
                                            onClick={toggleMusicPreview}
                                            className={`p-2 rounded-xl transition-all ${isPlayingMusic ? 'bg-sky-500 text-white shadow-lg' : 'bg-white/5 text-gray-400 hover:bg-white/10'}`}
                                        >
                                            {isPlayingMusic ? <PauseIcon className="w-4 h-4" /> : <PlayIcon className="w-4 h-4" />}
                                        </button>
                                    )}
                                    <button 
                                        onClick={() => musicUploadRef.current?.click()} 
                                        className="p-2 bg-white/5 text-gray-400 hover:bg-sky-500/20 hover:text-sky-400 rounded-xl transition-all"
                                        title="Subir MP3/WAV propio"
                                    >
                                        <UploadIcon className="w-4 h-4" />
                                    </button>
                                </div>
                            </div>

                            <select 
                                value={PREDEFINED_MUSIC.some(m => m.url === scene.backgroundMusicUrl) ? scene.backgroundMusicUrl : (customMusicName ? "custom" : "")} 
                                onChange={e => {
                                    if (e.target.value === "custom") return;
                                    setCustomMusicName(null);
                                    dispatch({ type: 'UPDATE_SCENE_CONFIG', payload: { sceneId: scene.id, config: { backgroundMusicUrl: e.target.value } } });
                                }}
                                className="bg-gray-900 border border-white/5 text-xs text-gray-400 focus:text-white outline-none w-full p-2.5 rounded-xl cursor-pointer font-medium"
                            >
                                {PREDEFINED_MUSIC.map(m => <option key={m.name} value={m.url}>{m.name}</option>)}
                                {customMusicName && <option value="custom">Personalizada: {customMusicName}</option>}
                            </select>

                            <div className="space-y-2">
                                <div className="flex items-center justify-between text-[10px] text-gray-500 font-bold uppercase tracking-widest">
                                    <span>Volumen Música</span>
                                    <span>{scene.musicVolume ?? 40}%</span>
                                </div>
                                <div className="flex items-center gap-3">
                                    <VolumeUpIcon className="w-4 h-4 text-gray-600" />
                                    <input 
                                        type="range" 
                                        min="0" 
                                        max="100" 
                                        value={scene.musicVolume ?? 40} 
                                        onChange={handleVolumeChange}
                                        className="flex-grow h-1.5 bg-white/5 rounded-lg appearance-none cursor-pointer accent-sky-500"
                                    />
                                </div>
                            </div>

                            <input ref={musicUploadRef} type="file" accept="audio/*" className="hidden" onChange={handleMusicUpload} />
                            <audio 
                                ref={musicPlayerRef} 
                                src={scene.backgroundMusicUrl} 
                                crossOrigin="anonymous"
                                preload="auto"
                                onEnded={() => setIsPlayingMusic(false)}
                                onPause={() => setIsPlayingMusic(false)}
                                onPlay={() => setIsPlayingMusic(true)}
                                loop
                                className="hidden"
                            />
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { useProjectState, useProjectDispatch } from '../context/ProjectContext';

const DEFAULT_SCENE_DURATION = 6;

export default function MovieModal() {
    const { scenes, isMovieModalOpen } = useProjectState();
    const dispatch = useProjectDispatch();

    const [currentIndex, setCurrentIndex] = useState(0);
    const [isTransitioning, setIsTransitioning] = useState(false);

    const narrationAudioRef = useRef<HTMLAudioElement | null>(null);
    const musicAudioRef = useRef<HTMLAudioElement | null>(null);
    const videoRef = useRef<HTMLVideoElement | null>(null);
    const timeoutRef = useRef<number | null>(null);

    const currentScene = scenes[currentIndex];

    const goToNextScene = useCallback(() => {
        if (currentIndex < scenes.length - 1) {
            setIsTransitioning(true);
            setTimeout(() => {
                setCurrentIndex(prev => prev + 1);
                setIsTransitioning(false);
            }, 600);
        } else {
            handleClose();
        }
    }, [currentIndex, scenes.length]);

    const handleClose = () => {
        if (narrationAudioRef.current) narrationAudioRef.current.pause();
        if (musicAudioRef.current) musicAudioRef.current.pause();
        if (timeoutRef.current) clearTimeout(timeoutRef.current);
        dispatch({ type: 'CLOSE_MOVIE_MODAL' });
        setCurrentIndex(0);
    };

    useEffect(() => {
        if (isMovieModalOpen && !isTransitioning && currentScene) {
            const nar = narrationAudioRef.current;
            const mus = musicAudioRef.current;
            const vid = videoRef.current;

            if (mus) {
                if (currentScene.backgroundMusicUrl && currentScene.backgroundMusicUrl.trim() !== "") {
                    if (mus.src !== currentScene.backgroundMusicUrl) {
                        mus.src = currentScene.backgroundMusicUrl;
                        mus.load();
                    }
                    // Aplicar volumen de la escena o predeterminado 25% si no existe
                    mus.volume = (currentScene.musicVolume ?? 40) / 100 * 0.7; // Atenuar un poco más para favorecer diálogos
                    mus.play().catch(e => console.error("Error música película:", e));
                } else {
                    mus.pause();
                    mus.src = "";
                }
            }

            if (nar && currentScene.audioUrl) {
                nar.src = currentScene.audioUrl;
                nar.onended = () => {
                    if (!vid) goToNextScene();
                };
                nar.play().catch(e => console.error("Error voz película:", e));
            }

            if (vid) {
                vid.onended = goToNextScene;
                vid.play().catch(e => console.error("Error video película:", e));
            } else if (!currentScene.audioUrl) {
                timeoutRef.current = window.setTimeout(goToNextScene, DEFAULT_SCENE_DURATION * 1000);
            }
        }
    }, [isMovieModalOpen, currentIndex, currentScene, isTransitioning, goToNextScene]);

    if (!isMovieModalOpen || !currentScene) return null;

    return (
        <div className="fixed inset-0 bg-black z-50 flex items-center justify-center p-4 md:p-12 overflow-hidden">
            <div className={`relative w-full max-w-6xl aspect-video rounded-3xl overflow-hidden shadow-[0_0_100px_rgba(0,0,0,0.8)] transition-all duration-700 transform ${isTransitioning ? 'scale-95 opacity-0 rotate-1' : 'scale-100 opacity-100 rotate-0'}`}>
                {currentScene.videoUrl ? (
                    <video ref={videoRef} src={currentScene.videoUrl} className="w-full h-full object-cover" />
                ) : (
                    <img src={currentScene.imageUrl} className="w-full h-full object-cover" />
                )}

                <div className="absolute inset-x-0 bottom-0 bg-gradient-to-t from-black/90 via-black/40 to-transparent p-12 pt-24 pointer-events-none">
                    <div className="max-w-3xl mx-auto text-center space-y-4">
                        {currentScene.parts.filter(p => p.type !== 'INSTRUCTION').map((p, i) => (
                            <p key={i} className={`text-lg md:text-2xl font-medium tracking-tight drop-shadow-lg ${p.type === 'DIALOGUE' ? 'text-sky-300 italic' : 'text-white'}`}>
                                {p.speaker && <span className="font-black uppercase text-xs tracking-widest block mb-1 opacity-70">{p.speaker}</span>}
                                "{p.text}"
                            </p>
                        ))}
                    </div>
                </div>

                <div className="absolute top-0 left-0 right-0 h-1 bg-white/10">
                    <div 
                        className="h-full bg-sky-500 transition-all duration-500" 
                        style={{ width: `${((currentIndex + 1) / scenes.length) * 100}%` }}
                    />
                </div>
            </div>

            <button onClick={handleClose} className="absolute top-8 right-8 w-12 h-12 flex items-center justify-center rounded-full bg-white/10 hover:bg-white/20 text-white transition-all backdrop-blur-md">
                <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>

            <audio ref={narrationAudioRef} crossOrigin="anonymous" />
            <audio ref={musicAudioRef} crossOrigin="anonymous" preload="auto" loop />
        </div>
    );
};

import React, { useRef, useState, useEffect } from 'react';
import type { Scene } from '../types';
import { useProjectState, useProjectDispatch, useProjectActions } from '../context/ProjectContext';
import Loader from './Loader';
import { FilmIcon, SpeakerWaveIcon, TrashIcon, DragHandleIcon, MusicNoteIcon, PlayIcon, PauseIcon, DownloadIcon, UploadIcon, VolumeUpIcon } from './Icons';
import { generateVideoForScene, checkVideoStatus } from '../services/gemini';

const PREDEFINED_MUSIC = [
    { name: "Sin música ambiental", url: "" }, 
    { name: "Misterio y Tensión", url: "https://www.soundhelix.com/examples/mp3/SoundHelix-Song-8.mp3" }, 
    { name: "Acción Heroica", url: "https://www.soundhelix.com/examples/mp3/SoundHelix-Song-1.mp3" }, 
    { name: "Atmósfera de Ensueño", url: "https://www.soundhelix.com/examples/mp3/SoundHelix-Song-2.mp3" },
    { name: "Suspenso Noir", url: "https://www.soundhelix.com/examples/mp3/SoundHelix-Song-3.mp3" }
];

interface SceneCardProps {
    scene: Scene;
    sceneNumber: number;
}

export default function SceneCard({ scene, sceneNumber }: SceneCardProps) {
    const dispatch = useProjectDispatch();
    const { hasApiKey, aspectRatio } = useProjectState();
    const { handleNarrateScene, handleGenerateImageForScene } = useProjectActions();

    const [isPlayingAudio, setIsPlayingAudio] = useState(false);
    const [isPlayingMusic, setIsPlayingMusic] = useState(false);
    const [customMusicName, setCustomMusicName] = useState<string | null>(null);

    const audioPlayerRef = useRef<HTMLAudioElement | null>(null);
    const musicPlayerRef = useRef<HTMLAudioElement | null>(null);
    const imageUploadRef = useRef<HTMLInputElement>(null);
    const videoUploadRef = useRef<HTMLInputElement>(null);
    const musicUploadRef = useRef<HTMLInputElement>(null);

    // Sincronizar volumen del reproductor con el estado
    useEffect(() => {
        if (musicPlayerRef.current) {
            musicPlayerRef.current.volume = (scene.musicVolume ?? 40) / 100;
        }
    }, [scene.musicVolume]);

    const toggleAudioPreview = () => {
        const player = audioPlayerRef.current;
        if (!player) return;
        if (isPlayingAudio) {
            player.pause();
        } else {
            if (isPlayingMusic && musicPlayerRef.current) musicPlayerRef.current.pause();
            player.play().catch(e => console.error("Error voz:", e));
        }
    };

    const toggleMusicPreview = () => {
        const player = musicPlayerRef.current;
        if (!player || !scene.backgroundMusicUrl) return;

        if (isPlayingMusic) {
            player.pause();
        } else {
            if (isPlayingAudio && audioPlayerRef.current) audioPlayerRef.current.pause();

            // Asegurar volumen antes de reproducir
            player.volume = (scene.musicVolume ?? 40) / 100;

            const playPromise = player.play();
            if (playPromise !== undefined) {
                playPromise.catch(error => {
                    console.error("Error al reproducir música:", error);
                    let msg = 'Error de conexión con el servidor de audio. Prueba subiendo tu propio archivo.';
                    if (error.name === 'NotAllowedError') msg = 'Haz clic en la página para habilitar el sonido';
                    dispatch({ type: 'ADD_TOAST', payload: { message: msg, type: 'error' } });
                    setIsPlayingMusic(false);
                });
            }
        }
    };

    const handleVolumeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const volume = parseInt(e.target.value);
        dispatch({ type: 'UPDATE_SCENE_CONFIG', payload: { sceneId: scene.id, config: { musicVolume: volume } } });
    };

    // Fix: Implemented handleImageUpload to process local image files
    const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onload = (event) => {
                const imageUrl = event.target?.result as string;
                dispatch({ type: 'UPDATE_SCENE', payload: { sceneId: scene.id, updates: { imageUrl, imagePrompt: 'Cargada por el usuario' } } });
                dispatch({ type: 'ADD_TOAST', payload: { message: 'Imagen subida correctamente', type: 'success' } });
            };
            reader.readAsDataURL(file);
        }
    };

    // Fix: Implemented handleVideoUpload to process local video files
    const handleVideoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const videoUrl = URL.createObjectURL(file);
            dispatch({ type: 'UPDATE_SCENE', payload: { sceneId: scene.id, updates: { videoUrl } } });
            dispatch({ type: 'ADD_TOAST', payload: { message: 'Video subido correctamente', type: 'success' } });
        }
    };

    const handleMusicUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const musicUrl = URL.createObjectURL(file);
            setCustomMusicName(file.name);
            dispatch({ type: 'UPDATE_SCENE_CONFIG', payload: { sceneId: scene.id, config: { backgroundMusicUrl: musicUrl } } });
            dispatch({ type: 'ADD_TOAST', payload: { message: `"${file.name}" cargada correctamente`, type: 'success' } });
        }
    };

    const handleAnimate = async () => {
        if (typeof (window as any).aistudio !== 'undefined' && !hasApiKey) {
            await (window as any).aistudio.openSelectKey();
            dispatch({ type: 'SET_API_KEY_STATUS', payload: true });
        }
        dispatch({type: 'UPDATE_SCENE', payload: {sceneId: scene.id, updates: { isGeneratingVideo: true, videoError: undefined }}});
        try {
            const operation = await generateVideoForScene(scene.parts, aspectRatio);
            const check = async () => {
                const status = await checkVideoStatus(operation);
                if (status.done) {
                    const url = `${status.response?.generatedVideos?.[0]?.video?.uri}&key=${process.env.API_KEY}`;
                    dispatch({type: 'UPDATE_SCENE', payload: {sceneId: scene.id, updates: { videoUrl: url, isGeneratingVideo: false }}});
                    dispatch({ type: 'ADD_TOAST', payload: { message: `Video listo`, type: 'success' } });
                } else {
                    setTimeout(check, 8000);
                }
            };
            check();
        } catch (err: any) {
            dispatch({type: 'UPDATE_SCENE', payload: {sceneId: scene.id, updates: { isGeneratingVideo: false, videoError: err.message }}});
        }
    };

    return (
        <div className="bg-gray-900/40 backdrop-blur-2xl border border-white/5 rounded-[2rem] overflow-hidden shadow-2xl hover:border-sky-500/30 transition-all duration-700 group/card">
            <header className="flex items-center justify-between bg-white/[0.02] p-6 border-b border-white/5">
                <div className="flex items-center gap-4">
                    <div className="p-2.5 bg-sky-500/10 rounded-2xl text-sky-400 group-hover/card:scale-110 transition-transform">
                        <DragHandleIcon className="w-5 h-5 cursor-grab active:cursor-grabbing" />
                    </div>
                    <div>
                        <h3 className="font-black text-lg text-white tracking-tight">ESCENA {sceneNumber}</h3>
                        <p className="text-[10px] text-gray-500 uppercase tracking-[0.2em] font-bold">Bloque de Storyboard</p>
                    </div>
                </div>
                <button onClick={() => dispatch({ type: 'DELETE_SCENE', payload: scene.id })} className="p-2 text-gray-600 hover:text-red-400 hover:bg-red-400/10 rounded-full transition-all">
                    <TrashIcon className="w-5 h-5" />
                </button>
            </header>

            <div className="flex flex-col xl:flex-row">
                <div className="xl:w-3/5 aspect-video bg-gray-950 relative group/media overflow-hidden border-r border-white/5">
                    {scene.isGeneratingImage ? (
                        <div className="absolute inset-0 flex items-center justify-center bg-gray-950"><Loader message="Sincronizando estilo..." /></div>
                    ) : scene.imageUrl ? (
                        scene.videoUrl ? (
                            <div className="relative w-full h-full">
                                <video src={scene.videoUrl} controls className="w-full h-full object-cover" />
                                <div className="absolute top-6 left-6 flex gap-2">
                                    <div className="px-4 py-1.5 bg-purple-600/90 backdrop-blur-xl rounded-full text-[10px] font-black text-white uppercase tracking-widest shadow-2xl animate-pulse">Cinemática Lista</div>
                                    <button onClick={() => {
                                        const link = document.createElement('a');
                                        link.href = scene.videoUrl!;
                                        link.download = `nova-video-${sceneNumber}.mp4`;
                                        link.click();
                                    }} className="p-2 bg-black/60 hover:bg-sky-500 rounded-full text-white transition-all shadow-xl">
                                        <DownloadIcon className="w-4 h-4" />
                                    </button>
                                </div>
                            </div>
                        ) : (
                            <div className="relative w-full h-full group/img">
                                <img src={scene.imageUrl} alt="" className="w-full h-full object-cover group-hover/img:scale-105 transition-transform duration-[2s]" />
                                <div className="absolute top-6 left-6 flex gap-2 opacity-0 group-hover/img:opacity-100 transition-opacity duration-500">
                                    <button onClick={() => {
                                        const link = document.createElement('a');
                                        link.href = scene.imageUrl!;
                                        link.download = `nova-img-${sceneNumber}.png`;
                                        link.click();
                                    }} className="p-2 bg-black/60 hover:bg-sky-500 rounded-full text-white transition-all shadow-xl">
                                        <DownloadIcon className="w-4 h-4" />
                                    </button>
                                    <button onClick={() => imageUploadRef.current?.click()} className="p-2 bg-black/60 hover:bg-sky-500 rounded-full text-white transition-all shadow-xl">
                                        <UploadIcon className="w-4 h-4" />
                                    </button>
                                    <button onClick={() => handleGenerateImageForScene(scene.id)} className="p-2 bg-sky-600 hover:bg-sky-500 rounded-full text-white transition-all shadow-xl">
                                        <svg xmlns="http://www.w3.org/2000/svg" className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
                                    </button>
                                </div>
                            </div>
                        )
                    ) : (
                        <div className="absolute inset-0 flex flex-col items-center justify-center gap-6 text-gray-700 bg-[radial-gradient(circle_at_center,_#111_0%,_#000_100%)]">
                             <div className="w-16 h-16 rounded-3xl border-2 border-dashed border-gray-800 flex items-center justify-center">
                                <UploadIcon className="w-6 h-6 opacity-20" />
                             </div>
                             <div className="flex flex-col gap-2">
                                <button onClick={() => handleGenerateImageForScene(scene.id)} className="px-6 py-2.5 bg-sky-600 hover:bg-sky-500 rounded-2xl text-xs font-bold text-white transition-all">Generar con Estilo Global</button>
                                <button onClick={() => imageUploadRef.current?.click()} className="px-6 py-2.5 bg-white/5 hover:bg-white/10 rounded-2xl text-xs font-bold text-gray-400 border border-white/5 transition-all">Subir Arte Propio</button>
                             </div>
                        </div>
                    )}
                    <input ref={imageUploadRef} type="file" accept="image/*" className="hidden" onChange={handleImageUpload} />
                    <input ref={videoUploadRef} type="file" accept="video/*" className="hidden" onChange={handleVideoUpload} />
                </div>

                <div className="xl:w-2/5 p-10 flex flex-col justify-between space-y-8 bg-gradient-to-br from-white/[0.01] to-transparent">
                    <div className="space-y-6">
                        <div className="max-h-40 overflow-y-auto pr-4 custom-scrollbar space-y-3">
                            {scene.parts.map((p, i) => (
                                <div key={i} className={`p-3 rounded-2xl border transition-colors ${p.type === 'DIALOGUE' ? 'bg-sky-500/5 border-sky-500/20' : 'bg-white/5 border-transparent'}`}>
                                    {p.speaker && <p className="text-[9px] font-black text-sky-400 uppercase tracking-widest mb-1">{p.speaker}</p>}
                                    <p className={`text-sm leading-relaxed ${p.type === 'DIALOGUE' ? 'text-white font-medium italic' : 'text-gray-400'}`}>
                                        {p.text}
                                    </p>
                                </div>
                            ))}
                        </div>
                    </div>

                    <div className="space-y-4">
                        <div className="grid grid-cols-2 gap-4">
                            {!scene.audioUrl ? (
                                <button 
                                    onClick={() => handleNarrateScene(scene.id)} 
                                    disabled={scene.isGeneratingAudio}
                                    className="flex flex-col items-center justify-center gap-2 py-5 rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest bg-sky-600 hover:bg-sky-500 text-white shadow-xl shadow-sky-600/10 transition-all disabled:opacity-50 group/btn"
                                >
                                    {scene.isGeneratingAudio ? <div className="w-5 h-5 border-2 border-white/20 border-t-white rounded-full animate-spin"></div> : <SpeakerWaveIcon className="w-6 h-6 group-hover/btn:scale-110 transition-transform" />}
                                    Generar Voz
                                </button>
                            ) : (
                                <div className="flex flex-col gap-2">
                                    <button 
                                        onClick={toggleAudioPreview}
                                        className={`flex flex-col items-center justify-center gap-2 py-5 rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest transition-all ${isPlayingAudio ? 'bg-amber-500 text-white shadow-amber-500/20 shadow-xl' : 'bg-green-500/10 text-green-400 border border-green-500/20 hover:bg-green-500/20'}`}
                                    >
                                        {isPlayingAudio ? <PauseIcon className="w-6 h-6 animate-pulse" /> : <PlayIcon className="w-6 h-6" />}
                                        {isPlayingAudio ? 'Reproduciendo' : 'Oír Narración'}
                                        <audio 
                                            ref={audioPlayerRef} 
                                            src={scene.audioUrl} 
                                            crossOrigin="anonymous"
                                            onEnded={() => setIsPlayingAudio(false)}
                                            onPause={() => setIsPlayingAudio(false)}
                                            onPlay={() => setIsPlayingAudio(true)}
                                            className="hidden" 
                                        />
                                    </button>
                                    <button onClick={() => dispatch({ type: 'UPDATE_SCENE', payload: { sceneId: scene.id, updates: { audioUrl: undefined } } })} className="text-[9px] text-gray-600 hover:text-sky-400 uppercase tracking-[0.2em] font-black transition-colors text-center">Remplazar Voz</button>
                                </div>
                            )}

                            <div className="flex flex-col gap-2">
                                <button 
                                    onClick={handleAnimate}
                                    disabled={scene.isGeneratingVideo || !scene.imageUrl || !!scene.videoUrl}
                                    className={`flex flex-col items-center justify-center gap-2 py-5 rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest transition-all ${scene.videoUrl ? 'bg-purple-500/10 text-purple-400 border border-purple-500/20' : 'bg-purple-600 hover:bg-purple-500 text-white shadow-xl shadow-purple-600/10 disabled:opacity-20'}`}
                                >
                                    {scene.isGeneratingVideo ? <div className="w-5 h-5 border-2 border-white/20 border-t-white rounded-full animate-spin"></div> : <FilmIcon className="w-6 h-6" />}
                                    {scene.videoUrl ? 'Cinemática OK' : 'Animar con IA'}
                                </button>
                                {!scene.videoUrl && scene.imageUrl && (
                                    <button onClick={() => videoUploadRef.current?.click()} className="text-[9px] text-gray-600 hover:text-purple-400 uppercase tracking-[0.2em] font-black transition-colors text-center">Subir Video</button>
                                )}
                            </div>
                        </div>

                        <div className="bg-white/[0.03] p-6 rounded-2xl border border-white/5 space-y-4">
                            <div className="flex items-center justify-between">
                                <div className="flex items-center gap-2 text-gray-400">
                                    <MusicNoteIcon className="w-4 h-4" />
                                    <span className="text-[10px] font-black uppercase tracking-widest">Música Ambiental</span>
                                </div>
                                <div className="flex items-center gap-2">
                                    {scene.backgroundMusicUrl && (
                                        <button 
                                            onClick={toggleMusicPreview}
                                            className={`p-2 rounded-xl transition-all ${isPlayingMusic ? 'bg-sky-500 text-white shadow-lg' : 'bg-white/5 text-gray-400 hover:bg-white/10'}`}
                                        >
                                            {isPlayingMusic ? <PauseIcon className="w-4 h-4" /> : <PlayIcon className="w-4 h-4" />}
                                        </button>
                                    )}
                                    <button 
                                        onClick={() => musicUploadRef.current?.click()} 
                                        className="p-2 bg-white/5 text-gray-400 hover:bg-sky-500/20 hover:text-sky-400 rounded-xl transition-all"
                                        title="Subir MP3/WAV propio"
                                    >
                                        <UploadIcon className="w-4 h-4" />
                                    </button>
                                </div>
                            </div>

                            <select 
                                value={PREDEFINED_MUSIC.some(m => m.url === scene.backgroundMusicUrl) ? scene.backgroundMusicUrl : (customMusicName ? "custom" : "")} 
                                onChange={e => {
                                    if (e.target.value === "custom") return;
                                    setCustomMusicName(null);
                                    dispatch({ type: 'UPDATE_SCENE_CONFIG', payload: { sceneId: scene.id, config: { backgroundMusicUrl: e.target.value } } });
                                }}
                                className="bg-gray-900 border border-white/5 text-xs text-gray-400 focus:text-white outline-none w-full p-2.5 rounded-xl cursor-pointer font-medium"
                            >
                                {PREDEFINED_MUSIC.map(m => <option key={m.name} value={m.url}>{m.name}</option>)}
                                {customMusicName && <option value="custom">Personalizada: {customMusicName}</option>}
                            </select>

                            <div className="space-y-2">
                                <div className="flex items-center justify-between text-[10px] text-gray-500 font-bold uppercase tracking-widest">
                                    <span>Volumen Música</span>
                                    <span>{scene.musicVolume ?? 40}%</span>
                                </div>
                                <div className="flex items-center gap-3">
                                    <VolumeUpIcon className="w-4 h-4 text-gray-600" />
                                    <input 
                                        type="range" 
                                        min="0" 
                                        max="100" 
                                        value={scene.musicVolume ?? 40} 
                                        onChange={handleVolumeChange}
                                        className="flex-grow h-1.5 bg-white/5 rounded-lg appearance-none cursor-pointer accent-sky-500"
                                    />
                                </div>
                            </div>

                            <input ref={musicUploadRef} type="file" accept="audio/*" className="hidden" onChange={handleMusicUpload} />
                            <audio 
                                ref={musicPlayerRef} 
                                src={scene.backgroundMusicUrl} 
                                crossOrigin="anonymous"
                                preload="auto"
                                onEnded={() => setIsPlayingMusic(false)}
                                onPause={() => setIsPlayingMusic(false)}
                                onPlay={() => setIsPlayingMusic(true)}
                                loop
                                className="hidden"
                            />
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

export interface Character {
  name: string;
  description: string;
  voice?: string;
}

export type NarrationPartType = 'NARRATION' | 'DIALOGUE' | 'INSTRUCTION';

export interface NarrationPart {
  type: NarrationPartType;
  speaker?: string;
  text: string;
}

export interface Scene {
  id: number;
  parts: NarrationPart[];
  imageUrl?: string;
  imagePrompt?: string;
  imageError?: string;
  videoUrl?: string;
  isGeneratingImage: boolean;
  isGeneratingVideo: boolean;
  videoGenerationOperation?: any; 
  videoError?: string;
  audioUrl?: string;
  isGeneratingAudio: boolean;
  audioError?: string;
  duration?: number; // Duración en segundos del audio
  backgroundMusicUrl?: string;
  musicVolume?: number;
  speechVolume?: number;
}

export type AppStep = 'input' | 'config' | 'scenes';

export interface Toast {
  id: number;
  message: string;
  type: 'success' | 'error' | 'info';
}

export interface ProjectState {
    currentStep: AppStep;
    novelText: string;
    scenes: Scene[];
    characters: Character[];
    statusMessage: string;
    error: string;
    hasApiKey: boolean;
    imageStyle: string;
    artDirection: string;
    aspectRatio: '16:9' | '9:16';
    includeTextInImage: boolean;
    narratorVoice: string;
    isSaving: boolean;
    isProjectSaved: boolean;
    isMovieModalOpen: boolean;
    toasts: Toast[];
}

export type ProjectAction =
    | { type: 'SET_STEP'; payload: AppStep }
    | { type: 'SET_NOVEL_TEXT'; payload: string }
    | { type: 'SET_STATUS_MESSAGE'; payload: string }
    | { type: 'SET_ERROR'; payload: string }
    | { type: 'START_ANALYSIS' }
    | { type: 'ANALYZE_SUCCESS'; payload: Character[] }
    | { type: 'ANALYZE_FAILURE'; payload: string }
    | { type: 'START_SCENE_GENERATION' }
    | { type: 'SCENE_GENERATION_INITIALIZE'; payload: Scene[] }
    | { type: 'SCENE_GENERATION_COMPLETE' }
    | { type: 'SCENE_GENERATION_FAILURE'; payload: string }
    | { type: 'UPDATE_SCENE'; payload: { sceneId: number; updates: Partial<Scene> } }
    | { type: 'UPDATE_SCENES_ORDER'; payload: Scene[] }
    | { type: 'DELETE_SCENE'; payload: number }
    | { type: 'UPDATE_CHARACTER_VOICE'; payload: { characterName: string; newVoice: string } }
    | { type: 'SET_CONFIG'; payload: Partial<Pick<ProjectState, 'imageStyle' | 'artDirection' | 'aspectRatio' | 'includeTextInImage' | 'narratorVoice'>> }
    | { type: 'UPDATE_SCENE_CONFIG', payload: { sceneId: number, config: Partial<Pick<Scene, 'backgroundMusicUrl' | 'musicVolume' | 'speechVolume'>>}}
    | { type: 'OPEN_MOVIE_MODAL' }
    | { type: 'CLOSE_MOVIE_MODAL' }
    | { type: 'LOAD_PROJECT'; payload: ProjectState }
    | { type: 'RESET_PROJECT' }
    | { type: 'SET_API_KEY_STATUS'; payload: boolean }
    | { type: 'ADD_TOAST'; payload: Omit<Toast, 'id'> }
    | { type: 'REMOVE_TOAST'; payload: number };

import React, { useRef, useState, useEffect } from 'react';
import type { Scene } from '../types';
import { useProjectState, useProjectDispatch, useProjectActions } from '../context/ProjectContext';
import Loader from './Loader';
import { FilmIcon, SpeakerWaveIcon, TrashIcon, DragHandleIcon, MusicNoteIcon, PlayIcon, PauseIcon, DownloadIcon, UploadIcon, VolumeUpIcon } from './Icons';
import { generateVideoForScene, checkVideoStatus } from '../services/gemini';

const PREDEFINED_MUSIC = [
    { name: "Sin música ambiental", url: "" }, 
    { name: "Misterio y Tensión", url: "https://www.soundhelix.com/examples/mp3/SoundHelix-Song-8.mp3" }, 
    { name: "Acción Heroica", url: "https://www.soundhelix.com/examples/mp3/SoundHelix-Song-1.mp3" }, 
    { name: "Atmósfera de Ensueño", url: "https://www.soundhelix.com/examples/mp3/SoundHelix-Song-2.mp3" },
    { name: "Suspenso Noir", url: "https://www.soundhelix.com/examples/mp3/SoundHelix-Song-3.mp3" }
];

interface SceneCardProps {
    scene: Scene;
    sceneNumber: number;
}

export default function SceneCard({ scene, sceneNumber }: SceneCardProps) {
    const dispatch = useProjectDispatch();
    const { hasApiKey, aspectRatio } = useProjectState();
    const { handleNarrateScene, handleGenerateImageForScene } = useProjectActions();

    const [isPlayingAudio, setIsPlayingAudio] = useState(false);
    const [isPlayingMusic, setIsPlayingMusic] = useState(false);
    const [customMusicName, setCustomMusicName] = useState<string | null>(null);

    const audioPlayerRef = useRef<HTMLAudioElement | null>(null);
    const musicPlayerRef = useRef<HTMLAudioElement | null>(null);
    const imageUploadRef = useRef<HTMLInputElement>(null);
    const videoUploadRef = useRef<HTMLInputElement>(null);
    const musicUploadRef = useRef<HTMLInputElement>(null);

    // Sincronizar volúmenes del reproductor con el estado
    useEffect(() => {
        if (musicPlayerRef.current) {
            musicPlayerRef.current.volume = (scene.musicVolume ?? 40) / 100;
        }
    }, [scene.musicVolume]);

    useEffect(() => {
        if (audioPlayerRef.current) {
            audioPlayerRef.current.volume = (scene.speechVolume ?? 100) / 100;
        }
    }, [scene.speechVolume]);

    const toggleAudioPreview = () => {
        const player = audioPlayerRef.current;
        if (!player) return;
        if (isPlayingAudio) {
            player.pause();
        } else {
            if (isPlayingMusic && musicPlayerRef.current) {
                // Ducking manual temporal al oir la voz
                musicPlayerRef.current.volume = ((scene.musicVolume ?? 40) / 100) * 0.3;
            }
            player.play().catch(e => console.error("Error voz:", e));
        }
    };

    const toggleMusicPreview = () => {
        const player = musicPlayerRef.current;
        if (!player || !scene.backgroundMusicUrl) return;

        if (isPlayingMusic) {
            player.pause();
        } else {
            player.volume = (scene.musicVolume ?? 40) / 100;
            const playPromise = player.play();
            if (playPromise !== undefined) {
                playPromise.catch(error => {
                    console.error("Error al reproducir música:", error);
                    let msg = 'Error de conexión con el servidor de audio. Prueba subiendo tu propio archivo.';
                    dispatch({ type: 'ADD_TOAST', payload: { message: msg, type: 'error' } });
                    setIsPlayingMusic(false);
                });
            }
        }
    };

    const handleConfigUpdate = (config: Partial<Pick<Scene, 'musicVolume' | 'speechVolume' | 'backgroundMusicUrl'>>) => {
        dispatch({ type: 'UPDATE_SCENE_CONFIG', payload: { sceneId: scene.id, config } });
    };

    const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onload = (event) => {
                const imageUrl = event.target?.result as string;
                dispatch({ type: 'UPDATE_SCENE', payload: { sceneId: scene.id, updates: { imageUrl, imagePrompt: 'Cargada por el usuario' } } });
                dispatch({ type: 'ADD_TOAST', payload: { message: 'Imagen subida', type: 'success' } });
            };
            reader.readAsDataURL(file);
        }
    };

    const handleVideoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const videoUrl = URL.createObjectURL(file);
            dispatch({ type: 'UPDATE_SCENE', payload: { sceneId: scene.id, updates: { videoUrl } } });
        }
    };

    const handleMusicUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const musicUrl = URL.createObjectURL(file);
            setCustomMusicName(file.name);
            handleConfigUpdate({ backgroundMusicUrl: musicUrl });
            dispatch({ type: 'ADD_TOAST', payload: { message: `"${file.name}" cargada`, type: 'success' } });
        }
    };

    const handleAnimate = async () => {
        if (typeof (window as any).aistudio !== 'undefined' && !hasApiKey) {
            await (window as any).aistudio.openSelectKey();
            dispatch({ type: 'SET_API_KEY_STATUS', payload: true });
        }
        dispatch({type: 'UPDATE_SCENE', payload: {sceneId: scene.id, updates: { isGeneratingVideo: true }}});
        try {
            const operation = await generateVideoForScene(scene.parts, aspectRatio);
            const check = async () => {
                const status = await checkVideoStatus(operation);
                if (status.done) {
                    const url = `${status.response?.generatedVideos?.[0]?.video?.uri}&key=${process.env.API_KEY}`;
                    dispatch({type: 'UPDATE_SCENE', payload: {sceneId: scene.id, updates: { videoUrl: url, isGeneratingVideo: false }}});
                } else {
                    setTimeout(check, 8000);
                }
            };
            check();
        } catch (err: any) {
            dispatch({type: 'UPDATE_SCENE', payload: {sceneId: scene.id, updates: { isGeneratingVideo: false, videoError: err.message }}});
        }
    };

    return (
        <div className="bg-gray-900/40 backdrop-blur-2xl border border-white/5 rounded-[2rem] overflow-hidden shadow-2xl hover:border-sky-500/30 transition-all duration-700 group/card">
            <header className="flex items-center justify-between bg-white/[0.02] p-6 border-b border-white/5">
                <div className="flex items-center gap-4">
                    <div className="p-2.5 bg-sky-500/10 rounded-2xl text-sky-400 group-hover/card:scale-110 transition-transform">
                        <DragHandleIcon className="w-5 h-5 cursor-grab active:cursor-grabbing" />
                    </div>
                    <div>
                        <h3 className="font-black text-lg text-white tracking-tight">ESCENA {sceneNumber}</h3>
                        <p className="text-[10px] text-gray-500 uppercase tracking-[0.2em] font-bold">Bloque de Storyboard</p>
                    </div>
                </div>
                <button onClick={() => dispatch({ type: 'DELETE_SCENE', payload: scene.id })} className="p-2 text-gray-600 hover:text-red-400 hover:bg-red-400/10 rounded-full transition-all">
                    <TrashIcon className="w-5 h-5" />
                </button>
            </header>

            <div className="flex flex-col xl:flex-row">
                <div className="xl:w-3/5 aspect-video bg-gray-950 relative group/media overflow-hidden border-r border-white/5">
                    {scene.isGeneratingImage ? (
                        <div className="absolute inset-0 flex items-center justify-center bg-gray-950"><Loader message="Sincronizando estilo..." /></div>
                    ) : scene.imageUrl ? (
                        scene.videoUrl ? (
                            <div className="relative w-full h-full">
                                <video src={scene.videoUrl} controls className="w-full h-full object-cover" />
                            </div>
                        ) : (
                            <div className="relative w-full h-full group/img">
                                <img src={scene.imageUrl} alt="" className="w-full h-full object-cover group-hover/img:scale-105 transition-transform duration-[2s]" />
                                <div className="absolute top-6 left-6 flex gap-2 opacity-0 group-hover/img:opacity-100 transition-opacity duration-500">
                                    <button onClick={() => imageUploadRef.current?.click()} className="p-2 bg-black/60 hover:bg-sky-500 rounded-full text-white transition-all shadow-xl">
                                        <UploadIcon className="w-4 h-4" />
                                    </button>
                                    <button onClick={() => handleGenerateImageForScene(scene.id)} className="p-2 bg-sky-600 hover:bg-sky-500 rounded-full text-white transition-all shadow-xl">
                                        <svg xmlns="http://www.w3.org/2000/svg" className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
                                    </button>
                                </div>
                            </div>
                        )
                    ) : (
                        <div className="absolute inset-0 flex flex-col items-center justify-center gap-6 bg-gray-950">
                             <button onClick={() => handleGenerateImageForScene(scene.id)} className="px-6 py-2.5 bg-sky-600 hover:bg-sky-500 rounded-2xl text-xs font-bold text-white transition-all">Generar Imagen</button>
                             <button onClick={() => imageUploadRef.current?.click()} className="px-6 py-2.5 bg-white/5 hover:bg-white/10 rounded-2xl text-xs font-bold text-gray-400 transition-all">Subir Arte</button>
                        </div>
                    )}
                    <input ref={imageUploadRef} type="file" accept="image/*" className="hidden" onChange={handleImageUpload} />
                    <input ref={videoUploadRef} type="file" accept="video/*" className="hidden" onChange={handleVideoUpload} />
                </div>

                <div className="xl:w-2/5 p-10 flex flex-col justify-between space-y-8 bg-gradient-to-br from-white/[0.01] to-transparent">
                    <div className="space-y-6">
                        <div className="max-h-40 overflow-y-auto pr-4 custom-scrollbar space-y-3">
                            {scene.parts.map((p, i) => (
                                <div key={i} className={`p-3 rounded-2xl border transition-colors ${p.type === 'DIALOGUE' ? 'bg-sky-500/5 border-sky-500/20' : 'bg-white/5 border-transparent'}`}>
                                    {p.speaker && <p className="text-[9px] font-black text-sky-400 uppercase tracking-widest mb-1">{p.speaker}</p>}
                                    <p className={`text-sm leading-relaxed ${p.type === 'DIALOGUE' ? 'text-white font-medium italic' : 'text-gray-400'}`}>
                                        {p.text}
                                    </p>
                                </div>
                            ))}
                        </div>
                    </div>

                    <div className="space-y-6">
                        <div className="grid grid-cols-2 gap-4">
                            {!scene.audioUrl ? (
                                <button 
                                    onClick={() => handleNarrateScene(scene.id)} 
                                    disabled={scene.isGeneratingAudio}
                                    className="flex flex-col items-center justify-center gap-2 py-5 rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest bg-sky-600 hover:bg-sky-500 text-white shadow-xl shadow-sky-600/10 transition-all disabled:opacity-50"
                                >
                                    {scene.isGeneratingAudio ? <div className="w-5 h-5 border-2 border-white/20 border-t-white rounded-full animate-spin"></div> : <SpeakerWaveIcon className="w-6 h-6" />}
                                    Generar Voz
                                </button>
                            ) : (
                                <div className="flex flex-col gap-2">
                                    <button 
                                        onClick={toggleAudioPreview}
                                        className={`flex flex-col items-center justify-center gap-2 py-5 rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest transition-all ${isPlayingAudio ? 'bg-amber-500 text-white shadow-amber-500/20 shadow-xl' : 'bg-green-500/10 text-green-400 border border-green-500/20 hover:bg-green-500/20'}`}
                                    >
                                        {isPlayingAudio ? <PauseIcon className="w-6 h-6" /> : <PlayIcon className="w-6 h-6" />}
                                        {isPlayingAudio ? 'Reproduciendo' : 'Oír Narración'}
                                        <audio 
                                            ref={audioPlayerRef} 
                                            src={scene.audioUrl} 
                                            crossOrigin="anonymous"
                                            onEnded={() => {
                                                setIsPlayingAudio(false);
                                                if (musicPlayerRef.current) musicPlayerRef.current.volume = (scene.musicVolume ?? 40) / 100;
                                            }}
                                            onPause={() => setIsPlayingAudio(false)}
                                            onPlay={() => setIsPlayingAudio(true)}
                                            className="hidden" 
                                        />
                                    </button>
                                    <button onClick={() => dispatch({ type: 'UPDATE_SCENE', payload: { sceneId: scene.id, updates: { audioUrl: undefined } } })} className="text-[9px] text-gray-600 hover:text-sky-400 uppercase tracking-widest font-black text-center">Cambiar Voz</button>
                                </div>
                            )}

                            <button 
                                onClick={handleAnimate}
                                disabled={scene.isGeneratingVideo || !scene.imageUrl || !!scene.videoUrl}
                                className={`flex flex-col items-center justify-center gap-2 py-5 rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest transition-all ${scene.videoUrl ? 'bg-purple-500/10 text-purple-400 border border-purple-500/20' : 'bg-purple-600 hover:bg-purple-500 text-white disabled:opacity-20'}`}
                            >
                                {scene.isGeneratingVideo ? <div className="w-5 h-5 border-2 border-white/20 border-t-white rounded-full animate-spin"></div> : <FilmIcon className="w-6 h-6" />}
                                {scene.videoUrl ? 'Cinemática OK' : 'Animar con IA'}
                            </button>
                        </div>

                        <div className="bg-white/[0.03] p-6 rounded-2xl border border-white/5 space-y-6">
                            <div className="flex items-center justify-between">
                                <div className="flex items-center gap-2 text-gray-400">
                                    <MusicNoteIcon className="w-4 h-4" />
                                    <span className="text-[10px] font-black uppercase tracking-widest">Mezclador de Audio</span>
                                </div>
                                <div className="flex items-center gap-2">
                                    {scene.backgroundMusicUrl && (
                                        <button onClick={toggleMusicPreview} className={`p-2 rounded-xl transition-all ${isPlayingMusic ? 'bg-sky-500 text-white' : 'bg-white/5 text-gray-400 hover:bg-white/10'}`}>
                                            {isPlayingMusic ? <PauseIcon className="w-4 h-4" /> : <PlayIcon className="w-4 h-4" />}
                                        </button>
                                    )}
                                    <button onClick={() => musicUploadRef.current?.click()} className="p-2 bg-white/5 text-gray-400 hover:text-sky-400 rounded-xl transition-all">
                                        <UploadIcon className="w-4 h-4" />
                                    </button>
                                </div>
                            </div>

                            <select 
                                value={PREDEFINED_MUSIC.some(m => m.url === scene.backgroundMusicUrl) ? scene.backgroundMusicUrl : (customMusicName ? "custom" : "")} 
                                onChange={e => {
                                    if (e.target.value === "custom") return;
                                    setCustomMusicName(null);
                                    handleConfigUpdate({ backgroundMusicUrl: e.target.value });
                                }}
                                className="bg-gray-900 border border-white/5 text-xs text-gray-400 outline-none w-full p-2.5 rounded-xl"
                            >
                                {PREDEFINED_MUSIC.map(m => <option key={m.name} value={m.url}>{m.name}</option>)}
                                {customMusicName && <option value="custom">Pers.: {customMusicName}</option>}
                            </select>

                            <div className="space-y-4">
                                <div className="space-y-2">
                                    <div className="flex justify-between text-[9px] text-gray-500 font-black uppercase tracking-widest">
                                        <span>Volumen Diálogo</span>
                                        <span className="text-sky-400">{scene.speechVolume ?? 100}%</span>
                                    </div>
                                    <input type="range" min="0" max="100" value={scene.speechVolume ?? 100} onChange={e => handleConfigUpdate({ speechVolume: parseInt(e.target.value) })} className="w-full h-1.5 bg-white/5 rounded-lg appearance-none accent-sky-500" />
                                </div>
                                <div className="space-y-2">
                                    <div className="flex justify-between text-[9px] text-gray-500 font-black uppercase tracking-widest">
                                        <span>Volumen Ambiente</span>
                                        <span className="text-purple-400">{scene.musicVolume ?? 40}%</span>
                                    </div>
                                    <input type="range" min="0" max="100" value={scene.musicVolume ?? 40} onChange={e => handleConfigUpdate({ musicVolume: parseInt(e.target.value) })} className="w-full h-1.5 bg-white/5 rounded-lg appearance-none accent-purple-500" />
                                </div>
                            </div>

                            <input ref={musicUploadRef} type="file" accept="audio/*" className="hidden" onChange={handleMusicUpload} />
                            <audio ref={musicPlayerRef} src={scene.backgroundMusicUrl} crossOrigin="anonymous" preload="auto" onPlay={() => setIsPlayingMusic(true)} onPause={() => setIsPlayingMusic(false)} loop className="hidden" />
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { useProjectState, useProjectDispatch } from '../context/ProjectContext';

const DEFAULT_SCENE_DURATION = 6;

export default function MovieModal() {
    const { scenes, isMovieModalOpen } = useProjectState();
    const dispatch = useProjectDispatch();

    const [currentIndex, setCurrentIndex] = useState(0);
    const [isTransitioning, setIsTransitioning] = useState(false);

    const narrationAudioRef = useRef<HTMLAudioElement | null>(null);
    const musicAudioRef = useRef<HTMLAudioElement | null>(null);
    const videoRef = useRef<HTMLVideoElement | null>(null);
    const timeoutRef = useRef<number | null>(null);

    const currentScene = scenes[currentIndex];

    const goToNextScene = useCallback(() => {
        if (currentIndex < scenes.length - 1) {
            setIsTransitioning(true);
            setTimeout(() => {
                setCurrentIndex(prev => prev + 1);
                setIsTransitioning(false);
            }, 600);
        } else {
            handleClose();
        }
    }, [currentIndex, scenes.length]);

    const handleClose = () => {
        if (narrationAudioRef.current) narrationAudioRef.current.pause();
        if (musicAudioRef.current) musicAudioRef.current.pause();
        if (timeoutRef.current) clearTimeout(timeoutRef.current);
        dispatch({ type: 'CLOSE_MOVIE_MODAL' });
        setCurrentIndex(0);
    };

    useEffect(() => {
        if (isMovieModalOpen && !isTransitioning && currentScene) {
            const nar = narrationAudioRef.current;
            const mus = musicAudioRef.current;
            const vid = videoRef.current;

            if (mus) {
                if (currentScene.backgroundMusicUrl && currentScene.backgroundMusicUrl.trim() !== "") {
                    if (mus.src !== currentScene.backgroundMusicUrl) {
                        mus.src = currentScene.backgroundMusicUrl;
                        mus.load();
                    }
                    // Aplicar el volumen específico de la mezcla de música para esta escena
                    mus.volume = (currentScene.musicVolume ?? 40) / 100;
                    mus.play().catch(e => console.error("Error música película:", e));
                } else {
                    mus.pause();
                    mus.src = "";
                }
            }

            if (nar && currentScene.audioUrl) {
                nar.src = currentScene.audioUrl;
                // Aplicar el volumen específico de la voz para esta escena
                nar.volume = (currentScene.speechVolume ?? 100) / 100;
                nar.onended = () => {
                    if (!vid) goToNextScene();
                };
                nar.play().catch(e => console.error("Error voz película:", e));
            }

            if (vid) {
                vid.onended = goToNextScene;
                vid.play().catch(e => console.error("Error video película:", e));
            } else if (!currentScene.audioUrl) {
                timeoutRef.current = window.setTimeout(goToNextScene, DEFAULT_SCENE_DURATION * 1000);
            }
        }
    }, [isMovieModalOpen, currentIndex, currentScene, isTransitioning, goToNextScene]);

    if (!isMovieModalOpen || !currentScene) return null;

    return (
        <div className="fixed inset-0 bg-black z-50 flex items-center justify-center p-4 md:p-12 overflow-hidden">
            <div className={`relative w-full max-w-6xl aspect-video rounded-3xl overflow-hidden shadow-[0_0_100px_rgba(0,0,0,0.8)] transition-all duration-700 transform ${isTransitioning ? 'scale-95 opacity-0 rotate-1' : 'scale-100 opacity-100 rotate-0'}`}>
                {currentScene.videoUrl ? (
                    <video ref={videoRef} src={currentScene.videoUrl} className="w-full h-full object-cover" />
                ) : (
                    <img src={currentScene.imageUrl} className="w-full h-full object-cover" />
                )}

                <div className="absolute inset-x-0 bottom-0 bg-gradient-to-t from-black/90 via-black/40 to-transparent p-12 pt-24 pointer-events-none">
