export const generateImageForScene = async (parts: NarrationPart[], style: string, characters: Character[], artDirection: string, includeTextInImage: boolean): Promise<{ imageUrl: string, imagePrompt: string }> => {
    const ai = getAiClient();
    const textModel = 'gemini-3-flash-preview';
    const imageModel = 'gemini-2.5-flash-image';

    const charRef = characters.map(c => `${c.name}: ${c.description}`).join('\n');
    const sceneContent = parts.map(p => p.text).join(' ');

    // Instrucción de sistema para asegurar consistencia extrema
    const systemInstruction = `
    Eres un Director de Arte experto en consistencia visual para novelas gráficas.
    Tu misión es redactar prompts para una IA generativa de imágenes (Imagen 3).

    REGLAS DE ORO:
    1. ESTILO OBLIGATORIO: "${style}". NO puedes usar otros estilos como Pixar, Disney o Anime a menos que se indique específicamente.
    2. COHERENCIA: Todas las imágenes deben parecer parte de la MISMA OBRA.
    3. PROHIBICIONES: No añadas palabras como "cartoon", "3d render", "cute" o "whimsical" si el estilo es "Cinematográfica" o "Realista".
    4. ANCLAJE: El prompt debe empezar describiendo la técnica artística de forma técnica.
    `;

    const promptGenPrompt = `
    GENERA UN PROMPT DE IMAGEN PARA ESTA ESCENA:
    "${sceneContent}"

    ESTILO SELECCIONADO POR EL USUARIO: ${style}
    DIRECCIÓN DE ARTE ADICIONAL: ${artDirection}

    DESCRIPCIÓN DE PERSONAJES (DEBEN SER IDÉNTICOS):
    ${charRef}

    ESTRUCTURA DEL PROMPT:
    [Técnica de Estilo ${style}] + [Sujetos y Acción] + [Ambiente y Luz ${artDirection}] + [Composición de Cámara].

    Idioma: English. Solo devuelve el texto del prompt.
    `;

    const promptResponse = await ai.models.generateContent({ 
        model: textModel, 
        contents: promptGenPrompt,
        config: { systemInstruction }
    });

    const imagePrompt = promptResponse.text;

    const imageResponse = await ai.models.generateContent({
        model: imageModel,
        contents: { parts: [{ text: imagePrompt }] },
    });

    const candidate = imageResponse.candidates?.[0];
    const imagePart = candidate?.content?.parts?.find(p => p.inlineData);

    if (imagePart?.inlineData) {
        return {
            imageUrl: `data:${imagePart.inlineData.mimeType};base64,${imagePart.inlineData.data}`,
            imagePrompt: imagePrompt
        };
    }
    throw new Error('La generación de imagen falló.');
};

export const generateVideoForScene = async (parts: NarrationPart[], aspectRatio: '16:9' | '9:16'): Promise<any> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = 'veo-3.1-fast-generate-preview';
    const action = parts.filter(p => p.type !== 'INSTRUCTION').map(p => p.text).join(' ').substring(0, 500);

    return await ai.models.generateVideos({
        model,
        prompt: `Cinematic high-quality animation: ${action}. Maintain strictly consistent character design and lighting. Fluid professional motion, filmic look.`,
        config: { numberOfVideos: 1, resolution: '720p', aspectRatio }
    });
};

